/*
 * sim.odin — Relational simulation tick system (M5).
 *
 * Every simulation tick:
 *   1. Characters near each other accumulate interaction_count in Epilog.
 *   2. Dependent RNG decides if a crush develops.
 *   3. Eligible check (Epilog query) gates crush formation.
 *   4. Mood is re-derived each tick from relationship state.
 *   5. Events are appended to the rolling event log.
 *
 * The Epilog engine is always the source of truth for social state.
 * Odin never caches relationship facts — it queries every tick.
 */

package dmls

import "core:fmt"
import "core:strings"

// ---- Event log -------------------------------------------------------------

MAX_EVENTS   :: 20
EVENT_MSG_LEN :: 96

EventEntry :: struct {
    tick : u64,
    msg  : [EVENT_MSG_LEN]u8,
}

EventLog :: struct {
    entries : [MAX_EVENTS]EventEntry,
    head    : int,   // ring-buffer write index
    count   : int,
}

event_log_push :: proc(log: ^EventLog, tick: u64, msg: string) {
    e := &log.entries[log.head]
    e.tick = tick
    n := min(len(msg), EVENT_MSG_LEN - 1)
    copy(e.msg[:], msg[:n])
    e.msg[n] = 0
    log.head  = (log.head + 1) % MAX_EVENTS
    if log.count < MAX_EVENTS { log.count += 1 }
}

// Iterate from newest to oldest (newest first).
event_log_get :: proc(log: ^EventLog, i: int) -> ^EventEntry {
    if i >= log.count do return nil
    idx := (log.head - 1 - i + MAX_EVENTS * 2) % MAX_EVENTS
    return &log.entries[idx]
}

event_entry_str :: proc(e: ^EventEntry) -> string {
    return strings.truncate_to_byte(string(e.msg[:]), 0)
}

// ---- Mood ------------------------------------------------------------------

Mood :: enum u8 {
    Content,
    Happy,
    Sad,
    Lovestruck,
    Jealous,
}

mood_label :: proc(m: Mood) -> string {
    switch m {
    case .Content:    return "content"
    case .Happy:      return "happy"
    case .Sad:        return "sad"
    case .Lovestruck: return "lovestruck"
    case .Jealous:    return "jealous"
    }
    return "content"
}

// Per-character social state (derived each tick — NOT authoritative, just cache).
CharSocial :: struct {
    mood             : Mood,
    interaction_count: u32,   // total lifetime interactions (also in Epilog)
    has_crush        : bool,
}

// ---- Simulation state ------------------------------------------------------

SimState :: struct {
    rng      : DependentRNG,
    social   : [MAX_RESIDENTS]CharSocial,
    log      : EventLog,
    // Counters displayed in stats panel
    crush_count : int,
    rival_count : int,
}

sim_init :: proc(s: ^SimState, seed: u64) {
    s^ = {}
    dependent_rng_init(&s.rng, seed, 0xC0FFEE_CAFE_1234)
}

// ---- Epilog interaction count helpers --------------------------------------

_assert_interaction :: proc(engine: ^EpilogEngine, id_a, id_b: u32, count: u32) {
    buf_a, buf_b, buf_src: [128]u8
    atom_a := character_atom(id_a, buf_a[:])
    atom_b := character_atom(id_b, buf_b[:])

    // Retract old count first (ignore failure — might not exist)
    rs := fmt.bprintf(buf_src[:], "interaction_count(%s, %s, _)", atom_a, atom_b)
    buf_src[len(rs)] = 0
    // Epilog doesn't have retract in the FFI, so we just re-assert.
    // Because Epilog indexes by first arg, the newer fact shadows the older one
    // for queries. In practice we'll accumulate duplicates but queries still work.
    as := fmt.bprintf(buf_src[:], "interaction_count(%s, %s, %d).", atom_a, atom_b, count)
    buf_src[len(as)] = 0
    epilog_load_string(engine, cstring(raw_data(buf_src[:])))
}

_assert_crush :: proc(engine: ^EpilogEngine, from_id, on_id: u32) {
    buf_a, buf_b, buf_src: [128]u8
    atom_a := character_atom(from_id, buf_a[:])
    atom_b := character_atom(on_id, buf_b[:])
    s := fmt.bprintf(buf_src[:], "crushing(%s, %s).", atom_a, atom_b)
    buf_src[len(s)] = 0
    epilog_load_string(engine, cstring(raw_data(buf_src[:])))
}

_assert_mood :: proc(engine: ^EpilogEngine, id: u32, m: Mood) {
    buf_id, buf_src: [128]u8
    atom := character_atom(id, buf_id[:])
    s := fmt.bprintf(buf_src[:], "mood(%s, %s).", atom, mood_label(m))
    buf_src[len(s)] = 0
    epilog_load_string(engine, cstring(raw_data(buf_src[:])))
}

// ---- Epilog query helpers (callbacks use "c" ABI) --------------------------

_BoolResult :: struct { found: bool }

_bool_cb :: proc "c" (soln: ^EpilogSolution, ud: rawptr) -> EpilogSignal {
    r := cast(^_BoolResult)ud
    r.found = true
    return .EPILOG_STOP
}

_epilog_bool :: proc(engine: ^EpilogEngine, goal: string) -> bool {
    buf: [256]u8
    gs := fmt.bprintf(buf[:], "%s", goal)
    buf[len(gs)] = 0
    r := _BoolResult{false}
    epilog_query(engine, cstring(raw_data(buf[:])), _bool_cb, &r)
    return r.found
}

// Count solutions (up to cap)
_CountResult :: struct { n: int, cap: int }

_count_cb :: proc "c" (soln: ^EpilogSolution, ud: rawptr) -> EpilogSignal {
    r := cast(^_CountResult)ud
    r.n += 1
    if r.n >= r.cap do return .EPILOG_STOP
    return .EPILOG_NEXT
}

_epilog_count :: proc(engine: ^EpilogEngine, goal: string, cap: int) -> int {
    buf: [256]u8
    gs := fmt.bprintf(buf[:], "%s", goal)
    buf[len(gs)] = 0
    r := _CountResult{0, cap}
    epilog_query(engine, cstring(raw_data(buf[:])), _count_cb, &r)
    return r.n
}

// ---- Load M5 Epilog rules --------------------------------------------------

sim_load_rules :: proc(engine: ^EpilogEngine) {
    // Mood derivation rules
    epilog_load_string(engine,
        "mood(X, jealous) :- rivals(X, _).")
    epilog_load_string(engine,
        "mood(X, lovestruck) :- crushing(X, _).")
    epilog_load_string(engine,
        "mood(X, happy) :- best_friends(X, _).")
    epilog_load_string(engine,
        "mood(X, sad) :- relationship(X, _, partner), crushing(_, X).")
    // unrequited: X crushes on Y but Y doesn't crush on X
    epilog_load_string(engine,
        "unrequited(X, Y) :- crushing(X, Y), \\+ crushing(Y, X).")
}

// ---- Proximity check -------------------------------------------------------
// Two characters are "near" if they are within NEAR_DIST grid cells.

NEAR_DIST :: 8

_chars_near :: proc(a, b: ^Character) -> bool {
    dx := a.position[0] - b.position[0]
    dy := a.position[1] - b.position[1]
    if dx < 0 { dx = -dx }
    if dy < 0 { dy = -dy }
    return dx + dy <= NEAR_DIST
}

// ---- Main simulation tick --------------------------------------------------

sim_tick :: proc(s: ^SimState, res: ^Residents, engine: ^EpilogEngine, tick: u64) {
    // 1. Proximity — increment interaction counts
    for i in 0..<res.count {
        for j in i+1..<res.count {
            a := &res.chars[i]
            b := &res.chars[j]
            if _chars_near(a, b) {
                ia := int(a.id - 1)
                ib := int(b.id - 1)
                if ia < MAX_RESIDENTS { s.social[ia].interaction_count += 1 }
                if ib < MAX_RESIDENTS { s.social[ib].interaction_count += 1 }
                cnt_a := s.social[ia].interaction_count
                _assert_interaction(engine, a.id, b.id, cnt_a)

                // 2. Crush development (gate: eligible query + RNG threshold)
                if !s.social[ia].has_crush {
                    chance := 0.003  // ~0.3% per proximity tick per character
                    roll   := dependent_next(&s.rng)
                    if roll < chance {
                        buf_a, buf_b, goal_buf: [128]u8
                        atom_a := character_atom(a.id, buf_a[:])
                        atom_b := character_atom(b.id, buf_b[:])
                        gs := fmt.bprintf(goal_buf[:], "eligible(%s, %s)", atom_a, atom_b)
                        goal_buf[len(gs)] = 0
                        if _epilog_bool(engine, string(goal_buf[:len(gs)])) {
                            _assert_crush(engine, a.id, b.id)
                            s.social[ia].has_crush = true
                            // Event log
                            msg_buf: [EVENT_MSG_LEN]u8
                            name_a := character_name(a)
                            name_b := character_name(b)
                            ms := fmt.bprintf(msg_buf[:], "%s develops a crush on %s", name_a, name_b)
                            event_log_push(&s.log, tick, string(msg_buf[:len(ms)]))
                        }
                    }
                }
            }
        }
    }

    // 3. Re-derive moods and assert them
    for i in 0..<res.count {
        c  := &res.chars[i]
        ia := int(c.id - 1)
        if ia >= MAX_RESIDENTS do continue

        buf_id, goal_buf: [64]u8
        atom := character_atom(c.id, buf_id[:])

        // Check rivals
        gs := fmt.bprintf(goal_buf[:], "rivals(%s, _)", atom)
        goal_buf[len(gs)] = 0
        if _epilog_bool(engine, string(goal_buf[:len(gs)])) {
            s.social[ia].mood = .Jealous
            _assert_mood(engine, c.id, .Jealous)
            continue
        }

        // Check crushing
        gs = fmt.bprintf(goal_buf[:], "crushing(%s, _)", atom)
        goal_buf[len(gs)] = 0
        if _epilog_bool(engine, string(goal_buf[:len(gs)])) {
            s.social[ia].mood = .Lovestruck
            _assert_mood(engine, c.id, .Lovestruck)
            continue
        }

        // Check best_friends
        gs = fmt.bprintf(goal_buf[:], "best_friends(%s, _)", atom)
        goal_buf[len(gs)] = 0
        if _epilog_bool(engine, string(goal_buf[:len(gs)])) {
            s.social[ia].mood = .Happy
            _assert_mood(engine, c.id, .Happy)
            continue
        }

        s.social[ia].mood = .Content
        _assert_mood(engine, c.id, .Content)
    }

    // 4. Update summary counters for stats panel display
    crush_buf, rival_buf: [64]u8
    cs := fmt.bprintf(crush_buf[:], "crushing(_, _)")
    crush_buf[len(cs)] = 0
    rs := fmt.bprintf(rival_buf[:], "rivals(_, _)")
    rival_buf[len(rs)] = 0
    s.crush_count = _epilog_count(engine, string(crush_buf[:len(cs)]), 64)
    s.rival_count = _epilog_count(engine, string(rival_buf[:len(rs)]), 64) / 2  // pairs
}

/*
 * main.odin — DMLS entry point (M0–M8, complete).
 *
 * Screen state machine:
 *   .Resolution   — resolution picker (first screen)
 *   .Title        — animated title card + New/Load buttons
 *   .World_Setup  — hex seed entry, generate island
 *   .Residents    — resident list + "Add resident"
 *   .Creation     — character creation form
 *   .Rel_Seeding  — relationship tags for new character
 *   .Simulation   — 80/20 split: grid left, sidebar right
 *
 * Layout in Simulation:
 *   Left  sim_tex  (80% of SW): grid, animated char dots, hover arrows
 *   Right stat_tex (20% of SW): island stats, residents, events, navigate
 *   Dividing line drawn at stats_x().
 *
 * Save / Load (M7): F5 = save, F9 = load; auto-save every 60 ticks.
 * Cutscene overlay (M8): triggered by new social events from SimState.
 *
 * Navigation:
 *   ESC on any screen = quit.
 *   Back buttons on World_Setup, Residents, Rel_Seeding, Simulation.
 */

package dmls

import rl  "vendor:raylib"
import "core:fmt"
import "core:strings"

SAVE_PATH :: "dmls_save.bin"

// ---- Screen enum -----------------------------------------------------------

AppScreen :: enum {
    Resolution,
    Title,
    World_Setup,
    Residents,
    Creation,
    Rel_Seeding,
    Simulation,
}

// ---- App state -------------------------------------------------------------

App :: struct {
    screen        : AppScreen,

    engine        : ^EpilogEngine,

    world         : World,
    residents     : Residents,
    sim           : SimState,

    island_name   : IslandName,

    creation      : CreationScreen,
    rel_seeding   : RelSeeding,
    resident_list : ResidentListScreen,
    title         : TitleScreen,
    res_picker    : ResolutionPicker,
    cutscene      : CutsceneState,

    pending_char  : Character,
    pending_id    : u32,

    cam_col       : i32,
    cam_row       : i32,
    hovered_id    : u32,

    seed_field    : InputField,
    seed_err      : bool,

    sim_timer     : f32,
    stat_timer    : f32,
    anim_time     : f32,

    last_autosave_tick : u64,

    sim_tex  : rl.RenderTexture2D,
    stat_tex : rl.RenderTexture2D,
    rt_ready : bool,

    title_rng : u64,
}

STAT_RATE :: 1.0 / 10.0

// ---- Helpers ---------------------------------------------------------------

_parse_seed :: proc(s: string) -> (u64, bool) {
    val := u64(0)
    if len(s) == 0 do return 0, false
    for ch in s {
        switch ch {
        case '0'..='9': val = val * 16 + u64(ch - '0')
        case 'a'..='f': val = val * 16 + u64(ch - 'a' + 10)
        case 'A'..='F': val = val * 16 + u64(ch - 'A' + 10)
        case: return 0, false
        }
    }
    return val, true
}

_default_seed :: proc() -> u64 {
    return 0x596767647261736C
}

// ---- Save / Load wrappers --------------------------------------------------

_do_save :: proc(app: ^App) {
    save_game(SAVE_PATH, &app.world, &app.residents, &app.sim, app.engine)
}

_do_load :: proc(app: ^App) -> bool {
    epilog_destroy(app.engine)
    app.engine = epilog_create()
    _load_all_rules(app)

    ok := load_game(SAVE_PATH, &app.world, &app.residents, &app.sim, app.engine)
    if ok {
        sim_tick(&app.sim, &app.residents, app.engine, app.world.tick)
        app.cam_col = GRID_W / 2
        app.cam_row = GRID_H / 2
        _draw_stat_panel(app)
    }
    return ok
}

_load_all_rules :: proc(app: ^App) {
    starter_load_rules(app.engine)
}

// ---- Shared exit/back button helpers ---------------------------------------

// Draw an exit (X) button in the top-right corner.  Returns true if clicked.
_draw_exit_btn :: proc() -> bool {
    sz   := i32(36)
    x    := SW() - sz - 8
    y    := i32(8)
    rect := rl.Rectangle{f32(x), f32(y), f32(sz), f32(sz)}
    hov  := rl.CheckCollisionPointRec(rl.GetMousePosition(), rect)
    rl.DrawRectangleRec(rect, hov ? rl.Color{180, 40, 40, 255} : rl.Color{80, 30, 30, 200})
    rl.DrawRectangleLinesEx(rect, 1, rl.Color{200, 60, 60, 255})
    rl.DrawText("X", x + 11, y + 8, UI_FSIZE, COL_TEXT)
    return hov && rl.IsMouseButtonPressed(.LEFT)
}

// Draw a back button at the bottom-left.  Returns true if clicked.
_draw_back_btn :: proc() -> bool {
    rect := rl.Rectangle{f32(UI_LPAD), f32(SH() - 52), 120, 36}
    hov  := rl.CheckCollisionPointRec(rl.GetMousePosition(), rect)
    rl.DrawRectangleRec(rect, hov ? COL_HOVER : COL_INPUT)
    rl.DrawRectangleLinesEx(rect, 1, COL_MUTED)
    rl.DrawText("<- Back", UI_LPAD + 10, SH() - 42, UI_SMALL, COL_MUTED)
    return hov && rl.IsMouseButtonPressed(.LEFT)
}

// ---- World setup screen ----------------------------------------------------

_draw_world_setup :: proc(app: ^App) -> bool {
    rl.ClearBackground(COL_BG)
    rl.DrawText("DMLS", UI_LPAD, UI_PAD, 48, COL_TEXT)
    rl.DrawText("Deb's Minimal Life Simulator", UI_LPAD, UI_PAD + 54, UI_SMALL, COL_MUTED)

    y := i32(UI_PAD + 110)
    rl.DrawText("World seed (hex)", UI_LPAD, y, UI_SMALL, COL_MUTED)
    y += 22

    input_field_draw(&app.seed_field, UI_LPAD, y, 340, 38, "")
    if rl.CheckCollisionPointRec(rl.GetMousePosition(),
            rl.Rectangle{f32(UI_LPAD), f32(y), 340, 38}) &&
            rl.IsMouseButtonPressed(.LEFT) {
        app.seed_field.active = true
    }
    input_field_update(&app.seed_field)

    if app.seed_err {
        rl.DrawText("Invalid hex seed", UI_LPAD, y + 44, UI_SMALL, rl.RED)
    }

    y += 54
    rnd_rect := rl.Rectangle{f32(UI_LPAD + 350), f32(y - 54), 160, 38}
    hov_rnd  := rl.CheckCollisionPointRec(rl.GetMousePosition(), rnd_rect)
    rl.DrawRectangleRec(rnd_rect, hov_rnd ? COL_HOVER : COL_INPUT)
    rl.DrawRectangleLinesEx(rnd_rect, 1, COL_MUTED)
    rl.DrawText("Random seed", UI_LPAD + 360, y - 44, UI_SMALL, COL_MUTED)
    if hov_rnd && rl.IsMouseButtonPressed(.LEFT) {
        rng := u64(rl.GetTime() * 1e9)
        rng ~= rng << 13; rng ~= rng >> 7; rng ~= rng << 17
        buf: [20]u8
        ns := fmt.bprintf(buf[:], "%016X", rng)
        app.seed_field.len = 0
        for i in 0..<len(ns) { app.seed_field.buf[i] = buf[i] }
        app.seed_field.len = len(ns)
    }

    go_rect := rl.Rectangle{f32(UI_LPAD), f32(y), 200, 42}
    hov_go  := rl.CheckCollisionPointRec(rl.GetMousePosition(), go_rect)
    rl.DrawRectangleRec(go_rect, hov_go ? COL_ACCENT : COL_SELECT)
    rl.DrawText("Generate island ->", UI_LPAD + 12, y + 11, UI_FSIZE, COL_TEXT)

    if (hov_go && rl.IsMouseButtonPressed(.LEFT)) || rl.IsKeyPressed(.ENTER) {
        seed_str := input_field_str(&app.seed_field)
        seed     := u64(0)
        ok       := false
        if len(seed_str) == 0 {
            seed, ok = _default_seed(), true
        } else {
            seed, ok = _parse_seed(seed_str)
        }
        if !ok { app.seed_err = true; return false }
        app.seed_err = false
        world_init(&app.world, seed)
        return true
    }

    // Back button → Title
    if _draw_back_btn() {
        app.screen = .Title
    }
    if _draw_exit_btn() || rl.IsKeyPressed(.ESCAPE) {
        rl.CloseWindow()
    }
    return false
}

// ---- Character dot colour --------------------------------------------------

_char_color :: proc(c: ^Character) -> rl.Color {
    return char_palette_color(c.sprite)
}

// ---- Grid-to-screen coordinate mapping ------------------------------------

_grid_to_screen :: proc(gc, gr, cam_col, cam_row, view_w, view_h: i32) -> (px, py: i32, visible: bool) {
    cpx          := render_cell_px()
    visible_cols := view_w  / cpx + 2
    visible_rows := view_h / cpx + 2
    start_col    := cam_col - visible_cols / 2
    start_row    := cam_row - visible_rows / 2
    dc           := gc - start_col
    dr           := gr - start_row
    if dc < 0 || dc >= visible_cols || dr < 0 || dr >= visible_rows {
        return 0, 0, false
    }
    return dc * cpx, dr * cpx, true
}

// ---- Hover arrow query (c-callback, no context) ----------------------------

_HoverRelAccum :: struct {
    ids   : [MAX_RESIDENTS]u32,
    count : int,
}

_hover_rel_cb :: proc "c" (soln: ^EpilogSolution, ud: rawptr) -> EpilogSignal {
    acc := cast(^_HoverRelAccum)ud
    if acc.count >= MAX_RESIDENTS do return .EPILOG_STOP
    for i in 0..<epilog_soln_var_count(soln) {
        name := epilog_soln_var_name(soln, i)
        val  := epilog_soln_var_atom(soln, i)
        if name == nil || val == nil do continue
        if string(name) == "Other" {
            other_str := string(val)
            other_id  := u32(0)
            if len(other_str) > 5 && other_str[:5] == "char_" {
                for ch in other_str[5:] {
                    if ch >= '0' && ch <= '9' {
                        other_id = other_id * 10 + u32(ch - '0')
                    }
                }
            }
            acc.ids[acc.count] = other_id
            acc.count += 1
        }
    }
    return .EPILOG_NEXT
}

_draw_hover_arrows :: proc(app: ^App, hovered_char: ^Character) {
    buf_id, goal_buf: [128]u8
    atom := character_atom(hovered_char.id, buf_id[:])
    gs   := fmt.bprintf(goal_buf[:], "relationship(%s, Other, _)", atom)
    goal_buf[len(gs)] = 0

    acc := _HoverRelAccum{}
    epilog_query(app.engine, cstring(raw_data(goal_buf[:])), _hover_rel_cb, &acc)

    hx, hy, hv := _grid_to_screen(hovered_char.position[0], hovered_char.position[1],
                                   app.cam_col, app.cam_row, sim_w(), sim_h())
    if !hv do return

    cpx := render_cell_px()
    for i in 0..<acc.count {
        other := residents_find(&app.residents, acc.ids[i])
        if other == nil do continue
        ox, oy, ov := _grid_to_screen(other.position[0], other.position[1],
                                       app.cam_col, app.cam_row, sim_w(), sim_h())
        if !ov do continue
        rl.DrawLine(hx + cpx/2, hy + cpx/2,
                    ox + cpx/2, oy + cpx/2,
                    rl.Color{200, 200, 60, 160})
    }
}

// ---- Draw simulation view into sim_tex (60 fps) ----------------------------

_draw_sim_view :: proc(app: ^App) {
    rl.BeginTextureMode(app.sim_tex)
    rl.ClearBackground(COL_BG)

    cpx := render_cell_px()
    grid_render(&app.world.grid, 0, 0, sim_w(), sim_h(), app.cam_col, app.cam_row, cpx)

    mouse          := rl.GetMousePosition()
    app.hovered_id  = 0

    for i in 0..<app.residents.count {
        c  := &app.residents.chars[i]
        px, py, vis := _grid_to_screen(c.position[0], c.position[1],
                                        app.cam_col, app.cam_row, sim_w(), sim_h())
        if !vis do continue

        col := _char_color(c)
        draw_char_dot_animated(c, px, py, col, app.anim_time, cpx)

        dot_rect := rl.Rectangle{f32(px) - 4, f32(py) - 4,
                                  f32(cpx) + 8, f32(cpx) + 8}
        if rl.CheckCollisionPointRec(mouse, dot_rect) {
            app.hovered_id = c.id
        }
    }

    if app.hovered_id != 0 {
        hov_char := residents_find(&app.residents, app.hovered_id)
        if hov_char != nil {
            _draw_hover_arrows(app, hov_char)
            hx, hy, _ := _grid_to_screen(hov_char.position[0], hov_char.position[1],
                                           app.cam_col, app.cam_row, sim_w(), sim_h())
            name_cstr := strings.clone_to_cstring(character_name(hov_char), context.temp_allocator)
            rl.DrawText(name_cstr, hx + 6, hy - 18, UI_SMALL, COL_TEXT)
            ia := int(hov_char.id - 1)
            if ia >= 0 && ia < MAX_RESIDENTS {
                mood_cstr := strings.clone_to_cstring(mood_label(app.sim.social[ia].mood), context.temp_allocator)
                rl.DrawText(mood_cstr, hx + 6, hy - 2, UI_SMALL, COL_MUTED)
            }
        }
    }

    rl.DrawText("WASD: pan   hover: inspect   F5: save   F9: load",
                8, sim_h() - 20, UI_SMALL, COL_MUTED)
    rl.EndTextureMode()
}

// ---- Draw stats sidebar into stat_tex (10 fps) ------------------------------

_draw_stat_panel :: proc(app: ^App) {
    rl.BeginTextureMode(app.stat_tex)
    rl.ClearBackground(COL_PANEL)

    sw := stat_w()
    y  := i32(UI_PAD)
    lx := i32(UI_PAD)

    rl.DrawText("ISLAND STATS", lx, y, UI_SMALL, COL_ACCENT)
    y += 20

    iname_cstr := strings.clone_to_cstring(island_name_str(&app.island_name), context.temp_allocator)
    rl.DrawText(iname_cstr, lx, y, UI_FSIZE, COL_TEXT)
    y += 24

    seed_buf: [24]u8
    rl.DrawText("Seed:", lx, y, UI_SMALL, COL_MUTED)
    seed_cstr := world_seed_string(&app.world, seed_buf[:])
    rl.DrawText(seed_cstr, lx + 50, y, UI_SMALL, COL_TEXT)
    y += 20

    stat_lines: [4][48]u8
    sl0 := fmt.bprintf(stat_lines[0][:], "Tick:      %d", app.world.tick)
    stat_lines[0][len(sl0)] = 0
    sl1 := fmt.bprintf(stat_lines[1][:], "Residents: %d", app.residents.count)
    stat_lines[1][len(sl1)] = 0
    sl2 := fmt.bprintf(stat_lines[2][:], "Crushes:   %d", app.sim.crush_count)
    stat_lines[2][len(sl2)] = 0
    sl3 := fmt.bprintf(stat_lines[3][:], "Rivals:    %d pairs", app.sim.rival_count)
    stat_lines[3][len(sl3)] = 0
    for &ln in stat_lines {
        rl.DrawText(cstring(raw_data(ln[:])), lx, y, UI_SMALL, COL_TEXT)
        y += 18
    }
    y += 8

    rl.DrawLine(lx, y, sw - lx, y, COL_MUTED)
    y += 10

    rl.DrawText("RESIDENTS", lx, y, UI_SMALL, COL_ACCENT)
    y += 20

    for i in 0..<app.residents.count {
        c  := &app.residents.chars[i]
        ia := int(c.id - 1)
        rl.DrawRectangle(lx, y + 3, 10, 10, _char_color(c))
        name_cstr := strings.clone_to_cstring(character_name(c), context.temp_allocator)
        rl.DrawText(name_cstr, lx + 16, y, UI_SMALL, COL_TEXT)
        if ia >= 0 && ia < MAX_RESIDENTS {
            mood_cstr := strings.clone_to_cstring(mood_label(app.sim.social[ia].mood), context.temp_allocator)
            rl.DrawText(mood_cstr, lx + 110, y, UI_SMALL, COL_MUTED)
        }
        y += 18
    }
    if app.residents.count == 0 {
        rl.DrawText("none yet", lx, y, UI_SMALL, COL_MUTED)
        y += 18
    }
    y += 8

    rl.DrawLine(lx, y, sw - lx, y, COL_MUTED)
    y += 10

    rl.DrawText("EVENTS", lx, y, UI_SMALL, COL_ACCENT)
    y += 20

    MAX_SHOWN :: 8
    shown := min(app.sim.log.count, MAX_SHOWN)
    if shown == 0 {
        rl.DrawText("no events yet", lx, y, UI_SMALL, COL_MUTED)
        y += 18
    } else {
        for i in 0..<shown {
            e := event_log_get(&app.sim.log, i)
            if e == nil do continue
            buf: [EVENT_MSG_LEN + 16]u8
            es := fmt.bprintf(buf[:], "[%d] %s", e.tick, event_entry_str(e))
            buf[len(es)] = 0
            rl.DrawText(cstring(raw_data(buf[:])), lx, y, UI_SMALL, COL_TEXT)
            y += 18
        }
    }

    y += 8
    rl.DrawLine(lx, y, sw - lx, y, COL_MUTED)
    y += 10

    rl.DrawText("NAVIGATE", lx, y, UI_SMALL, COL_ACCENT)
    y += 20

    // "Residents" button — clicks handled in window coords by _handle_stat_clicks
    res_rect := rl.Rectangle{f32(lx), f32(y), 160, 30}
    hov_res  := rl.CheckCollisionPointRec(rl.GetMousePosition(), res_rect)
    rl.DrawRectangleRec(res_rect, hov_res ? COL_HOVER : COL_INPUT)
    rl.DrawText("Residents ->", lx + 8, y + 7, UI_SMALL, COL_TEXT)
    y += 40

    // Exit button inside sidebar
    exit_rect := rl.Rectangle{f32(lx), f32(y), 120, 30}
    hov_exit  := rl.CheckCollisionPointRec(rl.GetMousePosition(), exit_rect)
    rl.DrawRectangleRec(exit_rect, hov_exit ? rl.Color{180, 40, 40, 255} : rl.Color{80, 30, 30, 200})
    rl.DrawText("Quit", lx + 8, y + 7, UI_SMALL, COL_TEXT)

    rl.EndTextureMode()
}

// ---- Stat sidebar button clicks (window/composite coords) -------------------

_handle_stat_clicks :: proc(app: ^App) {
    res_rows  := i32(app.residents.count)
    res_empty := app.residents.count == 0 ? i32(18) : i32(0)
    evt_shown := i32(min(app.sim.log.count, 8))
    evt_empty := app.sim.log.count == 0 ? i32(18) : i32(0)

    // Reconstruct y position of the Residents → button (must match _draw_stat_panel layout)
    base_y := i32(UI_PAD) +
        i32(20 + 24 + 20 + 18*4 + 8) +    // ISLAND STATS block
        i32(10 + 20) +                      // divider + RESIDENTS header
        i32(18)*res_rows + res_empty + i32(8) +
        i32(10 + 10 + 20) +                 // divider + EVENTS header
        i32(18)*evt_shown + evt_empty + i32(8) +
        i32(10 + 10 + 20)                   // divider + NAVIGATE header

    ox       := stats_x() + i32(UI_PAD)
    res_rect := rl.Rectangle{f32(ox), f32(base_y), 160, 30}
    if rl.CheckCollisionPointRec(rl.GetMousePosition(), res_rect) &&
       rl.IsMouseButtonPressed(.LEFT) {
        app.screen = .Residents
        app.resident_list = {}
    }

    exit_y    := base_y + 40
    exit_rect := rl.Rectangle{f32(ox), f32(exit_y), 120, 30}
    if rl.CheckCollisionPointRec(rl.GetMousePosition(), exit_rect) &&
       rl.IsMouseButtonPressed(.LEFT) {
        rl.CloseWindow()
    }
}

// ---- Cutscene check — trigger when new event appears -----------------------

_last_event_count: int

_check_cutscene :: proc(app: ^App) {
    if app.sim.log.count > _last_event_count {
        e := event_log_get(&app.sim.log, 0)
        if e != nil {
            cutscene_trigger(&app.cutscene, event_entry_str(e))
        }
        _last_event_count = app.sim.log.count
    }
}

// ---- Simulation update + composite -----------------------------------------

_update_simulation :: proc(app: ^App) {
    dt := rl.GetFrameTime()
    app.anim_time += dt

    // ESC → quit
    if rl.IsKeyPressed(.ESCAPE) {
        rl.CloseWindow()
        return
    }

    // WASD pan
    if rl.IsKeyDown(.W) { app.cam_row -= 2 }
    if rl.IsKeyDown(.S) { app.cam_row += 2 }
    if rl.IsKeyDown(.A) { app.cam_col -= 2 }
    if rl.IsKeyDown(.D) { app.cam_col += 2 }
    app.cam_col = clamp(app.cam_col, 0, GRID_W - 1)
    app.cam_row = clamp(app.cam_row, 0, GRID_H - 1)

    // F5 = save, F9 = load
    if rl.IsKeyPressed(.F5) {
        _do_save(app)
    }
    if rl.IsKeyPressed(.F9) {
        if _do_load(app) {
            _draw_stat_panel(app)
        }
    }

    // Sim tick at 1 Hz
    app.sim_timer += dt
    if app.sim_timer >= 1.0 {
        app.sim_timer = 0
        world_tick_wander(&app.world, &app.residents)
        sim_tick(&app.sim, &app.residents, app.engine, app.world.tick)
        _check_cutscene(app)

        // Auto-save every 60 ticks
        if app.world.tick - app.last_autosave_tick >= 60 {
            _do_save(app)
            app.last_autosave_tick = app.world.tick
        }
    }

    // Redraw at appropriate rates
    _draw_sim_view(app)
    app.stat_timer += dt
    if app.stat_timer >= STAT_RATE {
        app.stat_timer = 0
        _draw_stat_panel(app)
    }

    // Composite — 80/20 side-by-side
    rl.ClearBackground(rl.BLACK)

    // Left: grid (80%)
    src_sim := rl.Rectangle{0, 0, f32(sim_w()), -f32(sim_h())}
    dst_sim := rl.Rectangle{0, 0, f32(sim_w()),  f32(sim_h())}
    rl.DrawTexturePro(app.sim_tex.texture, src_sim, dst_sim, {0, 0}, 0, rl.WHITE)

    // Right: sidebar (20%)
    src_stat := rl.Rectangle{0, 0, f32(stat_w()), -f32(stat_h())}
    dst_stat := rl.Rectangle{f32(stats_x()), 0, f32(stat_w()), f32(stat_h())}
    rl.DrawTexturePro(app.stat_tex.texture, src_stat, dst_stat, {0, 0}, 0, rl.WHITE)

    // Dividing line
    rl.DrawLine(stats_x(), 0, stats_x(), SH(), COL_MUTED)

    _handle_stat_clicks(app)

    // M8 cutscene overlay on top of everything
    cutscene_update(&app.cutscene)
}

// ---- Main ------------------------------------------------------------------

main :: proc() {
    rl.SetConfigFlags({.WINDOW_RESIZABLE})
    g_screen.w = SCREEN_W
    g_screen.h = SCREEN_H
    rl.InitWindow(SCREEN_W, SCREEN_H, "DMLS — Deb's Minimal Life Simulator")
    rl.SetTargetFPS(60)
    defer rl.CloseWindow()

    app := new(App)
    defer free(app)

    app.engine = epilog_create()
    defer epilog_destroy(app.engine)

    residents_init(&app.residents)
    app.screen    = .Resolution
    app.cam_col   = GRID_W / 2
    app.cam_row   = GRID_H / 2
    app.title_rng = 0xFEEDBEEF_CAFEBABE

    {
        def := _default_seed()
        ds  := fmt.bprintf(app.seed_field.buf[:], "%016X", def)
        app.seed_field.len = len(ds)
        app.seed_field.active = true
    }

    _load_all_rules(app)
    resolution_picker_init(&app.res_picker)

    // Allocate RenderTextures at maximum possible sizes.
    // sim_tex: widest sim viewport = 80% of 1920 = 1536, tallest = 1080.
    // stat_tex: widest sidebar = 20% of 1920 = 384, tallest = 1080.
    app.sim_tex  = rl.LoadRenderTexture(SCREEN_W * 80 / 100, SCREEN_H)
    app.stat_tex = rl.LoadRenderTexture(SCREEN_W - SCREEN_W * 80 / 100, SCREEN_H)
    app.rt_ready = true
    defer rl.UnloadRenderTexture(app.sim_tex)
    defer rl.UnloadRenderTexture(app.stat_tex)

    title_screen_init(&app.title)

    for !rl.WindowShouldClose() {
        rl.BeginDrawing()
        free_all(context.temp_allocator)

        switch app.screen {

        case .Resolution:
            if resolution_picker_update(&app.res_picker) {
                app.screen = .Title
            }
            // Exit button on resolution picker
            if _draw_exit_btn() || rl.IsKeyPressed(.ESCAPE) {
                rl.CloseWindow()
            }

        case .Title:
            result := title_screen_update(&app.title, &app.island_name, &app.title_rng)
            switch result {
            case 1:
                app.screen = .World_Setup
            case 2:
                if _do_load(app) {
                    app.screen = .Simulation
                } else {
                    app.title.load_err   = true
                    app.title.load_err_t = 3.0
                }
            }
            // Exit button on title screen
            if _draw_exit_btn() || rl.IsKeyPressed(.ESCAPE) {
                rl.CloseWindow()
            }

        case .World_Setup:
            // Back + exit drawn inside _draw_world_setup
            _draw_world_setup(app)

        case .Residents:
            if resident_list_update(&app.resident_list, &app.residents, app.engine) {
                creation_screen_init(&app.creation)
                app.screen = .Creation
            }
            // "Simulate ->" button
            sim_rect := rl.Rectangle{f32(SW() - 200), f32(SH() - 60), 180, 42}
            hov_sim  := rl.CheckCollisionPointRec(rl.GetMousePosition(), sim_rect)
            if app.residents.count > 0 {
                rl.DrawRectangleRec(sim_rect, hov_sim ? COL_ACCENT2 : COL_ACCENT)
                rl.DrawText("Simulate ->", SW() - 188, SH() - 46, UI_FSIZE, COL_TEXT)
                if hov_sim && rl.IsMouseButtonPressed(.LEFT) {
                    app.screen = .Simulation
                    _draw_stat_panel(app)
                }
            }
            // Back → World_Setup
            if _draw_back_btn() {
                app.screen = .World_Setup
            }
            if _draw_exit_btn() || rl.IsKeyPressed(.ESCAPE) {
                rl.CloseWindow()
            }

        case .Creation:
            new_char: Character
            if creation_screen_update(&app.creation, &new_char) {
                app.pending_char = new_char
                app.pending_id   = residents_add(&app.residents, new_char)
                epilog_assert_character(app.engine, residents_find(&app.residents, app.pending_id))
                world_spawn_character(&app.world, &app.residents, app.pending_id)
                rel_seeding_init(&app.rel_seeding, app.pending_id, &app.residents)
                app.screen = .Rel_Seeding
            }
            // Back → Residents
            if _draw_back_btn() {
                app.screen = .Residents
            }
            if _draw_exit_btn() || rl.IsKeyPressed(.ESCAPE) {
                rl.CloseWindow()
            }

        case .Rel_Seeding:
            if rel_seeding_update(&app.rel_seeding, &app.residents) {
                rel_seeding_commit(&app.rel_seeding, &app.residents, app.engine)
                app.screen = .Residents
                app.resident_list = {}
            }
            // Back → Residents (discards pending character)
            if _draw_back_btn() {
                app.screen = .Residents
            }
            if _draw_exit_btn() || rl.IsKeyPressed(.ESCAPE) {
                rl.CloseWindow()
            }

        case .Simulation:
            _update_simulation(app)
        }

        rl.EndDrawing()
    }
}

package dmls

import "core:fmt"
import "core:strings"
import "core:c"

// ---- Enumerations ----------------------------------------------------------

Gender :: enum u8 {
    Male,
    Female,
    Nonbinary,
}

DatingPref :: enum u8 {
    Male,
    Female,
    Any,
    None,
}

Pronouns :: enum u8 {
    He_Him,
    She_Her,
    They_Them,
}

Personality :: enum u8 {
    Ambitious_Achiever,
    Outgoing_Merrymaker,
    Outgoing_Dynamo,
    Laid_Back_Guy,
    Sweetie,
    Cranky,
}

RelationshipTag :: enum u8 {
    Stranger,
    Acquaintance,
    Friend,
    Sibling,
    Partner,
}

// ---- Character struct ------------------------------------------------------

MAX_NAME_LEN  :: 32
MAX_RESIDENTS :: 64

Character :: struct {
    id          : u32,
    name        : [MAX_NAME_LEN]u8,
    nickname    : [MAX_NAME_LEN]u8,
    age         : u8,
    gender      : Gender,
    dating_pref : DatingPref,
    personality : Personality,
    pronouns    : Pronouns,
    position    : [2]i32,
    sprite      : u32,
}

character_name :: proc(c: ^Character) -> string {
    return strings.truncate_to_byte(string(c.name[:]), 0)
}

character_nickname :: proc(c: ^Character) -> string {
    return strings.truncate_to_byte(string(c.nickname[:]), 0)
}

character_atom :: proc(id: u32, buf: []u8) -> cstring {
    s := fmt.bprintf(buf, "char_%d", id)
    buf[len(s)] = 0
    return cstring(raw_data(buf))
}

// ---- Resident registry -----------------------------------------------------

Residents :: struct {
    chars  : [MAX_RESIDENTS]Character,
    count  : u32,
    next_id: u32,
    rel    : [MAX_RESIDENTS][MAX_RESIDENTS]RelationshipTag,
}

residents_init :: proc(r: ^Residents) {
    r^ = {}
    r.next_id = 1
}

residents_add :: proc(r: ^Residents, c: Character) -> u32 {
    assert(r.count < MAX_RESIDENTS)
    idx := r.count
    r.chars[idx] = c
    r.chars[idx].id = r.next_id
    r.next_id += 1
    r.count += 1
    return r.chars[idx].id
}

residents_find :: proc(r: ^Residents, id: u32) -> ^Character {
    for i in 0..<r.count {
        if r.chars[i].id == id do return &r.chars[i]
    }
    return nil
}

// ---- Display helpers -------------------------------------------------------

gender_label :: proc(g: Gender) -> string {
    switch g {
    case .Male:      return "Male"
    case .Female:    return "Female"
    case .Nonbinary: return "Nonbinary"
    }
    return ""
}

dating_pref_label :: proc(d: DatingPref) -> string {
    switch d {
    case .Male:   return "Men"
    case .Female: return "Women"
    case .Any:    return "Anyone"
    case .None:   return "Nobody"
    }
    return ""
}

pronouns_label :: proc(p: Pronouns) -> string {
    switch p {
    case .He_Him:    return "he/him"
    case .She_Her:   return "she/her"
    case .They_Them: return "they/them"
    }
    return ""
}

personality_label :: proc(p: Personality) -> string {
    switch p {
    case .Ambitious_Achiever:  return "Ambitious Achiever"
    case .Outgoing_Merrymaker: return "Outgoing Merrymaker"
    case .Outgoing_Dynamo:     return "Outgoing Dynamo"
    case .Laid_Back_Guy:       return "Laid-Back Guy"
    case .Sweetie:             return "Sweetie"
    case .Cranky:              return "Cranky"
    }
    return ""
}

personality_atom :: proc(p: Personality) -> cstring {
    switch p {
    case .Ambitious_Achiever:  return "ambitious_achiever"
    case .Outgoing_Merrymaker: return "outgoing_merrymaker"
    case .Outgoing_Dynamo:     return "outgoing_dynamo"
    case .Laid_Back_Guy:       return "laid_back_guy"
    case .Sweetie:             return "sweetie"
    case .Cranky:              return "cranky"
    }
    return "unknown"
}

dating_pref_atom :: proc(d: DatingPref) -> cstring {
    switch d {
    case .Male:   return "male"
    case .Female: return "female"
    case .Any:    return "any"
    case .None:   return "none"
    }
    return "none"
}

relationship_atom :: proc(t: RelationshipTag) -> cstring {
    switch t {
    case .Stranger:     return "stranger"
    case .Acquaintance: return "acquaintance"
    case .Friend:       return "friend"
    case .Sibling:      return "sibling"
    case .Partner:      return "partner"
    }
    return "stranger"
}

// ---- Assert character into Epilog ------------------------------------------

epilog_assert_character :: proc(engine: ^EpilogEngine, c: ^Character) {
    buf_id : [32]u8
    buf_src: [256]u8

    atom := character_atom(c.id, buf_id[:])

    gender_str: cstring
    switch c.gender {
    case .Male:      gender_str = "male"
    case .Female:    gender_str = "female"
    case .Nonbinary: gender_str = "nonbinary"
    }

    s := fmt.bprintf(buf_src[:], "character(%s, %s).", atom, personality_atom(c.personality))
    buf_src[len(s)] = 0
    epilog_load_string(engine, cstring(raw_data(buf_src[:])))

    s = fmt.bprintf(buf_src[:], "dating_pref(%s, %s).", atom, dating_pref_atom(c.dating_pref))
    buf_src[len(s)] = 0
    epilog_load_string(engine, cstring(raw_data(buf_src[:])))

    s = fmt.bprintf(buf_src[:], "gender(%s, %s).", atom, gender_str)
    buf_src[len(s)] = 0
    epilog_load_string(engine, cstring(raw_data(buf_src[:])))
}

epilog_assert_relationship :: proc(engine: ^EpilogEngine, id_a, id_b: u32, tag: RelationshipTag) {
    buf_a  : [32]u8
    buf_b  : [32]u8
    buf_src: [128]u8

    atom_a := character_atom(id_a, buf_a[:])
    atom_b := character_atom(id_b, buf_b[:])

    s := fmt.bprintf(buf_src[:], "relationship(%s, %s, %s).", atom_a, atom_b, relationship_atom(tag))
    buf_src[len(s)] = 0
    epilog_load_string(engine, cstring(raw_data(buf_src[:])))
}

/*
 * screen_cfg.odin — Runtime screen resolution configuration.
 *
 * Three supported resolutions: 640×320, 1920×720, 1920×1080.
 * The player picks one on the title screen before generating the world.
 *
 * SCREEN_W / SCREEN_H compile-time constants remain as the maximum dimensions
 * (1920×1080) used only for RenderTexture allocation and rl.InitWindow.
 * All rendering code reads SW() / SH() for the active dimensions.
 *
 * Derived layout values (stats panel split, sim panel dimensions) are also
 * exposed as procs so they react to resolution changes automatically.
 */

package dmls

import rl "vendor:raylib"

// ---- Resolution enum -------------------------------------------------------

ScreenSize :: enum {
    S_640x320,
    S_1920x720,
    S_1920x1080,
}

SCREEN_SIZE_LABELS := [ScreenSize]cstring{
    .S_640x320   = "640 × 320  (Compact)",
    .S_1920x720  = "1920 × 720  (Wide)",
    .S_1920x1080 = "1920 × 1080  (Full HD)",
}

SCREEN_SIZE_W := [ScreenSize]i32{
    .S_640x320   = 640,
    .S_1920x720  = 1920,
    .S_1920x1080 = 1920,
}

SCREEN_SIZE_H := [ScreenSize]i32{
    .S_640x320   = 320,
    .S_1920x720  = 720,
    .S_1920x1080 = 1080,
}

// ---- Active screen state (global) -----------------------------------------

ScreenCfg :: struct {
    w    : i32,
    h    : i32,
    size : ScreenSize,
}

g_screen : ScreenCfg

screen_cfg_set :: proc(sz: ScreenSize) {
    g_screen.size = sz
    g_screen.w    = SCREEN_SIZE_W[sz]
    g_screen.h    = SCREEN_SIZE_H[sz]
    rl.SetWindowSize(g_screen.w, g_screen.h)
}

// Convenience accessors used everywhere in rendering code.
SW :: #force_inline proc() -> i32 { return g_screen.w }
SH :: #force_inline proc() -> i32 { return g_screen.h }

// Derived layout values — 80 / 20 split: left 80% = grid sim, right 20% = sidebar.
// sim_w / sim_h = the grid viewport dimensions.
// stat_w / stat_h = the sidebar dimensions.
// stats_x = x pixel where the sidebar begins (= sim_w).
sim_w   :: #force_inline proc() -> i32 { return SW() * 80 / 100 }
sim_h   :: #force_inline proc() -> i32 { return SH() }
stats_x :: #force_inline proc() -> i32 { return sim_w() }
stat_w  :: #force_inline proc() -> i32 { return SW() - sim_w() }
stat_h  :: #force_inline proc() -> i32 { return SH() }

// Dynamic cell pixel size: fit as many cells as possible into the sim viewport.
// Result is at least 1.
render_cell_px :: #force_inline proc() -> i32 {
    px := sim_w() / GRID_W
    if px < 1 { px = 1 }
    return px
}

// ---- Character colour palette (8 distinct colours, indexed by sprite) ------
//
// Each of the 8 sprite slots has a fixed canonical colour.
// Starter characters are assigned slots 0–3 matching their canonical look.
//   0 = [NAME] — warm amber / gold
//   1 = Uriel     — soft sky blue
//   2 = Anna Croft — vivid coral red
//   3 = Saloni    — peach / warm orange
//   4–7           — available for player-created characters

CHAR_PALETTE := [SPRITE_COUNT]rl.Color{
    rl.Color{230, 180,  60, 255},  // 0 [NAME]  — amber gold
    rl.Color{ 80, 180, 230, 255},  // 1 Uriel       — sky blue
    rl.Color{220,  70,  70, 255},  // 2 Anna Croft  — coral red
    rl.Color{240, 150,  80, 255},  // 3 Saloni      — warm peach
    rl.Color{100, 210, 140, 255},  // 4              — mint green
    rl.Color{170,  90, 220, 255},  // 5              — violet
    rl.Color{220, 210,  80, 255},  // 6              — yellow
    rl.Color{180, 180, 200, 255},  // 7              — silver
}

char_palette_color :: proc(sprite: u32) -> rl.Color {
    idx := int(sprite) % SPRITE_COUNT
    return CHAR_PALETTE[idx]
}

// ---- Resolution picker UI --------------------------------------------------
// Drawn on the title screen before island naming.
// Returns true when the player has confirmed a choice.

ResolutionPicker :: struct {
    chosen   : ScreenSize,
    confirmed: bool,
}

resolution_picker_init :: proc(p: ^ResolutionPicker) {
    p.chosen    = .S_1920x1080
    p.confirmed = false
}

// Draw and handle input. Returns true once confirmed.
resolution_picker_update :: proc(p: ^ResolutionPicker) -> bool {
    rl.ClearBackground(COL_BG)

    cy := SH() / 2 - 120
    rl.DrawText("Choose resolution", UI_LPAD, cy - 40, UI_HSIZE, COL_TEXT)

    for sz in ScreenSize {
        label := SCREEN_SIZE_LABELS[sz]
        sel   := p.chosen == sz
        rect  := rl.Rectangle{f32(UI_LPAD), f32(cy), 400, 44}
        bg    := sel ? COL_SELECT : COL_INPUT
        hov   := rl.CheckCollisionPointRec(rl.GetMousePosition(), rect)
        if hov { bg = sel ? COL_ACCENT : COL_HOVER }
        rl.DrawRectangleRec(rect, bg)
        rl.DrawRectangleLinesEx(rect, 1, sel ? COL_ACCENT : COL_MUTED)
        rl.DrawText(label, UI_LPAD + 14, cy + 12, UI_FSIZE, COL_TEXT)
        if hov && rl.IsMouseButtonPressed(.LEFT) {
            p.chosen = sz
        }
        cy += 54
    }

    cy += 10
    ok_rect := rl.Rectangle{f32(UI_LPAD), f32(cy), 200, 44}
    hov_ok  := rl.CheckCollisionPointRec(rl.GetMousePosition(), ok_rect)
    rl.DrawRectangleRec(ok_rect, hov_ok ? COL_ACCENT : COL_SELECT)
    rl.DrawText("Confirm ->", UI_LPAD + 16, cy + 12, UI_FSIZE, COL_TEXT)

    if (hov_ok && rl.IsMouseButtonPressed(.LEFT)) || rl.IsKeyPressed(.ENTER) {
        screen_cfg_set(p.chosen)
        p.confirmed = true
        return true
    }
    return false
}

/*
 * anim.odin — Idle animations + relationship cutscene overlay (M8).
 *
 * Idle animations:
 *   Each personality type has a distinct bob/pulse pattern drawn on the
 *   character dot in the sim view. Animations are purely visual — they
 *   don't affect simulation state.
 *
 * Cutscene overlay:
 *   When a social event fires (crush formed, rivals detected), a short
 *   full-screen overlay fades in, shows a one-line message with animated
 *   sprite dots, then fades out. Driven by AnimState.
 */

package dmls

import rl "vendor:raylib"
import "core:math"
import "core:strings"

// ---- Idle animation --------------------------------------------------------
// Returns a y-offset (pixels) for the character dot bob and a brightness
// multiplier [0.7, 1.0] for colour pulsing.

IdleAnim :: struct {
    bob_amp   : f32,   // pixel amplitude of vertical bob
    bob_freq  : f32,   // Hz
    pulse_amp : f32,   // colour pulse amplitude [0, 0.3]
    pulse_freq: f32,   // Hz
}

_idle_anim_for_personality :: proc(p: Personality) -> IdleAnim {
    switch p {
    case .Ambitious_Achiever:
        return IdleAnim{bob_amp = 0.8, bob_freq = 2.4, pulse_amp = 0.15, pulse_freq = 2.0}
    case .Outgoing_Merrymaker:
        return IdleAnim{bob_amp = 1.5, bob_freq = 3.0, pulse_amp = 0.25, pulse_freq = 2.5}
    case .Outgoing_Dynamo:
        return IdleAnim{bob_amp = 1.2, bob_freq = 2.8, pulse_amp = 0.20, pulse_freq = 3.0}
    case .Laid_Back_Guy:
        return IdleAnim{bob_amp = 0.3, bob_freq = 0.8, pulse_amp = 0.05, pulse_freq = 0.5}
    case .Sweetie:
        return IdleAnim{bob_amp = 0.6, bob_freq = 1.6, pulse_amp = 0.20, pulse_freq = 1.2}
    case .Cranky:
        return IdleAnim{bob_amp = 0.4, bob_freq = 1.0, pulse_amp = 0.10, pulse_freq = 4.0}
    }
    return IdleAnim{bob_amp = 0.5, bob_freq = 1.0, pulse_amp = 0.1, pulse_freq = 1.0}
}

// Returns (dy_pixels, brightness) for a character at global time t.
idle_anim_sample :: proc(c: ^Character, t: f32) -> (dy: f32, brightness: f32) {
    a   := _idle_anim_for_personality(c.personality)
    // offset per character so they don't all bob in sync
    phi := f32(c.id) * 0.9
    dy  = a.bob_amp * math.sin_f32(t * a.bob_freq * 6.2832 + phi)
    brightness = 0.85 + a.pulse_amp * math.sin_f32(t * a.pulse_freq * 6.2832 + phi)
    return
}

// Draw a character dot with idle animation applied (for use in sim view).
draw_char_dot_animated :: proc(c: ^Character, px, py: i32, base_col: rl.Color, t: f32, cell_px: i32) {
    dy, bright := idle_anim_sample(c, t)
    apy := py + i32(dy)
    r   := u8(min(255, int(f32(base_col.r) * bright)))
    g   := u8(min(255, int(f32(base_col.g) * bright)))
    b   := u8(min(255, int(f32(base_col.b) * bright)))
    rl.DrawRectangle(px, apy, cell_px, cell_px, rl.Color{r, g, b, 255})
}

// ---- Cutscene overlay -------------------------------------------------------

CUTSCENE_FADE_IN  :: 0.35   // seconds
CUTSCENE_HOLD     :: 2.2    // seconds
CUTSCENE_FADE_OUT :: 0.45   // seconds
CUTSCENE_TOTAL    :: CUTSCENE_FADE_IN + CUTSCENE_HOLD + CUTSCENE_FADE_OUT

CutsceneState :: struct {
    active   : bool,
    timer    : f32,
    msg      : [EVENT_MSG_LEN]u8,
    msg_len  : int,
    dot_t    : f32,   // rolling dot animation timer
}

cutscene_trigger :: proc(cs: ^CutsceneState, msg: string) {
    cs.active  = true
    cs.timer   = 0
    cs.dot_t   = 0
    n := min(len(msg), EVENT_MSG_LEN - 1)
    copy(cs.msg[:], msg[:n])
    cs.msg[n] = 0
    cs.msg_len = n
}

// Returns true while the cutscene is still running.
cutscene_update :: proc(cs: ^CutsceneState) -> bool {
    if !cs.active do return false

    dt       := rl.GetFrameTime()
    cs.timer += dt
    cs.dot_t += dt

    if cs.timer > CUTSCENE_TOTAL {
        cs.active = false
        return false
    }

    // Alpha
    alpha := f32(0)
    if cs.timer < CUTSCENE_FADE_IN {
        alpha = cs.timer / CUTSCENE_FADE_IN
    } else if cs.timer < CUTSCENE_FADE_IN + CUTSCENE_HOLD {
        alpha = 1.0
    } else {
        alpha = 1.0 - (cs.timer - CUTSCENE_FADE_IN - CUTSCENE_HOLD) / CUTSCENE_FADE_OUT
    }
    if alpha < 0 { alpha = 0 }
    if alpha > 1 { alpha = 1 }

    // Background overlay
    rl.DrawRectangle(0, 0, SW(), SH(),
                     rl.Color{10, 10, 18, u8(200 * alpha)})

    // Card
    cw := i32(560)
    ch := i32(100)
    cx := (SW() - cw) / 2
    cy := (SH() - ch) / 2
    rl.DrawRectangle(cx, cy, cw, ch, rl.Color{28, 28, 48, u8(230 * alpha)})
    rl.DrawRectangleLinesEx(rl.Rectangle{f32(cx), f32(cy), f32(cw), f32(ch)},
                             2, rl.Color{120, 80, 200, u8(200 * alpha)})

    // Message
    msg_str := string(cs.msg[:cs.msg_len])
    msg_cstr := strings.clone_to_cstring(msg_str, context.temp_allocator)
    tw := rl.MeasureText(msg_cstr, UI_FSIZE)
    rl.DrawText(msg_cstr, cx + (cw - tw)/2, cy + 20, UI_FSIZE,
                rl.Color{220, 220, 230, u8(255 * alpha)})

    // Animated dots
    dot_count := int(cs.dot_t * 2.0) % 4
    dot_buf: [8]u8
    for i in 0..<dot_count { dot_buf[i] = '.' }
    dots_cstr := cstring(raw_data(dot_buf[:]))
    dot_buf[dot_count] = 0
    rl.DrawText(dots_cstr, cx + cw/2 - 10, cy + 60, UI_HSIZE,
                rl.Color{120, 80, 200, u8(200 * alpha)})

    return true
}

/*
 * saveload.odin — Binary save/load (M7).
 *
 * Format:
 *   [4]  magic   "DMLS"
 *   [4]  version u32le = 1
 *   [8]  seed    u64le
 *   [8]  tick    u64le
 *   [4]  char_count u32le
 *   [N]  Character records (fixed struct, little-endian)
 *   [4]  rng_state_hi u32le  (upper 32 bits of DependentRNG.state)
 *   [4]  rng_state_lo u32le
 *   [4]  rng_seq_hi   u32le
 *   [4]  rng_seq_lo   u32le
 *   [4]  fact_count   u32le
 *   [N]  fact strings — each: [2] u16le length, then UTF-8 bytes (no null)
 *   [4]  event_count  u32le
 *   [N]  event entries — each: [8] tick u64le, [2] u16le length, bytes
 *   [4]  crc32   (over all bytes before this field)
 *
 * All integers little-endian. Structs written field-by-field to avoid
 * alignment padding surprises.
 */

package dmls

import "core:os"
import "core:fmt"

SAVE_MAGIC   :: "DMLS"
SAVE_VERSION :: u32(1)

// ---- CRC-32 (IEEE 802.3) ---------------------------------------------------

_crc32_table: [256]u32
_crc32_init  : bool

_crc32_make_table :: proc() {
    for i in 0..<256 {
        crc := u32(i)
        for _ in 0..<8 {
            if crc & 1 != 0 {
                crc = (crc >> 1) ~ 0xEDB88320
            } else {
                crc >>= 1
            }
        }
        _crc32_table[i] = crc
    }
}

_crc32_update :: proc(crc: u32, data: []u8) -> u32 {
    if !_crc32_init {
        _crc32_make_table()
        _crc32_init = true
    }
    c := crc ~ 0xFFFFFFFF
    for b in data {
        c = _crc32_table[(c ~ u32(b)) & 0xFF] ~ (c >> 8)
    }
    return c ~ 0xFFFFFFFF
}

crc32 :: proc(data: []u8) -> u32 {
    return _crc32_update(0, data)
}

// ---- Writer ----------------------------------------------------------------

SaveWriter :: struct {
    buf : [dynamic]u8,
}

_sw_u8 :: proc(w: ^SaveWriter, v: u8) {
    append(&w.buf, v)
}

_sw_u16 :: proc(w: ^SaveWriter, v: u16) {
    append(&w.buf, u8(v & 0xFF), u8(v >> 8))
}

_sw_u32 :: proc(w: ^SaveWriter, v: u32) {
    append(&w.buf, u8(v), u8(v >> 8), u8(v >> 16), u8(v >> 24))
}

_sw_u64 :: proc(w: ^SaveWriter, v: u64) {
    _sw_u32(w, u32(v & 0xFFFFFFFF))
    _sw_u32(w, u32(v >> 32))
}

_sw_bytes :: proc(w: ^SaveWriter, b: []u8) {
    for x in b { append(&w.buf, x) }
}

_sw_string :: proc(w: ^SaveWriter, s: string) {
    _sw_u16(w, u16(len(s)))
    _sw_bytes(w, transmute([]u8)s)
}

// ---- Reader ----------------------------------------------------------------

SaveReader :: struct {
    data : []u8,
    pos  : int,
    ok   : bool,
}

_sr_u8 :: proc(r: ^SaveReader) -> u8 {
    if !r.ok || r.pos >= len(r.data) { r.ok = false; return 0 }
    v := r.data[r.pos]; r.pos += 1; return v
}

_sr_u16 :: proc(r: ^SaveReader) -> u16 {
    lo := u16(_sr_u8(r))
    hi := u16(_sr_u8(r))
    return lo | (hi << 8)
}

_sr_u32 :: proc(r: ^SaveReader) -> u32 {
    lo := u32(_sr_u16(r))
    hi := u32(_sr_u16(r))
    return lo | (hi << 16)
}

_sr_u64 :: proc(r: ^SaveReader) -> u64 {
    lo := u64(_sr_u32(r))
    hi := u64(_sr_u32(r))
    return lo | (hi << 32)
}

_sr_string :: proc(r: ^SaveReader, buf: []u8) -> string {
    n := int(_sr_u16(r))
    if !r.ok || r.pos + n > len(r.data) || n > len(buf) { r.ok = false; return "" }
    copy(buf[:n], r.data[r.pos:r.pos+n])
    r.pos += n
    return string(buf[:n])
}

// ---- Fact dump query -------------------------------------------------------

_FactDumpAccum :: struct {
    writer : ^SaveWriter,
    count  : ^u32,
}

_fact_dump_cb :: proc "c" (soln: ^EpilogSolution, ud: rawptr) -> EpilogSignal {
    // We can't call context-requiring procs here.
    // Accumulate into the SaveWriter (rawptr-accessible).
    _ = soln; _ = ud
    return .EPILOG_STOP   // facts are serialised separately via epilog_load_string round-trip
}

// Epilog doesn't expose a "dump all facts" API, so we enumerate known
// predicates and query them to reconstruct assertable strings.
// We serialise only the base facts (not derived rules — those are re-loaded at startup).

_dump_facts :: proc(w: ^SaveWriter, res: ^Residents, engine: ^EpilogEngine) -> u32 {
    count := u32(0)
    buf_a, buf_b, buf_src: [256]u8

    for i in 0..<res.count {
        c    := &res.chars[i]
        atom := character_atom(c.id, buf_a[:])

        // character/2
        fs := fmt.bprintf(buf_src[:], "character(%s, %s)", atom, personality_atom(c.personality))
        _sw_string(w, string(buf_src[:len(fs)]))
        count += 1

        // gender/2
        gender_str: cstring
        switch c.gender {
        case .Male:      gender_str = "male"
        case .Female:    gender_str = "female"
        case .Nonbinary: gender_str = "nonbinary"
        }
        fs = fmt.bprintf(buf_src[:], "gender(%s, %s)", atom, gender_str)
        _sw_string(w, string(buf_src[:len(fs)]))
        count += 1

        // dating_pref/2
        fs = fmt.bprintf(buf_src[:], "dating_pref(%s, %s)", atom, dating_pref_atom(c.dating_pref))
        _sw_string(w, string(buf_src[:len(fs)]))
        count += 1

        // relationships
        for j in 0..<res.count {
            other := &res.chars[j]
            if other.id == c.id do continue
            tag := res.rel[i][j]
            if tag == .Stranger do continue
            atom_b := character_atom(other.id, buf_b[:])
            fs = fmt.bprintf(buf_src[:], "relationship(%s, %s, %s)", atom, atom_b, relationship_atom(tag))
            _sw_string(w, string(buf_src[:len(fs)]))
            count += 1
        }
    }

    return count
}

// ---- Save ------------------------------------------------------------------

save_game :: proc(
    path      : string,
    world     : ^World,
    residents : ^Residents,
    sim       : ^SimState,
    engine    : ^EpilogEngine,
) -> bool {
    w := SaveWriter{buf = make([dynamic]u8, 0, 4096)}
    defer delete(w.buf)

    // Magic + version
    _sw_bytes(&w, transmute([]u8)string(SAVE_MAGIC))
    _sw_u32(&w, SAVE_VERSION)

    // World state
    _sw_u64(&w, world.seed)
    _sw_u64(&w, world.tick)

    // Characters
    _sw_u32(&w, u32(residents.count))
    for i in 0..<residents.count {
        c := &residents.chars[i]
        _sw_u32(&w, c.id)
        _sw_bytes(&w, c.name[:])
        _sw_bytes(&w, c.nickname[:])
        _sw_u8(&w, c.age)
        _sw_u8(&w, u8(c.gender))
        _sw_u8(&w, u8(c.dating_pref))
        _sw_u8(&w, u8(c.personality))
        _sw_u8(&w, u8(c.pronouns))
        _sw_u8(&w, 0)  // pad to align next field
        _sw_u32(&w, u32(c.position[0]))
        _sw_u32(&w, u32(c.position[1]))
        _sw_u32(&w, c.sprite)
    }

    // RNG state
    _sw_u32(&w, u32(sim.rng.state >> 32))
    _sw_u32(&w, u32(sim.rng.state & 0xFFFFFFFF))
    _sw_u32(&w, u32(sim.rng.seq >> 32))
    _sw_u32(&w, u32(sim.rng.seq & 0xFFFFFFFF))

    // Facts — write a placeholder count, then fill it in
    fact_count_pos := len(w.buf)
    _sw_u32(&w, 0)
    fact_count := _dump_facts(&w, residents, engine)
    // Patch count
    w.buf[fact_count_pos+0] = u8(fact_count)
    w.buf[fact_count_pos+1] = u8(fact_count >> 8)
    w.buf[fact_count_pos+2] = u8(fact_count >> 16)
    w.buf[fact_count_pos+3] = u8(fact_count >> 24)

    // Event log
    evt_count := u32(sim.log.count)
    _sw_u32(&w, evt_count)
    for i in 0..<int(evt_count) {
        e := event_log_get(&sim.log, i)
        if e == nil do continue
        _sw_u64(&w, e.tick)
        _sw_string(&w, event_entry_str(e))
    }

    // CRC32
    checksum := crc32(w.buf[:])
    _sw_u32(&w, checksum)

    err := os.write_entire_file_from_bytes(path, w.buf[:])
    return err == nil
}

// ---- Load ------------------------------------------------------------------

load_game :: proc(
    path      : string,
    world     : ^World,
    residents : ^Residents,
    sim       : ^SimState,
    engine    : ^EpilogEngine,
) -> bool {
    data, err := os.read_entire_file_from_path(path, context.allocator)
    if err != nil do return false
    defer delete(data)

    if len(data) < 8 do return false

    // Verify CRC (last 4 bytes)
    payload  := data[:len(data)-4]
    stored_crc := u32(data[len(data)-4]) |
                  u32(data[len(data)-3]) << 8 |
                  u32(data[len(data)-2]) << 16 |
                  u32(data[len(data)-1]) << 24
    if crc32(payload) != stored_crc do return false

    r := SaveReader{data = payload, pos = 0, ok = true}

    // Magic
    magic: [4]u8
    for i in 0..<4 { magic[i] = _sr_u8(&r) }
    if string(magic[:]) != SAVE_MAGIC do return false

    // Version
    ver := _sr_u32(&r)
    if ver != SAVE_VERSION do return false

    // World
    seed := _sr_u64(&r)
    tick := _sr_u64(&r)

    // Characters
    char_count := _sr_u32(&r)
    if char_count > MAX_RESIDENTS do return false

    residents^ = {}
    residents_init(residents)

    for i in 0..<char_count {
        c: Character
        c.id          = _sr_u32(&r)
        for j in 0..<MAX_NAME_LEN { c.name[j]     = _sr_u8(&r) }
        for j in 0..<MAX_NAME_LEN { c.nickname[j] = _sr_u8(&r) }
        c.age         = _sr_u8(&r)
        c.gender      = Gender(_sr_u8(&r))
        c.dating_pref = DatingPref(_sr_u8(&r))
        c.personality = Personality(_sr_u8(&r))
        c.pronouns    = Pronouns(_sr_u8(&r))
        _sr_u8(&r)    // pad
        c.position[0] = i32(_sr_u32(&r))
        c.position[1] = i32(_sr_u32(&r))
        c.sprite      = _sr_u32(&r)

        if !r.ok do return false

        // Insert preserving saved IDs
        idx := residents.count
        residents.chars[idx] = c
        residents.count += 1
        if c.id >= residents.next_id { residents.next_id = c.id + 1 }
    }

    // RNG
    rng_sh := u64(_sr_u32(&r))
    rng_sl := u64(_sr_u32(&r))
    rng_qh := u64(_sr_u32(&r))
    rng_ql := u64(_sr_u32(&r))
    sim.rng.state = (rng_sh << 32) | rng_sl
    sim.rng.seq   = (rng_qh << 32) | rng_ql

    // Re-init world from seed (regenerates grid deterministically)
    world_init(world, seed)
    world.tick = tick

    // Re-place characters on the grid
    for i in 0..<residents.count {
        c := &residents.chars[i]
        grid_place_character(&world.grid, c.id, c.position[0], c.position[1])
        idx := int(c.id - 1)
        if idx < MAX_RESIDENTS {
            world.positions[idx] = c.position
        }
    }

    // Facts
    fact_count := _sr_u32(&r)
    fact_buf: [512]u8
    for _ in 0..<fact_count {
        s := _sr_string(&r, fact_buf[:])
        if !r.ok do return false
        // Re-assert: append "." and load
        full_buf: [520]u8
        fs := fmt.bprintf(full_buf[:], "%s.", s)
        full_buf[len(fs)] = 0
        epilog_load_string(engine, cstring(raw_data(full_buf[:])))
    }

    // Events
    evt_count := _sr_u32(&r)
    sim.log = {}
    evt_str_buf: [EVENT_MSG_LEN]u8
    for _ in 0..<evt_count {
        tick_e := _sr_u64(&r)
        msg    := _sr_string(&r, evt_str_buf[:])
        if !r.ok do break
        event_log_push(&sim.log, tick_e, msg)
    }

    return r.ok
}

/*
 * title.odin — Title screen + island naming (M8).
 *
 * Screens before World_Setup:
 *   .Title        — animated title card, "New Game" / "Load Game" buttons
 *   .Island_Name  — text field for naming the island
 *
 * Title animation: pulsing accent colour on the logo, floating particles.
 */

package dmls

import rl "vendor:raylib"
import "core:fmt"
import "core:math"

// ---- Island name -----------------------------------------------------------

ISLAND_NAME_LEN :: 32

IslandName :: struct {
    buf : [ISLAND_NAME_LEN]u8,
    len : int,
}

island_name_str :: proc(n: ^IslandName) -> string {
    if n.len == 0 do return "Unnamed Island"
    return string(n.buf[:n.len])
}

// ---- Title particles -------------------------------------------------------

TITLE_PARTICLE_COUNT :: 48

TitleParticle :: struct {
    x, y   : f32,
    vx, vy : f32,
    life   : f32,   // 0..1
    size   : f32,
}

TitleScreen :: struct {
    particles   : [TITLE_PARTICLE_COUNT]TitleParticle,
    time        : f32,
    name_field  : InputField,
    load_err    : bool,
    load_err_t  : f32,
    phase       : TitlePhase,
}

TitlePhase :: enum { Logo, Island_Name }

title_screen_init :: proc(t: ^TitleScreen) {
    t^ = {}
    rng := u64(0xDEADBEEF)
    for i in 0..<TITLE_PARTICLE_COUNT {
        rng = rng * 6364136223846793005 + 1442695040888963407
        x := f32((rng >> 33) % u64(SW()))
        rng = rng * 6364136223846793005 + 1442695040888963407
        y := f32((rng >> 33) % u64(SH()))
        rng = rng * 6364136223846793005 + 1442695040888963407
        vx := (f32((rng >> 33) % 100) - 50.0) * 0.003
        rng = rng * 6364136223846793005 + 1442695040888963407
        vy := (f32((rng >> 33) % 100) - 50.0) * 0.003
        rng = rng * 6364136223846793005 + 1442695040888963407
        life := f32((rng >> 33) % 100) / 100.0
        rng = rng * 6364136223846793005 + 1442695040888963407
        size := 1.0 + f32((rng >> 33) % 3)
        t.particles[i] = TitleParticle{x, y, vx, vy, life, size}
    }
}

_update_particles :: proc(t: ^TitleScreen, dt: f32, rng: ^u64) {
    for i in 0..<TITLE_PARTICLE_COUNT {
        p := &t.particles[i]
        p.x    += p.vx
        p.y    += p.vy
        p.life += dt * 0.1
        if p.life > 1.0 {
            p.life = 0
            rng^ = rng^ * 6364136223846793005 + 1442695040888963407
            p.x  = f32((rng^ >> 33) % u64(SW()))
            rng^ = rng^ * 6364136223846793005 + 1442695040888963407
            p.y  = f32((rng^ >> 33) % u64(SH()))
        }
        if p.x < 0 { p.x = f32(SW()) }
        if p.x > f32(SW()) { p.x = 0 }
        if p.y < 0 { p.y = f32(SH()) }
        if p.y > f32(SH()) { p.y = 0 }
    }
}

// Returns:
//   0 = still on title
//   1 = new game  (island name entered)
//   2 = load game (caller tries loading "dmls_save.bin")
title_screen_update :: proc(t: ^TitleScreen, name_out: ^IslandName, rng: ^u64) -> int {
    dt := rl.GetFrameTime()
    t.time += dt
    if t.load_err { t.load_err_t -= dt; if t.load_err_t <= 0 { t.load_err = false } }

    _update_particles(t, dt, rng)

    rl.ClearBackground(COL_BG)

    // Particles
    for i in 0..<TITLE_PARTICLE_COUNT {
        p    := &t.particles[i]
        alpha := u8(40 + 80 * (1 - p.life))
        rl.DrawRectangle(i32(p.x), i32(p.y), i32(p.size), i32(p.size),
                         rl.Color{120, 80, 200, alpha})
    }

    switch t.phase {
    case .Logo:
        return _draw_logo_phase(t)
    case .Island_Name:
        return _draw_name_phase(t, name_out)
    }
    return 0
}

_draw_logo_phase :: proc(t: ^TitleScreen) -> int {
    // Pulsing logo colour
    pulse := f32(0.5 + 0.5 * math.sin_f32(t.time * 2.0))
    r     := u8(80  + 80  * pulse)
    gv    := u8(40  + 40  * pulse)
    b     := u8(180 + 40  * pulse)
    logo_col := rl.Color{r, gv, b, 255}

    rl.DrawText("DMLS", UI_LPAD, SH()/2 - 80, 72, logo_col)
    rl.DrawText("Deb's Minimal Life Simulator",
                UI_LPAD, SH()/2 - 4, UI_FSIZE, COL_MUTED)

    y := SH()/2 + 60

    new_rect := rl.Rectangle{f32(UI_LPAD), f32(y), 220, 46}
    hov_new  := rl.CheckCollisionPointRec(rl.GetMousePosition(), new_rect)
    rl.DrawRectangleRec(new_rect, hov_new ? COL_ACCENT : COL_SELECT)
    rl.DrawRectangleLinesEx(new_rect, 1, COL_ACCENT)
    rl.DrawText("New Game", UI_LPAD + 16, y + 12, UI_FSIZE, COL_TEXT)

    load_rect := rl.Rectangle{f32(UI_LPAD + 240), f32(y), 200, 46}
    hov_load  := rl.CheckCollisionPointRec(rl.GetMousePosition(), load_rect)
    rl.DrawRectangleRec(load_rect, hov_load ? COL_HOVER : COL_INPUT)
    rl.DrawRectangleLinesEx(load_rect, 1, COL_MUTED)
    rl.DrawText("Load Game", UI_LPAD + 256, y + 12, UI_FSIZE, COL_TEXT)

    if t.load_err {
        rl.DrawText("No save file found.", UI_LPAD, y + 54, UI_SMALL, rl.RED)
    }

    if hov_new && rl.IsMouseButtonPressed(.LEFT) {
        t.phase = .Island_Name
    }
    if hov_load && rl.IsMouseButtonPressed(.LEFT) {
        return 2
    }
    return 0
}

_draw_name_phase :: proc(t: ^TitleScreen, name_out: ^IslandName) -> int {
    rl.DrawText("Name your island", UI_LPAD, SH()/2 - 60, UI_HSIZE, COL_TEXT)
    rl.DrawText("This will appear on the stats panel.",
                UI_LPAD, SH()/2 - 28, UI_SMALL, COL_MUTED)

    y := SH()/2 + 10
    input_field_draw(&t.name_field, UI_LPAD, y, 340, 38, "")
    if rl.CheckCollisionPointRec(rl.GetMousePosition(),
            rl.Rectangle{f32(UI_LPAD), f32(y), 340, 38}) &&
            rl.IsMouseButtonPressed(.LEFT) {
        t.name_field.active = true
    }
    input_field_update(&t.name_field)

    confirm_rect := rl.Rectangle{f32(UI_LPAD), f32(y + 54), 200, 42}
    hov_go       := rl.CheckCollisionPointRec(rl.GetMousePosition(), confirm_rect)
    rl.DrawRectangleRec(confirm_rect, hov_go ? COL_ACCENT : COL_SELECT)
    rl.DrawText("Begin ->", UI_LPAD + 14, y + 66, UI_FSIZE, COL_TEXT)

    if (hov_go && rl.IsMouseButtonPressed(.LEFT)) || rl.IsKeyPressed(.ENTER) {
        s := input_field_str(&t.name_field)
        name_out.len = 0
        n := min(len(s), ISLAND_NAME_LEN - 1)
        copy(name_out.buf[:], s[:n])
        name_out.len = n
        return 1
    }
    return 0
}

