/*
 * world.odin — World seed system and character placement / wandering (M3).
 */

package dmls

import "core:fmt"

// ---- World -----------------------------------------------------------------

World :: struct {
    seed        : u64,
    grid        : Grid,
    rng         : u64,              // LCG state for placement/wandering
    tick        : u64,
    // Per-character position cache (mirrors grid occupant)
    positions   : [MAX_RESIDENTS][2]i32,    // [id-1] = {col, row}
}

world_init :: proc(w: ^World, seed: u64) {
    w.seed = seed
    w.rng  = seed
    w.tick = 0
    grid_generate(&w.grid, seed)
}

// Spawn a newly created character onto the grid.
world_spawn_character :: proc(w: ^World, res: ^Residents, id: u32) -> bool {
    c := residents_find(res, id)
    if c == nil do return false

    col, row, ok := grid_find_spawn(&w.grid, &w.rng)
    if !ok do return false

    if !grid_place_character(&w.grid, id, col, row) do return false

    c.position = {col, row}
    idx := id - 1
    if int(idx) < MAX_RESIDENTS {
        w.positions[idx] = {col, row}
    }
    return true
}

// One wander step per character — moves to a random adjacent walkable cell.
world_tick_wander :: proc(w: ^World, res: ^Residents) {
    dx := [4]i32{0, 0, 1, -1}
    dy := [4]i32{1, -1, 0, 0}

    for i in 0..<res.count {
        c   := &res.chars[i]
        col := c.position[0]
        row := c.position[1]

        // Pick a random direction
        w.rng = w.rng * 6364136223846793005 + 1442695040888963407
        dir  := int((w.rng >> 33) % 4)

        nc := col + dx[dir]
        nr := row + dy[dir]

        if grid_move_character(&w.grid, c.id, col, row, nc, nr) {
            c.position = {nc, nr}
            idx := c.id - 1
            if int(idx) < MAX_RESIDENTS {
                w.positions[idx] = {nc, nr}
            }
        }
    }
    w.tick += 1
}

// Format the seed as a hex string for display.
world_seed_string :: proc(w: ^World, buf: []u8) -> cstring {
    s := fmt.bprintf(buf, "%016X", w.seed)
    buf[len(s)] = 0
    return cstring(raw_data(buf))
}

/*
 * grid.odin — 256×256 world grid (M3).
 *
 * Each cell stores a terrain type, occupant character id (0 = empty),
 * and a generic object id (0 = none).
 *
 * Terrain zones and their walkability:
 *   .Water  — impassable
 *   .Beach  — walkable, spawnable
 *   .Grass  — walkable, spawnable
 *   .Town   — walkable, spawnable (preferred spawn)
 *   .Forest — walkable, not spawnable
 */

package dmls

import rl "vendor:raylib"
import "core:math"

GRID_W :: 256
GRID_H :: 256

// Terrain scale: smaller = more zoomed-out noise features.
TERRAIN_SCALE :: 0.035
TERRAIN_OCTAVES :: 5

Terrain :: enum u8 {
    Water,
    Beach,
    Grass,
    Town,
    Forest,
}

Cell :: struct {
    terrain   : Terrain,
    occupant  : u32,    // character id, 0 = empty
    object_id : u32,    // reserved for Phase 8 objects
}

Grid :: struct {
    cells     : [GRID_H][GRID_W]Cell,
    world_seed: u64,
}

// ---- Terrain colour lookup -------------------------------------------------

terrain_color :: proc(t: Terrain) -> rl.Color {
    switch t {
    case .Water:  return rl.Color{30,  80,  160, 255}
    case .Beach:  return rl.Color{210, 190, 130, 255}
    case .Grass:  return rl.Color{60,  140, 60,  255}
    case .Town:   return rl.Color{160, 140, 110, 255}
    case .Forest: return rl.Color{30,  90,  30,  255}
    }
    return rl.Color{0, 0, 0, 255}
}

terrain_walkable :: proc(t: Terrain) -> bool {
    return t != .Water
}

terrain_spawnable :: proc(t: Terrain) -> bool {
    return t == .Grass || t == .Town || t == .Beach
}

// ---- Grid generation -------------------------------------------------------

grid_generate :: proc(g: ^Grid, seed: u64) {
    g.world_seed = seed
    g^ = {}
    g.world_seed = seed

    ns: NoiseState
    noise_init(&ns, seed)

    // Second noise for town/forest layer
    ns2: NoiseState
    noise_init(&ns2, seed ~ 0xdeadbeefcafe1234)

    for row in 0..<GRID_H {
        for col in 0..<GRID_W {
            x := f64(col)
            y := f64(row)

            // Island mask: distance from centre falls off to water at edges
            cx  := f64(GRID_W) / 2.0
            cy  := f64(GRID_H) / 2.0
            dx  := (x - cx) / cx
            dy  := (y - cy) / cy
            dist := math.sqrt(dx*dx + dy*dy)

            // Base elevation from fBm noise
            elevation := fbm(&ns, x * TERRAIN_SCALE, y * TERRAIN_SCALE, TERRAIN_OCTAVES)
            // Clamp to [-1,1] roughly — fBm with 5 octaves goes beyond 1
            elevation = elevation * 0.5

            // Apply island radial mask — edges become water
            elevation -= dist * 1.2

            // Secondary noise for town/forest differentiation
            detail := perlin2(&ns2, x * TERRAIN_SCALE * 2, y * TERRAIN_SCALE * 2)

            terrain: Terrain
            switch {
            case elevation < -0.3:
                terrain = .Water
            case elevation < -0.1:
                terrain = .Beach
            case elevation < 0.25:
                // Grass vs town vs forest based on detail noise
                if detail > 0.3 {
                    terrain = .Town
                } else if detail < -0.3 {
                    terrain = .Forest
                } else {
                    terrain = .Grass
                }
            case:
                terrain = .Forest   // high ground = dense forest
            }

            g.cells[row][col].terrain = terrain
        }
    }
}

// ---- Occupant helpers ------------------------------------------------------

grid_place_character :: proc(g: ^Grid, id: u32, col, row: i32) -> bool {
    if col < 0 || col >= GRID_W || row < 0 || row >= GRID_H do return false
    cell := &g.cells[row][col]
    if cell.occupant != 0 do return false
    if !terrain_walkable(cell.terrain) do return false
    cell.occupant = id
    return true
}

grid_move_character :: proc(g: ^Grid, id: u32, old_col, old_row, new_col, new_row: i32) -> bool {
    if new_col < 0 || new_col >= GRID_W || new_row < 0 || new_row >= GRID_H do return false
    dst := &g.cells[new_row][new_col]
    if dst.occupant != 0 do return false
    if !terrain_walkable(dst.terrain) do return false
    g.cells[old_row][old_col].occupant = 0
    dst.occupant = id
    return true
}

grid_remove_character :: proc(g: ^Grid, col, row: i32) {
    if col >= 0 && col < GRID_W && row >= 0 && row < GRID_H {
        g.cells[row][col].occupant = 0
    }
}

// ---- Spawn: find a random spawnable cell using a simple LCG ----------------

grid_find_spawn :: proc(g: ^Grid, rng: ^u64) -> (col, row: i32, ok: bool) {
    for _ in 0..<512 {
        rng^ = rng^ * 6364136223846793005 + 1442695040888963407
        c := i32((rng^ >> 33) % GRID_W)
        r := i32((rng^ >> 17) % GRID_H)
        cell := &g.cells[r][c]
        if terrain_spawnable(cell.terrain) && cell.occupant == 0 {
            return c, r, true
        }
    }
    return 0, 0, false
}

// ---- Rendering -------------------------------------------------------------

// Render the grid into the current drawing context.
// origin_x/y: top-left pixel of the simulation view.
// view_w/h:   pixel size of the simulation panel.
// cell_px:    pixel size per grid cell (use render_cell_px() from screen_cfg).
grid_render :: proc(g: ^Grid, origin_x, origin_y, view_w, view_h: i32,
                    cam_col, cam_row: i32, cell_px: i32) {
    cpx := max(cell_px, 1)
    visible_cols := view_w  / cpx + 2
    visible_rows := view_h / cpx + 2

    start_col := cam_col - visible_cols / 2
    start_row := cam_row - visible_rows / 2

    for r in 0..<visible_rows {
        for c in 0..<visible_cols {
            gc := start_col + c
            gr := start_row + r
            if gc < 0 || gc >= GRID_W || gr < 0 || gr >= GRID_H do continue

            cell  := &g.cells[gr][gc]
            color := terrain_color(cell.terrain)

            px := origin_x + c * cpx
            py := origin_y + r * cpx
            rl.DrawRectangle(px, py, cpx, cpx, color)

            // Draw occupant dot
            if cell.occupant != 0 {
                dot_x := px + cpx / 2
                dot_y := py + cpx / 2
                rl.DrawPixel(dot_x, dot_y, rl.WHITE)
            }
        }
    }
}

/*
 * residents.odin — Resident list screen (M2).
 */

package dmls

import rl "vendor:raylib"
import "core:fmt"
import "core:strings"

// ---- Relationship query state ----------------------------------------------

MAX_REL_RESULTS :: 64

RelResult :: struct {
    other_id   : u32,
    other_name : string,
    tag        : string,
}

ResidentListScreen :: struct {
    selected_id : u32,
    rel_results : [MAX_REL_RESULTS]RelResult,
    rel_count   : int,
}

// Raw callback data (no context available in "c" procs)
RelQueryAccum :: struct {
    results : ^[MAX_REL_RESULTS]RelResult,
    count   : ^int,
}

_rel_query_cb :: proc "c" (soln: ^EpilogSolution, ud: rawptr) -> EpilogSignal {
    acc := cast(^RelQueryAccum)ud

    other_atom: cstring
    tag_atom  : cstring

    for i in 0..<epilog_soln_var_count(soln) {
        name := epilog_soln_var_name(soln, i)
        val  := epilog_soln_var_atom(soln, i)
        if name == nil || val == nil do continue
        switch string(name) {
        case "Other": other_atom = val
        case "Tag":   tag_atom   = val
        }
    }

    if other_atom != nil && tag_atom != nil && acc.count^ < MAX_REL_RESULTS {
        other_str := string(other_atom)
        other_id  := u32(0)
        if len(other_str) > 5 && other_str[:5] == "char_" {
            for ch in other_str[5:] {
                if ch >= '0' && ch <= '9' {
                    other_id = other_id * 10 + u32(ch - '0')
                }
            }
        }
        idx := acc.count^
        acc.results[idx].other_id   = other_id
        acc.results[idx].other_name = string(other_atom)
        acc.results[idx].tag        = string(tag_atom)
        acc.count^ += 1
    }
    return .EPILOG_NEXT
}

_query_relationships :: proc(
    s      : ^ResidentListScreen,
    id     : u32,
    res    : ^Residents,
    engine : ^EpilogEngine,
) {
    s.rel_count = 0

    buf_id  : [32]u8
    atom    := character_atom(id, buf_id[:])
    buf_goal: [128]u8
    gs := fmt.bprintf(buf_goal[:], "relationship(%s, Other, Tag)", atom)
    buf_goal[len(gs)] = 0

    acc := RelQueryAccum{&s.rel_results, &s.rel_count}
    epilog_query(engine, cstring(raw_data(buf_goal[:])), _rel_query_cb, &acc)

    // Resolve atom names to real character names (needs context, so done here)
    for i in 0..<s.rel_count {
        c := residents_find(res, s.rel_results[i].other_id)
        if c != nil {
            s.rel_results[i].other_name = character_name(c)
        }
    }
}

// Returns true when the player clicks "Add resident".
resident_list_update :: proc(
    s     : ^ResidentListScreen,
    res   : ^Residents,
    engine: ^EpilogEngine,
) -> bool {
    rl.ClearBackground(COL_BG)

    rl.DrawText("Island Residents", UI_LPAD, UI_PAD, UI_HSIZE, COL_TEXT)

    count_buf: [32]u8
    cs := fmt.bprintf(count_buf[:], "%d resident(s)", res.count)
    count_buf[len(cs)] = 0
    rl.DrawText(cstring(raw_data(count_buf[:])), UI_LPAD, UI_PAD + UI_HSIZE + 6, UI_SMALL, COL_MUTED)

    add_rect := rl.Rectangle{f32(SW() - 200), f32(UI_PAD), 180, 36}
    hov_add  := rl.CheckCollisionPointRec(rl.GetMousePosition(), add_rect)
    rl.DrawRectangleRec(add_rect, hov_add ? COL_ACCENT : COL_SELECT)
    rl.DrawText("+ Add resident", SW() - 190, UI_PAD + 8, UI_SMALL, COL_TEXT)
    if hov_add && rl.IsMouseButtonPressed(.LEFT) {
        return true
    }

    list_y := i32(UI_PAD + UI_HSIZE + 40)

    for i in 0..<res.count {
        c    := &res.chars[i]
        row  := rl.Rectangle{f32(UI_LPAD), f32(list_y + i32(i) * 48), 340, 42}
        sel  := c.id == s.selected_id
        hov  := rl.CheckCollisionPointRec(rl.GetMousePosition(), row)
        bg   := sel ? COL_SELECT : (hov ? COL_HOVER : COL_PANEL)
        rl.DrawRectangleRec(row, bg)
        rl.DrawRectangleLinesEx(row, 1, sel ? COL_ACCENT : COL_MUTED)

        hue := f32(c.sprite) / f32(SPRITE_COUNT)
        r   := u8(80 + 100 * (1 - hue))
        g   := u8(80 + 100 * hue)
        b   := u8(180 - 80 * hue)
        rl.DrawRectangle(i32(row.x) + 6, i32(row.y) + 9, 24, 24, rl.Color{r, g, b, 200})

        name_cstr := strings.clone_to_cstring(character_name(c), context.temp_allocator)
        rl.DrawText(name_cstr, i32(row.x) + 38, i32(row.y) + 6, UI_FSIZE, COL_TEXT)

        pers_cstr := strings.clone_to_cstring(personality_label(c.personality), context.temp_allocator)
        rl.DrawText(pers_cstr, i32(row.x) + 38, i32(row.y) + 26, UI_SMALL, COL_MUTED)

        if hov && rl.IsMouseButtonPressed(.LEFT) && c.id != s.selected_id {
            s.selected_id = c.id
            _query_relationships(s, c.id, res, engine)
        }
    }

    if res.count == 0 {
        rl.DrawText("No residents yet. Add the first one!", UI_LPAD + 8, list_y + 14, UI_FSIZE, COL_MUTED)
    }

    // Right panel — relationship detail
    if s.selected_id != 0 {
        rx := i32(UI_LPAD + 360)
        rl.DrawRectangle(rx - 10, list_y - 8, SW() - rx, SH() - list_y, COL_PANEL)

        sel_char := residents_find(res, s.selected_id)
        if sel_char != nil {
            name_cstr := strings.clone_to_cstring(character_name(sel_char), context.temp_allocator)
            rl.DrawText(name_cstr, rx, list_y, UI_HSIZE, COL_TEXT)

            ry := list_y + UI_HSIZE + 10

            pron_cstr := strings.clone_to_cstring(pronouns_label(sel_char.pronouns), context.temp_allocator)
            rl.DrawText(pron_cstr, rx, ry, UI_SMALL, COL_MUTED)
            ry += 22

            pers_cstr := strings.clone_to_cstring(personality_label(sel_char.personality), context.temp_allocator)
            rl.DrawText(pers_cstr, rx, ry, UI_SMALL, COL_MUTED)
            ry += 22

            age_buf: [32]u8
            age_s := fmt.bprintf(age_buf[:], "Age %d", sel_char.age)
            age_buf[len(age_s)] = 0
            rl.DrawText(cstring(raw_data(age_buf[:])), rx, ry, UI_SMALL, COL_MUTED)
            ry += 30

            rl.DrawText("Relationships:", rx, ry, UI_SMALL, COL_TEXT)
            ry += 22

            if s.rel_count == 0 {
                rl.DrawText("none", rx + 8, ry, UI_SMALL, COL_MUTED)
            } else {
                for ri in 0..<s.rel_count {
                    r := &s.rel_results[ri]
                    row_buf: [128]u8
                    nr := fmt.bprintf(row_buf[:], "%s  --  %s", r.other_name, r.tag)
                    row_buf[len(nr)] = 0
                    rl.DrawText(cstring(raw_data(row_buf[:])), rx + 8, ry, UI_SMALL, COL_TEXT)
                    ry += 22
                }
            }
        }
    }

    return false
}

/*
 * creation.odin — Character creation screen (M2).
 *
 * Screen flow:
