// ---- Sprite data (8×8 pixel-art, 2 frames each) ----------------------------
// Each sprite is 2 frames × 8 rows × u8 bitmask (bit7=leftmost pixel).
// Frame 0 = idle/stand, Frame 1 = step (right foot forward).

// Row pixel helpers
_px :: proc(bits: u8, col: int) -> bool { return (bits >> u8(7 - col)) & 1 == 1 }

// Generic humanoid sprite (used for player-created chars 4-7)
_SPRITE_GENERIC := [2][8]u8{
    // frame 0
    {0b00111100, 0b00111100, 0b00011000, 0b00111100, 0b01111110, 0b00100100, 0b01100110, 0b01100110},
    // frame 1
    {0b00111100, 0b00111100, 0b00011000, 0b00111100, 0b01111110, 0b00100100, 0b01001010, 0b01010110},
}

// [NAME]: dark hair, glasses, pink cardigan  (sprite slot 0)
_SPRITE_DEB := [2][8]u8{
    {0b00111100, 0b01111110, 0b01011010, 0b00111100, 0b01111110, 0b00111100, 0b01100110, 0b01100110},
    {0b00111100, 0b01111110, 0b01011010, 0b00111100, 0b01111110, 0b00111100, 0b01001010, 0b01010110},
}

// Uriel: blonde fringe, black top, teal trousers  (sprite slot 1)
_SPRITE_URIEL := [2][8]u8{
    {0b01111110, 0b01111110, 0b00011000, 0b00111100, 0b01111110, 0b00111100, 0b01111110, 0b00100100},
    {0b01111110, 0b01111110, 0b00011000, 0b00111100, 0b01111110, 0b00111100, 0b01011010, 0b00110100},
}

// Anna Croft: blonde, red eyes, orange top  (sprite slot 2)
_SPRITE_ANNA := [2][8]u8{
    {0b01111110, 0b01111110, 0b01011010, 0b00111100, 0b01111110, 0b01111110, 0b01100110, 0b00100100},
    {0b01111110, 0b01111110, 0b01011010, 0b00111100, 0b01111110, 0b01111110, 0b01010110, 0b01000100},
}

// Saloni: brown hair, glasses, peach top  (sprite slot 3)
_SPRITE_SALONI := [2][8]u8{
    {0b00111100, 0b01111110, 0b01111110, 0b00111100, 0b01111110, 0b00111100, 0b01100110, 0b00100100},
    {0b00111100, 0b01111110, 0b01111110, 0b00111100, 0b01111110, 0b00111100, 0b01010110, 0b01000100},
}

_sprite_rows :: proc(sprite_idx: u32) -> ^[2][8]u8 {
    switch sprite_idx {
    case 0: return &_SPRITE_DEB
    case 1: return &_SPRITE_URIEL
    case 2: return &_SPRITE_ANNA
    case 3: return &_SPRITE_SALONI
    }
    return &_SPRITE_GENERIC
}

// Draw a character sprite at (px, py), scaled to cell_px.
// frame = 0 (idle) or 1 (step).
// Hair/accent colour is derived from base_col; skin is fixed warm tone.
_draw_sprite :: proc(c: ^Character, px, py: i32, base_col: rl.Color, frame: int, cell_px: i32) {
    rows := _sprite_rows(c.sprite)
    f    := clamp(frame, 0, 1)

    // Scale: sprite is 8×8; cell_px might be 1–8+ px per grid cell.
    // We draw each sprite pixel as max(1, cell_px/4) screen pixels, centred.
    spx := max(i32(1), cell_px / 4)
    off := (cell_px - spx * 8) / 2

    skin := rl.Color{220, 190, 160, 255}

    for row in 0..<8 {
        bits := rows[f][row]
        for col in 0..<8 {
            if !_px(bits, col) do continue
            sx := px + off + i32(col) * spx
            sy := py + off + i32(row) * spx

            // Top 2 rows = hair/head → use base_col (character colour)
            // Row 2 = eyes (white pixels)
            // Rows 3-4 = face/skin
            // Rows 5-6 = torso → slightly darker base_col
            // Row 7 = legs → mixed
            pixel_col := base_col
            switch {
            case row < 2:
                pixel_col = base_col
            case row == 2:
                pixel_col = rl.WHITE
            case row < 5:
                pixel_col = skin
            case row < 7:
                pixel_col = rl.Color{
                    u8(max(0, int(base_col.r) - 30)),
                    u8(max(0, int(base_col.g) - 30)),
                    u8(max(0, int(base_col.b) - 30)),
                    255,
                }
            case:
                pixel_col = rl.Color{
                    u8((int(base_col.r) + int(skin.r)) / 2),
                    u8((int(base_col.g) + int(skin.g)) / 2),
                    u8((int(base_col.b) + int(skin.b)) / 2),
                    255,
                }
            }
            rl.DrawRectangle(sx, sy, spx, spx, pixel_col)
        }
    }
}

// Draw a character dot with idle animation applied (for use in sim view).
draw_char_dot_animated :: proc(c: ^Character, px, py: i32, base_col: rl.Color, t: f32, cell_px: i32) {
    dy, bright := idle_anim_sample(c, t)
    apy := py + i32(dy)

    // Determine walk frame: flip every 0.5 s while the character recently moved.
    frame := int(t * 2.0) % 2

    // Apply brightness to base_col for the sprite
    r := u8(min(255, int(f32(base_col.r) * bright)))
    g := u8(min(255, int(f32(base_col.g) * bright)))
    b := u8(min(255, int(f32(base_col.b) * bright)))
    bright_col := rl.Color{r, g, b, 255}

    if cell_px >= 4 {
        _draw_sprite(c, px, apy, bright_col, frame, cell_px)
    } else {
        // Too small for sprites — fall back to coloured dot
        rl.DrawRectangle(px, apy, cell_px, cell_px, bright_col)
    }
}

