// ---- Mood icons above characters -------------------------------------------
// Small pixel icons that pulse gently (scale 1.0→1.15→1.0 over 1 second).
// Drawn above the character sprite in the sim view.

// Icon types: heart(pink), flame(orange), star(yellow), drop(blue), swords(red)

_mood_icon_heart :: proc(cx, cy, r: i32, col: rl.Color) {
    // Two overlapping circles + triangle = simple heart
    rl.DrawCircle(cx - r/2, cy,     r/2, col)
    rl.DrawCircle(cx + r/2, cy,     r/2, col)
    rl.DrawTriangle(
        {f32(cx - r), f32(cy)},
        {f32(cx + r), f32(cy)},
        {f32(cx),     f32(cy + r)},
        col,
    )
}

_mood_icon_flame :: proc(cx, cy, r: i32, col: rl.Color) {
    rl.DrawCircle(cx, cy + r/3, r * 2 / 3, col)
    rl.DrawTriangle(
        {f32(cx - r/2), f32(cy + r/3)},
        {f32(cx + r/2), f32(cy + r/3)},
        {f32(cx),       f32(cy - r)},
        col,
    )
}

_mood_icon_star :: proc(cx, cy, r: i32, col: rl.Color) {
    // Approximate star as overlapping rotated squares
    rl.DrawRectangle(cx - r/4, cy - r, r/2, r*2, col)
    rl.DrawRectangle(cx - r,   cy - r/4, r*2, r/2, col)
    rl.DrawLine(cx - r + r/4, cy - r + r/4, cx + r - r/4, cy + r - r/4, col)
    rl.DrawLine(cx + r - r/4, cy - r + r/4, cx - r + r/4, cy + r - r/4, col)
}

_mood_icon_drop :: proc(cx, cy, r: i32, col: rl.Color) {
    rl.DrawCircle(cx, cy + r/3, r * 2 / 3, col)
    rl.DrawTriangle(
        {f32(cx - r/3), f32(cy + r/3)},
        {f32(cx + r/3), f32(cy + r/3)},
        {f32(cx),       f32(cy - r)},
        col,
    )
}

_mood_icon_swords :: proc(cx, cy, r: i32, col: rl.Color) {
    rl.DrawLine(cx - r, cy - r, cx + r, cy + r, col)
    rl.DrawLine(cx + r, cy - r, cx - r, cy + r, col)
}

// Draw a small mood icon above (px, py) with a gentle pulse.
// Returns without drawing if mood is .Content.
draw_mood_icon :: proc(m: Mood, px, py: i32, t: f32, cell_px: i32) {
    if m == .Content do return

    pulse  := 1.0 + 0.15 * math.sin_f32(t * 6.2832)
    r      := i32(max(2, f32(cell_px) * 0.5 * pulse))
    cx     := px + cell_px / 2
    cy     := py - r - 2

    switch m {
    case .Lovestruck:
        _mood_icon_heart(cx, cy, r, rl.Color{255, 100, 160, 220})
    case .Jealous:
        _mood_icon_flame(cx, cy, r, rl.Color{255, 140, 40, 220})
    case .Happy:
        _mood_icon_star(cx, cy, r, rl.Color{255, 230, 60, 220})
    case .Sad:
        _mood_icon_drop(cx, cy, r, rl.Color{80, 150, 255, 220})
    case .Content:
        // nothing
    }
}

