/*
 * anim.odin — Idle animations + relationship cutscene overlay (M8).
 *
 * Idle animations:
 *   Each personality type has a distinct bob/pulse pattern drawn on the
 *   character dot in the sim view. Animations are purely visual — they
 *   don't affect simulation state.
 *
 * Cutscene overlay:
 *   When a social event fires (crush formed, rivals detected), a short
 *   full-screen overlay fades in, shows a one-line message with animated
 *   sprite dots, then fades out. Driven by AnimState.
 */

package dmls

import rl "vendor:raylib"
import "core:math"
import "core:strings"

// ---- Idle animation --------------------------------------------------------
// Returns a y-offset (pixels) for the character dot bob and a brightness
// multiplier [0.7, 1.0] for colour pulsing.

IdleAnim :: struct {
    bob_amp   : f32,   // pixel amplitude of vertical bob
    bob_freq  : f32,   // Hz
    pulse_amp : f32,   // colour pulse amplitude [0, 0.3]
    pulse_freq: f32,   // Hz
}

_idle_anim_for_personality :: proc(p: Personality) -> IdleAnim {
    switch p {
    case .Ambitious_Achiever:
        return IdleAnim{bob_amp = 0.8, bob_freq = 2.4, pulse_amp = 0.15, pulse_freq = 2.0}
    case .Outgoing_Merrymaker:
        return IdleAnim{bob_amp = 1.5, bob_freq = 3.0, pulse_amp = 0.25, pulse_freq = 2.5}
    case .Outgoing_Dynamo:
        return IdleAnim{bob_amp = 1.2, bob_freq = 2.8, pulse_amp = 0.20, pulse_freq = 3.0}
    case .Laid_Back_Guy:
        return IdleAnim{bob_amp = 0.3, bob_freq = 0.8, pulse_amp = 0.05, pulse_freq = 0.5}
    case .Sweetie:
        return IdleAnim{bob_amp = 0.6, bob_freq = 1.6, pulse_amp = 0.20, pulse_freq = 1.2}
    case .Cranky:
        return IdleAnim{bob_amp = 0.4, bob_freq = 1.0, pulse_amp = 0.10, pulse_freq = 4.0}
    }
    return IdleAnim{bob_amp = 0.5, bob_freq = 1.0, pulse_amp = 0.1, pulse_freq = 1.0}
}

// Returns (dy_pixels, brightness) for a character at global time t.
idle_anim_sample :: proc(c: ^Character, t: f32) -> (dy: f32, brightness: f32) {
    a   := _idle_anim_for_personality(c.personality)
    // offset per character so they don't all bob in sync
    phi := f32(c.id) * 0.9
    dy  = a.bob_amp * math.sin_f32(t * a.bob_freq * 6.2832 + phi)
    brightness = 0.85 + a.pulse_amp * math.sin_f32(t * a.pulse_freq * 6.2832 + phi)
    return
}

// ---- Sprite data (8×8 pixel-art, 2 frames each) ----------------------------
// Each sprite is 2 frames × 8 rows × u8 bitmask (bit7=leftmost pixel).
// Frame 0 = idle/stand, Frame 1 = step (right foot forward).

// Row pixel helpers
_px :: proc(bits: u8, col: int) -> bool { return (bits >> u8(7 - col)) & 1 == 1 }

// Generic humanoid sprite (used for player-created chars 4-7)
_SPRITE_GENERIC := [2][8]u8{
    // frame 0
    {0b00111100, 0b00111100, 0b00011000, 0b00111100, 0b01111110, 0b00100100, 0b01100110, 0b01100110},
    // frame 1
    {0b00111100, 0b00111100, 0b00011000, 0b00111100, 0b01111110, 0b00100100, 0b01001010, 0b01010110},
}

// [NAME]: dark hair, glasses, pink cardigan  (sprite slot 0)
_SPRITE_DEB := [2][8]u8{
    {0b00111100, 0b01111110, 0b01011010, 0b00111100, 0b01111110, 0b00111100, 0b01100110, 0b01100110},
    {0b00111100, 0b01111110, 0b01011010, 0b00111100, 0b01111110, 0b00111100, 0b01001010, 0b01010110},
}

// Uriel: blonde fringe, black top, teal trousers  (sprite slot 1)
_SPRITE_URIEL := [2][8]u8{
    {0b01111110, 0b01111110, 0b00011000, 0b00111100, 0b01111110, 0b00111100, 0b01111110, 0b00100100},
    {0b01111110, 0b01111110, 0b00011000, 0b00111100, 0b01111110, 0b00111100, 0b01011010, 0b00110100},
}

// Anna Croft: blonde, red eyes, orange top  (sprite slot 2)
_SPRITE_ANNA := [2][8]u8{
    {0b01111110, 0b01111110, 0b01011010, 0b00111100, 0b01111110, 0b01111110, 0b01100110, 0b00100100},
    {0b01111110, 0b01111110, 0b01011010, 0b00111100, 0b01111110, 0b01111110, 0b01010110, 0b01000100},
}

// Saloni: brown hair, glasses, peach top  (sprite slot 3)
_SPRITE_SALONI := [2][8]u8{
    {0b00111100, 0b01111110, 0b01111110, 0b00111100, 0b01111110, 0b00111100, 0b01100110, 0b00100100},
    {0b00111100, 0b01111110, 0b01111110, 0b00111100, 0b01111110, 0b00111100, 0b01010110, 0b01000100},
}

_sprite_rows :: proc(sprite_idx: u32) -> ^[2][8]u8 {
    switch sprite_idx {
    case 0: return &_SPRITE_DEB
    case 1: return &_SPRITE_URIEL
    case 2: return &_SPRITE_ANNA
    case 3: return &_SPRITE_SALONI
    }
    return &_SPRITE_GENERIC
}

// Draw a character sprite at (px, py), scaled to cell_px.
// frame = 0 (idle) or 1 (step).
// Hair/accent colour is derived from base_col; skin is fixed warm tone.
_draw_sprite :: proc(c: ^Character, px, py: i32, base_col: rl.Color, frame: int, cell_px: i32) {
    rows := _sprite_rows(c.sprite)
    f    := clamp(frame, 0, 1)

    // Scale: sprite is 8×8; cell_px might be 1–8+ px per grid cell.
    // We draw each sprite pixel as max(1, cell_px/4) screen pixels, centred.
    spx := max(i32(1), cell_px / 4)
    off := (cell_px - spx * 8) / 2

    skin := rl.Color{220, 190, 160, 255}

    for row in 0..<8 {
        bits := rows[f][row]
        for col in 0..<8 {
            if !_px(bits, col) do continue
            sx := px + off + i32(col) * spx
            sy := py + off + i32(row) * spx

            // Top 2 rows = hair/head → use base_col (character colour)
            // Row 2 = eyes (white pixels)
            // Rows 3-4 = face/skin
            // Rows 5-6 = torso → slightly darker base_col
            // Row 7 = legs → mixed
            pixel_col := base_col
            switch {
            case row < 2:
                pixel_col = base_col
            case row == 2:
                pixel_col = rl.WHITE
            case row < 5:
                pixel_col = skin
            case row < 7:
                pixel_col = rl.Color{
                    u8(max(0, int(base_col.r) - 30)),
                    u8(max(0, int(base_col.g) - 30)),
                    u8(max(0, int(base_col.b) - 30)),
                    255,
                }
            case:
                pixel_col = rl.Color{
                    u8((int(base_col.r) + int(skin.r)) / 2),
                    u8((int(base_col.g) + int(skin.g)) / 2),
                    u8((int(base_col.b) + int(skin.b)) / 2),
                    255,
                }
            }
            rl.DrawRectangle(sx, sy, spx, spx, pixel_col)
        }
    }
}

// Draw a character dot with idle animation applied (for use in sim view).
draw_char_dot_animated :: proc(c: ^Character, px, py: i32, base_col: rl.Color, t: f32, cell_px: i32) {
    dy, bright := idle_anim_sample(c, t)
    apy := py + i32(dy)

    // Determine walk frame: flip every 0.5 s while the character recently moved.
    frame := int(t * 2.0) % 2

    // Apply brightness to base_col for the sprite
    r := u8(min(255, int(f32(base_col.r) * bright)))
    g := u8(min(255, int(f32(base_col.g) * bright)))
    b := u8(min(255, int(f32(base_col.b) * bright)))
    bright_col := rl.Color{r, g, b, 255}

    if cell_px >= 4 {
        _draw_sprite(c, px, apy, bright_col, frame, cell_px)
    } else {
        // Too small for sprites — fall back to coloured dot
        rl.DrawRectangle(px, apy, cell_px, cell_px, bright_col)
    }
}

// ---- Cutscene overlay -------------------------------------------------------

CUTSCENE_FADE_IN  :: 0.35   // seconds
CUTSCENE_HOLD     :: 2.2    // seconds
CUTSCENE_FADE_OUT :: 0.45   // seconds
CUTSCENE_TOTAL    :: CUTSCENE_FADE_IN + CUTSCENE_HOLD + CUTSCENE_FADE_OUT

CutsceneState :: struct {
    active   : bool,
    timer    : f32,
    msg      : [EVENT_MSG_LEN]u8,
    msg_len  : int,
    dot_t    : f32,   // rolling dot animation timer
}

cutscene_trigger :: proc(cs: ^CutsceneState, msg: string) {
    cs.active  = true
    cs.timer   = 0
    cs.dot_t   = 0
    n := min(len(msg), EVENT_MSG_LEN - 1)
    copy(cs.msg[:], msg[:n])
    cs.msg[n] = 0
    cs.msg_len = n
}

// Returns true while the cutscene is still running.
cutscene_update :: proc(cs: ^CutsceneState) -> bool {
    if !cs.active do return false

    dt       := rl.GetFrameTime()
    cs.timer += dt
    cs.dot_t += dt

    if cs.timer > CUTSCENE_TOTAL {
        cs.active = false
        return false
    }

    // Alpha
    alpha := f32(0)
    if cs.timer < CUTSCENE_FADE_IN {
        alpha = cs.timer / CUTSCENE_FADE_IN
    } else if cs.timer < CUTSCENE_FADE_IN + CUTSCENE_HOLD {
        alpha = 1.0
    } else {
        alpha = 1.0 - (cs.timer - CUTSCENE_FADE_IN - CUTSCENE_HOLD) / CUTSCENE_FADE_OUT
    }
    if alpha < 0 { alpha = 0 }
    if alpha > 1 { alpha = 1 }

    // Background overlay
    rl.DrawRectangle(0, 0, SW(), SH(),
                     rl.Color{10, 10, 18, u8(200 * alpha)})

    // Card
    cw := i32(560)
    ch := i32(100)
    cx := (SW() - cw) / 2
    cy := (SH() - ch) / 2
    rl.DrawRectangle(cx, cy, cw, ch, rl.Color{28, 28, 48, u8(230 * alpha)})
    rl.DrawRectangleLinesEx(rl.Rectangle{f32(cx), f32(cy), f32(cw), f32(ch)},
                             2, rl.Color{120, 80, 200, u8(200 * alpha)})

    // Message
    msg_str := string(cs.msg[:cs.msg_len])
    msg_cstr := strings.clone_to_cstring(msg_str, context.temp_allocator)
    tw := rl.MeasureText(msg_cstr, UI_FSIZE)
    rl.DrawText(msg_cstr, cx + (cw - tw)/2, cy + 20, UI_FSIZE,
                rl.Color{220, 220, 230, u8(255 * alpha)})

    // Animated dots
    dot_count := int(cs.dot_t * 2.0) % 4
    dot_buf: [8]u8
    for i in 0..<dot_count { dot_buf[i] = '.' }
    dots_cstr := cstring(raw_data(dot_buf[:]))
    dot_buf[dot_count] = 0
    rl.DrawText(dots_cstr, cx + cw/2 - 10, cy + 60, UI_HSIZE,
                rl.Color{120, 80, 200, u8(200 * alpha)})

    return true
}

