/*
 * grid.odin — 256×256 world grid (M3).
 *
 * Each cell stores a terrain type, occupant character id (0 = empty),
 * and a generic object id (0 = none).
 *
 * Terrain zones and their walkability:
 *   .Water  — impassable
 *   .Beach  — walkable, spawnable
 *   .Grass  — walkable, spawnable
 *   .Town   — walkable, spawnable (preferred spawn)
 *   .Forest — walkable, not spawnable
 */

package dmls

import rl "vendor:raylib"
import "core:math"

GRID_W :: 256
GRID_H :: 256

// Terrain scale: smaller = more zoomed-out noise features.
TERRAIN_SCALE :: 0.035
TERRAIN_OCTAVES :: 5

Terrain :: enum u8 {
    Water,
    Beach,
    Grass,
    Town,
    Forest,
}

Cell :: struct {
    terrain   : Terrain,
    occupant  : u32,    // character id, 0 = empty
    object_id : u32,    // reserved for Phase 8 objects
}

Grid :: struct {
    cells     : [GRID_H][GRID_W]Cell,
    world_seed: u64,
}

// ---- Terrain colour lookup -------------------------------------------------

terrain_color :: proc(t: Terrain) -> rl.Color {
    switch t {
    case .Water:  return rl.Color{30,  80,  160, 255}
    case .Beach:  return rl.Color{210, 190, 130, 255}
    case .Grass:  return rl.Color{60,  140, 60,  255}
    case .Town:   return rl.Color{160, 140, 110, 255}
    case .Forest: return rl.Color{30,  90,  30,  255}
    }
    return rl.Color{0, 0, 0, 255}
}

terrain_walkable :: proc(t: Terrain) -> bool {
    return t != .Water
}

terrain_spawnable :: proc(t: Terrain) -> bool {
    return t == .Grass || t == .Town || t == .Beach
}

// ---- Grid generation -------------------------------------------------------

grid_generate :: proc(g: ^Grid, seed: u64) {
    g.world_seed = seed
    g^ = {}
    g.world_seed = seed

    ns: NoiseState
    noise_init(&ns, seed)

    // Second noise for town/forest layer
    ns2: NoiseState
    noise_init(&ns2, seed ~ 0xdeadbeefcafe1234)

    for row in 0..<GRID_H {
        for col in 0..<GRID_W {
            x := f64(col)
            y := f64(row)

            // Island mask: distance from centre falls off to water at edges
            cx  := f64(GRID_W) / 2.0
            cy  := f64(GRID_H) / 2.0
            dx  := (x - cx) / cx
            dy  := (y - cy) / cy
            dist := math.sqrt(dx*dx + dy*dy)

            // Base elevation from fBm noise
            elevation := fbm(&ns, x * TERRAIN_SCALE, y * TERRAIN_SCALE, TERRAIN_OCTAVES)
            // Clamp to [-1,1] roughly — fBm with 5 octaves goes beyond 1
            elevation = elevation * 0.5

            // Apply island radial mask — edges become water
            elevation -= dist * 1.2

            // Secondary noise for town/forest differentiation
            detail := perlin2(&ns2, x * TERRAIN_SCALE * 2, y * TERRAIN_SCALE * 2)

            terrain: Terrain
            switch {
            case elevation < -0.3:
                terrain = .Water
            case elevation < -0.1:
                terrain = .Beach
            case elevation < 0.25:
                // Grass vs town vs forest based on detail noise
                if detail > 0.3 {
                    terrain = .Town
                } else if detail < -0.3 {
                    terrain = .Forest
                } else {
                    terrain = .Grass
                }
            case:
                terrain = .Forest   // high ground = dense forest
            }

            g.cells[row][col].terrain = terrain
        }
    }
}

// ---- Occupant helpers ------------------------------------------------------

grid_place_character :: proc(g: ^Grid, id: u32, col, row: i32) -> bool {
    if col < 0 || col >= GRID_W || row < 0 || row >= GRID_H do return false
    cell := &g.cells[row][col]
    if cell.occupant != 0 do return false
    if !terrain_walkable(cell.terrain) do return false
    cell.occupant = id
    return true
}

grid_move_character :: proc(g: ^Grid, id: u32, old_col, old_row, new_col, new_row: i32) -> bool {
    if new_col < 0 || new_col >= GRID_W || new_row < 0 || new_row >= GRID_H do return false
    dst := &g.cells[new_row][new_col]
    if dst.occupant != 0 do return false
    if !terrain_walkable(dst.terrain) do return false
    g.cells[old_row][old_col].occupant = 0
    dst.occupant = id
    return true
}

grid_remove_character :: proc(g: ^Grid, col, row: i32) {
    if col >= 0 && col < GRID_W && row >= 0 && row < GRID_H {
        g.cells[row][col].occupant = 0
    }
}

// ---- Spawn: find a random spawnable cell using a simple LCG ----------------

grid_find_spawn :: proc(g: ^Grid, rng: ^u64) -> (col, row: i32, ok: bool) {
    for _ in 0..<512 {
        rng^ = rng^ * 6364136223846793005 + 1442695040888963407
        c := i32((rng^ >> 33) % GRID_W)
        r := i32((rng^ >> 17) % GRID_H)
        cell := &g.cells[r][c]
        if terrain_spawnable(cell.terrain) && cell.occupant == 0 {
            return c, r, true
        }
    }
    return 0, 0, false
}

// ---- Rendering -------------------------------------------------------------

// Render the grid into the current drawing context.
// origin_x/y: top-left pixel of the simulation view.
// view_w/h:   pixel size of the simulation panel.
// cell_px:    pixel size per grid cell (use render_cell_px() from screen_cfg).
grid_render :: proc(g: ^Grid, origin_x, origin_y, view_w, view_h: i32,
                    cam_col, cam_row: i32, cell_px: i32) {
    cpx := max(cell_px, 1)
    visible_cols := view_w  / cpx + 2
    visible_rows := view_h / cpx + 2

    start_col := cam_col - visible_cols / 2
    start_row := cam_row - visible_rows / 2

    for r in 0..<visible_rows {
        for c in 0..<visible_cols {
            gc := start_col + c
            gr := start_row + r
            if gc < 0 || gc >= GRID_W || gr < 0 || gr >= GRID_H do continue

            cell  := &g.cells[gr][gc]
            color := terrain_color(cell.terrain)

            px := origin_x + c * cpx
            py := origin_y + r * cpx
            rl.DrawRectangle(px, py, cpx, cpx, color)

            // Draw occupant dot
            if cell.occupant != 0 {
                dot_x := px + cpx / 2
                dot_y := py + cpx / 2
                rl.DrawPixel(dot_x, dot_y, rl.WHITE)
            }
        }
    }
}

