    resolution_picker_init(&app.res_picker)

    // Allocate RenderTextures at maximum possible sizes.
    // sim_tex: widest sim viewport = 80% of 1920 = 1536, tallest = 1080.
    // stat_tex: widest sidebar = 20% of 1920 = 384, tallest = 1080.
    app.sim_tex  = rl.LoadRenderTexture(SCREEN_W * 80 / 100, SCREEN_H)
    app.stat_tex = rl.LoadRenderTexture(SCREEN_W - SCREEN_W * 80 / 100, SCREEN_H)
    app.rt_ready = true
    defer rl.UnloadRenderTexture(app.sim_tex)
    defer rl.UnloadRenderTexture(app.stat_tex)

    title_screen_init(&app.title)

    for !rl.WindowShouldClose() {
        rl.BeginDrawing()
        free_all(context.temp_allocator)

        switch app.screen {

        case .Resolution:
            if resolution_picker_update(&app.res_picker) {
                app.screen = .Title
            }
            // Exit button on resolution picker
            if _draw_exit_btn() || rl.IsKeyPressed(.ESCAPE) {
                rl.CloseWindow()
            }

        case .Title:
            result := title_screen_update(&app.title, &app.island_name, &app.title_rng)
            switch result {
            case 1:
                app.screen = .World_Setup
            case 2:
                if _do_load(app) {
                    app.screen = .Simulation
                } else {
                    app.title.load_err   = true
                    app.title.load_err_t = 3.0
                }
            }
            // Exit button on title screen
            if _draw_exit_btn() || rl.IsKeyPressed(.ESCAPE) {
                rl.CloseWindow()
            }

        case .World_Setup:
            // Back + exit drawn inside _draw_world_setup
            if _draw_world_setup(app) {
                zone_labels_seed(&app.zone_labels, &app.world.grid)
                starters_seed(&app.residents, &app.world, app.engine)
                sim_init(&app.sim, app.world.seed)
                app.screen = .Residents
            }

        case .Residents:
            if resident_list_update(&app.resident_list, &app.residents, app.engine) {
                creation_screen_init(&app.creation)
                app.screen = .Creation
            }
            // "Simulate ->" button
            sim_rect := rl.Rectangle{f32(SW() - 200), f32(SH() - 60), 180, 42}
            hov_sim  := rl.CheckCollisionPointRec(rl.GetMousePosition(), sim_rect)
            if app.residents.count > 0 {
                rl.DrawRectangleRec(sim_rect, hov_sim ? COL_ACCENT2 : COL_ACCENT)
                rl.DrawText("Simulate ->", SW() - 188, SH() - 46, UI_FSIZE, COL_TEXT)
                if hov_sim && rl.IsMouseButtonPressed(.LEFT) {
                    app.screen = .Simulation
                    _draw_stat_panel(app)
                }
            }
            // Back → World_Setup
            if _draw_back_btn() {
                app.screen = .World_Setup
            }
            if _draw_exit_btn() || rl.IsKeyPressed(.ESCAPE) {
                rl.CloseWindow()
            }

        case .Creation:
            new_char: Character
            if creation_screen_update(&app.creation, &new_char) {
                app.pending_char = new_char
                app.pending_id   = residents_add(&app.residents, new_char)
                epilog_assert_character(app.engine, residents_find(&app.residents, app.pending_id))
                world_spawn_character(&app.world, &app.residents, app.pending_id)
                rel_seeding_init(&app.rel_seeding, app.pending_id, &app.residents)
                app.screen = .Rel_Seeding
            }
            // Back → Residents
            if _draw_back_btn() {
                app.screen = .Residents
            }
            if _draw_exit_btn() || rl.IsKeyPressed(.ESCAPE) {
                rl.CloseWindow()
            }

        case .Rel_Seeding:
            if rel_seeding_update(&app.rel_seeding, &app.residents) {
                rel_seeding_commit(&app.rel_seeding, &app.residents, app.engine)
                app.screen = .Residents
                app.resident_list = {}
            }
            // Back → Residents (discards pending character)
            if _draw_back_btn() {
                app.screen = .Residents
            }
            if _draw_exit_btn() || rl.IsKeyPressed(.ESCAPE) {
                rl.CloseWindow()
            }

        case .Simulation:
            _update_simulation(app)
        }

        rl.EndDrawing()
    }
}

/*
 * world_fx.odin — Visual world effects: terrain labels, day/night cycle,
 *                 weather, and minimap.
 *
 * None of these affect simulation logic — purely cosmetic.
 */

package dmls

import rl    "vendor:raylib"
import "core:fmt"
import "core:math"

// ============================================================
// 2.1 Terrain Zone Labels
// ============================================================
// Zone labels are computed once per grid generation and stored
// as centroid positions. On first load they show for 3 seconds;
// they re-appear while the mouse is near the centroid.

MAX_ZONE_LABELS :: 12

ZoneLabel :: struct {
    x, y    : i32,         // grid coordinates of centroid
    name    : [16]u8,
    timer   : f32,         // seconds remaining to display
}

ZoneLabels :: struct {
    labels : [MAX_ZONE_LABELS]ZoneLabel,
    count  : int,
    seeded : bool,
}

zone_labels_seed :: proc(zl: ^ZoneLabels, g: ^Grid) {
    zl.count  = 0
    zl.seeded = true

    // Walk the grid and track one centroid per terrain type per rough quadrant
    // (quadrant = grid divided into 3×2 blocks for variety)
    QCOLS :: 3
    QROWS :: 2
    QW    :: GRID_W / QCOLS
    QH    :: GRID_H / QROWS

    terrain_names := [Terrain]string{
        .Water  = "",
        .Beach  = "beach",
        .Grass  = "grassland",
        .Town   = "town",
        .Forest = "forest",
    }

    // For each quadrant, find the first non-water centroid cell of each type
    for qr in 0..<QROWS {
        for qc in 0..<QCOLS {
            if zl.count >= MAX_ZONE_LABELS do break
            // Sample the quadrant for the most common non-water terrain
            best_terrain := Terrain.Water
            best_count   := 0
            terrain_sum_x := [Terrain]i32{}
            terrain_sum_y := [Terrain]i32{}
            terrain_cnt   := [Terrain]i32{}

            r_start := qr * QH
            c_start := qc * QW
            for r in r_start..<r_start+QH {
                for c in c_start..<c_start+QW {
                    if r >= GRID_H || c >= GRID_W do continue
                    t := g.cells[r][c].terrain
                    if t == .Water do continue
                    terrain_sum_x[t] += i32(c)
                    terrain_sum_y[t] += i32(r)
                    terrain_cnt[t]   += 1
                    if int(terrain_cnt[t]) > best_count {
                        best_count   = int(terrain_cnt[t])
                        best_terrain = t
                    }
                }
            }
            if best_terrain == .Water || terrain_cnt[best_terrain] == 0 do continue
            n := terrain_names[best_terrain]
            if len(n) == 0 do continue

            cx := terrain_sum_x[best_terrain] / terrain_cnt[best_terrain]
            cy := terrain_sum_y[best_terrain] / terrain_cnt[best_terrain]

            idx := zl.count
            zl.labels[idx].x     = cx
            zl.labels[idx].y     = cy
            zl.labels[idx].timer = 3.0
            nn := min(len(n), 15)
            copy(zl.labels[idx].name[:], n[:nn])
            zl.labels[idx].name[nn] = 0
            zl.count += 1
        }
    }
}

// Call each frame (after grid_render) to draw labels if visible.
zone_labels_draw :: proc(zl: ^ZoneLabels, cam_col, cam_row: i32, dt: f32) {
    mouse := rl.GetMousePosition()
    for i in 0..<zl.count {
        lbl := &zl.labels[i]

        px, py, vis := _grid_to_screen(lbl.x, lbl.y, cam_col, cam_row, sim_w(), sim_h())
        if !vis do continue

        // Hover: reset timer
        near_rect := rl.Rectangle{f32(px) - 40, f32(py) - 20, 120, 40}
        if rl.CheckCollisionPointRec(mouse, near_rect) {
            lbl.timer = 2.0
        }

        if lbl.timer <= 0 do continue
        lbl.timer -= dt

        alpha := u8(clamp(int(lbl.timer * 128), 0, 180))
        name_cstr := cstring(raw_data(lbl.name[:]))
        tw := rl.MeasureText(name_cstr, UI_SMALL - 2)
        rl.DrawText(name_cstr, px - tw/2, py - 12, UI_SMALL - 2,
                    rl.Color{220, 220, 200, alpha})
    }
}

// ============================================================
// 2.2 Day / Night Cycle
// ============================================================
// One full cycle = 100 simulation ticks.
// Purely visual — does not affect logic.

DayPhase :: enum { Dawn, Day, Dusk, Night }

day_phase_for_tick :: proc(tick: u64) -> DayPhase {
    t := int(tick % 100)
    switch {
    case t < 10:  return .Dawn
    case t < 60:  return .Day
    case t < 75:  return .Dusk
    }
    return .Night
}

// Returns the overlay colour (with alpha) for the current tick.
// Call DrawRectangle over the whole sim view after rendering grid+chars.
day_night_overlay :: proc(tick: u64, sub_t: f32) -> rl.Color {
    phase := day_phase_for_tick(tick)
    t     := int(tick % 100)

    switch phase {
    case .Dawn:
        // Warm orange fade in (ticks 0–9)
        a := u8(f32(t) / 10.0 * 80.0)
        return rl.Color{200, 120, 30, a}
    case .Day:
        return rl.Color{0, 0, 0, 0}
    case .Dusk:
        // Purple-pink (ticks 60–74)
        a := u8(f32(t - 60) / 15.0 * 60.0)
        return rl.Color{140, 60, 180, a}
    case .Night:
        // Dark blue (ticks 75–99)
        progress := f32(t - 75) / 25.0
        a := u8(progress * 100 + 40)
        return rl.Color{20, 30, 80, a}
    }
    return rl.Color{0, 0, 0, 0}
}

// Draw stars during night over ocean tiles.  Deterministic from tick/cam.
day_night_draw_stars :: proc(tick: u64, cam_col, cam_row: i32, g: ^Grid) {
    phase := day_phase_for_tick(tick)
    if phase != .Night do return

    // Star seed from world seed to keep positions stable
    star_rng := g.world_seed ~ u64(0xC0FFEEbabe1234)
    for _ in 0..<80 {
        star_rng = star_rng * 6364136223846793005 + 1442695040888963407
        gc := i32((star_rng >> 33) % GRID_W)
        star_rng = star_rng * 6364136223846793005 + 1442695040888963407
        gr := i32((star_rng >> 17) % GRID_H)
        if g.cells[gr][gc].terrain != .Water do continue
        px, py, vis := _grid_to_screen(gc, gr, cam_col, cam_row, sim_w(), sim_h())
        if !vis do continue
        rl.DrawPixel(px, py, rl.Color{255, 255, 240, 180})
    }
}

// ============================================================
// 2.3 Weather System
// ============================================================

Weather :: enum { Clear, Rain, Fog, Wind }

WeatherState :: struct {
    current         : Weather,
    ticks_remaining : int,     // ticks until next change
}

WEATHER_MIN_DURATION :: 50
WEATHER_MAX_DURATION :: 200

weather_init :: proc(ws: ^WeatherState) {
    ws.current         = .Clear
    ws.ticks_remaining = WEATHER_MIN_DURATION + WEATHER_MAX_DURATION / 2
}

weather_tick :: proc(ws: ^WeatherState, rng: ^DependentRNG) {
    ws.ticks_remaining -= 1
    if ws.ticks_remaining <= 0 {
        // Pick a new weather (weighted toward Clear)
        roll := dependent_next(rng)
        switch {
        case roll < 0.50: ws.current = .Clear
        case roll < 0.70: ws.current = .Rain
        case roll < 0.85: ws.current = .Fog
        case:             ws.current = .Wind
        }
        span := f32(WEATHER_MAX_DURATION - WEATHER_MIN_DURATION)
        ws.ticks_remaining = WEATHER_MIN_DURATION + int(f32(dependent_next(rng)) * span)
    }
}

weather_label :: proc(w: Weather) -> string {
    switch w {
    case .Clear: return "Clear"
    case .Rain:  return "Rain"
    case .Fog:   return "Fog"
    case .Wind:  return "Wind"
    }
    return "Clear"
}

// Draw rain effect (blue diagonal streaks over the sim view).
weather_draw_rain :: proc(t: f32, cam_col, cam_row: i32) {
    rng := u64(math.floor_f32(t * 30) * 12345)
    for _ in 0..<60 {
        rng = rng * 6364136223846793005 + 1442695040888963407
        rx := i32((rng >> 33) % u64(sim_w()))
        rng = rng * 6364136223846793005 + 1442695040888963407
        ry := i32((rng >> 17) % u64(sim_h()))
        len := i32(6 + (rng >> 5) % 10)
        rl.DrawLine(rx, ry, rx - len/3, ry + len, rl.Color{80, 140, 220, 100})
    }
}

// Draw fog overlay.
weather_draw_fog :: proc() {
    rl.DrawRectangle(0, 0, sim_w(), sim_h(), rl.Color{200, 210, 220, 50})
}

// Draw wind — animate grass tiles with slight colour flicker.
weather_draw_wind :: proc(t: f32, g: ^Grid, cam_col, cam_row, cpx: i32) {
    wave := math.sin_f32(t * 3.0) * 15
    wave_col := rl.Color{u8(60 + int(wave)), u8(140 + int(wave)/2), u8(60), 255}
    visible_cols := sim_w()  / max(cpx, 1) + 2
    visible_rows := sim_h() / max(cpx, 1) + 2
    start_col := cam_col - visible_cols / 2
    start_row := cam_row - visible_rows / 2
    for r in 0..<visible_rows {
        for c in 0..<visible_cols {
            gc := start_col + c
            gr := start_row + r
            if gc < 0 || gc >= GRID_W || gr < 0 || gr >= GRID_H do continue
            if g.cells[gr][gc].terrain != .Grass do continue
            px := c * cpx
            py := r * cpx
            rl.DrawRectangle(px, py, cpx, cpx, wave_col)
        }
    }
}

// ============================================================
// 2.5 Minimap
// ============================================================
// 64×64 pixel overview drawn into the stat panel.
// Renders terrain + character dots. Refreshes every 5 ticks.

MINIMAP_W :: 64
MINIMAP_H :: 64

minimap_draw :: proc(g: ^Grid, res: ^Residents, x, y: i32) {
    scx := f32(MINIMAP_W) / f32(GRID_W)
    scy := f32(MINIMAP_H) / f32(GRID_H)

    // Terrain
    for gr in 0..<GRID_H {
        for gc in 0..<GRID_W {
            mx := x + i32(f32(gc) * scx)
            my := y + i32(f32(gr) * scy)
            col := terrain_color(g.cells[gr][gc].terrain)
            col.a = 220
            rl.DrawPixel(mx, my, col)
        }
    }

    // Border
    rl.DrawRectangleLinesEx(rl.Rectangle{f32(x), f32(y), MINIMAP_W, MINIMAP_H},
                             1, COL_MUTED)

    // Character dots
    for i in 0..<res.count {
        c  := &res.chars[i]
        mx := x + i32(f32(c.position[0]) * scx)
        my := y + i32(f32(c.position[1]) * scy)
        rl.DrawPixel(mx,     my,     char_palette_color(c.sprite))
        rl.DrawPixel(mx + 1, my,     char_palette_color(c.sprite))
        rl.DrawPixel(mx,     my + 1, char_palette_color(c.sprite))
    }
}

/*
 * landmarks.odin — Fixed landmark placement and rendering (DLC 2.4).
 *
 * Landmarks are placed once at world generation using the world seed.
 * They are stored in Grid.cells[].object_id.
 *
 * | ID | Landmark      | Zone    | Size  |
 * |----|---------------|---------|-------|
 * |  1 | Bench         | Beach   | 2×1   |
 * |  2 | Food stall    | Town    | 2×2   |
 * |  3 | Lookout point | Forest  | 1×1   |
 * |  4 | Tree grove    | Forest  | 3×3   |
 */

package dmls

import rl "vendor:raylib"

// ---- Landmark IDs -----------------------------------------------------------

LANDMARK_NONE    :: u32(0)
LANDMARK_BENCH   :: u32(1)
LANDMARK_FOOD    :: u32(2)
LANDMARK_LOOKOUT :: u32(3)
LANDMARK_GROVE   :: u32(4)

// ---- Landmark colours (drawn over terrain) ----------------------------------

landmark_color :: proc(id: u32) -> rl.Color {
    switch id {
    case LANDMARK_BENCH:   return rl.Color{120, 80,  40,  220}  // brown
    case LANDMARK_FOOD:    return rl.Color{220, 160, 60,  220}  // amber
    case LANDMARK_LOOKOUT: return rl.Color{180, 180, 200, 220}  // pale stone
    case LANDMARK_GROVE:   return rl.Color{30,  110, 30,  220}  // dark green
    }
    return rl.Color{0, 0, 0, 0}
}

// ---- Placement helpers ------------------------------------------------------

_stamp_landmark :: proc(g: ^Grid, id: u32, col, row, w, h: i32) -> bool {
    // Check all cells are on-island and unoccupied by other landmarks
    for dr in 0..<h {
        for dc in 0..<w {
            r := row + dr
            c := col + dc
            if r < 0 || r >= GRID_H || c < 0 || c >= GRID_W do return false
            cell := &g.cells[r][c]
            if !terrain_walkable(cell.terrain) do return false
            if cell.object_id != LANDMARK_NONE do return false
        }
    }
    for dr in 0..<h {
        for dc in 0..<w {
            g.cells[row+dr][col+dc].object_id = id
        }
    }
    return true
}

_try_place :: proc(g: ^Grid, rng: ^u64, id: u32, preferred: Terrain, w, h: i32) {
    for _ in 0..<512 {
        rng^ = rng^ * 6364136223846793005 + 1442695040888963407
        c := i32((rng^ >> 33) % GRID_W)
        rng^ = rng^ * 6364136223846793005 + 1442695040888963407
        r := i32((rng^ >> 17) % GRID_H)
        if g.cells[r][c].terrain == preferred {
            if _stamp_landmark(g, id, c, r, w, h) do return
        }
    }
}

// Place all landmarks. Called once after grid_generate.
landmarks_place :: proc(g: ^Grid, seed: u64) {
    lrng := seed ~ u64(0xDEAD_BEEF_1234)

    // 3 benches on Beach
    for _ in 0..<3 {
        _try_place(g, &lrng, LANDMARK_BENCH, .Beach, 2, 1)
    }
    // 2 food stalls in Town
    for _ in 0..<2 {
        _try_place(g, &lrng, LANDMARK_FOOD, .Town, 2, 2)
    }
    // 2 lookout points in Forest
    for _ in 0..<2 {
        _try_place(g, &lrng, LANDMARK_LOOKOUT, .Forest, 1, 1)
    }
    // 2 tree groves in Forest
    for _ in 0..<2 {
        _try_place(g, &lrng, LANDMARK_GROVE, .Forest, 3, 3)
    }
}

// ---- Rendering -------------------------------------------------------------
// Called inside grid_render after drawing the base terrain tile.
// Draws a coloured overlay for landmark cells.

landmark_render_cell :: proc(cell_object_id: u32, px, py, cpx: i32) {
    if cell_object_id == LANDMARK_NONE do return
    col := landmark_color(cell_object_id)
    rl.DrawRectangle(px, py, cpx, cpx, col)
}

// ---- Mood-based landmark attraction (for sim_tick) -------------------------
// Returns the preferred landmark ID for a given mood.
// Characters gravitate toward this landmark when wandering.

mood_preferred_landmark :: proc(m: Mood) -> u32 {
    switch m {
    case .Lovestruck: return LANDMARK_LOOKOUT
    case .Sad:        return LANDMARK_GROVE
    case .Happy:      return LANDMARK_FOOD
    case .Content:    return LANDMARK_BENCH
    case .Jealous:    return LANDMARK_FOOD
    }
    return LANDMARK_NONE
}

/*
 * sim.odin — Relational simulation tick system (M5).
 *
 * Every simulation tick:
 *   1. Characters near each other accumulate interaction_count in Epilog.
 *   2. Dependent RNG decides if a crush develops.
 *   3. Eligible check (Epilog query) gates crush formation.
 *   4. Mood is re-derived each tick from relationship state.
 *   5. Events are appended to the rolling event log.
 *
 * The Epilog engine is always the source of truth for social state.
 * Odin never caches relationship facts — it queries every tick.
 */

package dmls

import "core:fmt"
import "core:strings"

// ---- Event log -------------------------------------------------------------

MAX_EVENTS   :: 20
EVENT_MSG_LEN :: 96

EventEntry :: struct {
    tick : u64,
    msg  : [EVENT_MSG_LEN]u8,
}

EventLog :: struct {
    entries : [MAX_EVENTS]EventEntry,
    head    : int,   // ring-buffer write index
    count   : int,
}

event_log_push :: proc(log: ^EventLog, tick: u64, msg: string) {
    e := &log.entries[log.head]
    e.tick = tick
    n := min(len(msg), EVENT_MSG_LEN - 1)
    copy(e.msg[:], msg[:n])
    e.msg[n] = 0
    log.head  = (log.head + 1) % MAX_EVENTS
    if log.count < MAX_EVENTS { log.count += 1 }
}

// Iterate from newest to oldest (newest first).
event_log_get :: proc(log: ^EventLog, i: int) -> ^EventEntry {
    if i >= log.count do return nil
    idx := (log.head - 1 - i + MAX_EVENTS * 2) % MAX_EVENTS
    return &log.entries[idx]
}

event_entry_str :: proc(e: ^EventEntry) -> string {
    return strings.truncate_to_byte(string(e.msg[:]), 0)
}

// ---- Mood ------------------------------------------------------------------

Mood :: enum u8 {
    Content,
    Happy,
    Sad,
    Lovestruck,
    Jealous,
}

mood_label :: proc(m: Mood) -> string {
    switch m {
    case .Content:    return "content"
    case .Happy:      return "happy"
    case .Sad:        return "sad"
    case .Lovestruck: return "lovestruck"
    case .Jealous:    return "jealous"
    }
    return "content"
}

// Per-character social state (derived each tick — NOT authoritative, just cache).
CharSocial :: struct {
    mood             : Mood,
    interaction_count: u32,   // total lifetime interactions (also in Epilog)
    has_crush        : bool,
}

// ---- Simulation state ------------------------------------------------------

SimState :: struct {
    rng      : DependentRNG,
    social   : [MAX_RESIDENTS]CharSocial,
    log      : EventLog,
    // Counters displayed in stats panel
    crush_count : int,
    rival_count : int,
}

sim_init :: proc(s: ^SimState, seed: u64) {
    s^ = {}
    dependent_rng_init(&s.rng, seed, 0xC0FFEE_CAFE_1234)
}

// ---- Epilog interaction count helpers --------------------------------------

_assert_interaction :: proc(engine: ^EpilogEngine, id_a, id_b: u32, count: u32) {
    buf_a, buf_b, buf_src: [128]u8
    atom_a := character_atom(id_a, buf_a[:])
    atom_b := character_atom(id_b, buf_b[:])

    // Retract old count first (ignore failure — might not exist)
    rs := fmt.bprintf(buf_src[:], "interaction_count(%s, %s, _)", atom_a, atom_b)
    buf_src[len(rs)] = 0
    // Epilog doesn't have retract in the FFI, so we just re-assert.
    // Because Epilog indexes by first arg, the newer fact shadows the older one
    // for queries. In practice we'll accumulate duplicates but queries still work.
    as := fmt.bprintf(buf_src[:], "interaction_count(%s, %s, %d).", atom_a, atom_b, count)
    buf_src[len(as)] = 0
    epilog_load_string(engine, cstring(raw_data(buf_src[:])))
}

_assert_crush :: proc(engine: ^EpilogEngine, from_id, on_id: u32) {
    buf_a, buf_b, buf_src: [128]u8
    atom_a := character_atom(from_id, buf_a[:])
    atom_b := character_atom(on_id, buf_b[:])
    s := fmt.bprintf(buf_src[:], "crushing(%s, %s).", atom_a, atom_b)
    buf_src[len(s)] = 0
    epilog_load_string(engine, cstring(raw_data(buf_src[:])))
}

_assert_mood :: proc(engine: ^EpilogEngine, id: u32, m: Mood) {
    buf_id, buf_src: [128]u8
    atom := character_atom(id, buf_id[:])
    s := fmt.bprintf(buf_src[:], "mood(%s, %s).", atom, mood_label(m))
    buf_src[len(s)] = 0
    epilog_load_string(engine, cstring(raw_data(buf_src[:])))
}

// ---- Epilog query helpers (callbacks use "c" ABI) --------------------------

_BoolResult :: struct { found: bool }

_bool_cb :: proc "c" (soln: ^EpilogSolution, ud: rawptr) -> EpilogSignal {
    r := cast(^_BoolResult)ud
    r.found = true
    return .EPILOG_STOP
}

_epilog_bool :: proc(engine: ^EpilogEngine, goal: string) -> bool {
    buf: [256]u8
    gs := fmt.bprintf(buf[:], "%s", goal)
    buf[len(gs)] = 0
    r := _BoolResult{false}
    epilog_query(engine, cstring(raw_data(buf[:])), _bool_cb, &r)
    return r.found
}

// Count solutions (up to cap)
_CountResult :: struct { n: int, cap: int }

_count_cb :: proc "c" (soln: ^EpilogSolution, ud: rawptr) -> EpilogSignal {
    r := cast(^_CountResult)ud
    r.n += 1
    if r.n >= r.cap do return .EPILOG_STOP
    return .EPILOG_NEXT
}

_epilog_count :: proc(engine: ^EpilogEngine, goal: string, cap: int) -> int {
    buf: [256]u8
    gs := fmt.bprintf(buf[:], "%s", goal)
    buf[len(gs)] = 0
    r := _CountResult{0, cap}
    epilog_query(engine, cstring(raw_data(buf[:])), _count_cb, &r)
    return r.n
}

// ---- Load M5 Epilog rules --------------------------------------------------

sim_load_rules :: proc(engine: ^EpilogEngine) {
    // Mood derivation rules
    epilog_load_string(engine,
        "mood(X, jealous) :- rivals(X, _).")
    epilog_load_string(engine,
        "mood(X, lovestruck) :- crushing(X, _).")
    epilog_load_string(engine,
        "mood(X, happy) :- best_friends(X, _).")
    epilog_load_string(engine,
        "mood(X, sad) :- relationship(X, _, partner), crushing(_, X).")
    // unrequited: X crushes on Y but Y doesn't crush on X
    epilog_load_string(engine,
        "unrequited(X, Y) :- crushing(X, Y), \\+ crushing(Y, X).")
}

// ---- Proximity check -------------------------------------------------------
// Two characters are "near" if they are within NEAR_DIST grid cells.

NEAR_DIST :: 8

_chars_near :: proc(a, b: ^Character) -> bool {
    dx := a.position[0] - b.position[0]
    dy := a.position[1] - b.position[1]
    if dx < 0 { dx = -dx }
    if dy < 0 { dy = -dy }
    return dx + dy <= NEAR_DIST
}

// ---- Main simulation tick --------------------------------------------------

// Global pointers set by main — nil-safe throughout.
g_decay   : ^FriendshipDecay
g_bubbles : ^BubbleSystem

sim_tick :: proc(s: ^SimState, res: ^Residents, engine: ^EpilogEngine, tick: u64) {
    // 1. Proximity — increment interaction counts
    for i in 0..<res.count {
        for j in i+1..<res.count {
            a := &res.chars[i]
            b := &res.chars[j]
            if _chars_near(a, b) {
                ia := int(a.id - 1)
                ib := int(b.id - 1)
                if ia < MAX_RESIDENTS { s.social[ia].interaction_count += 1 }
                if ib < MAX_RESIDENTS { s.social[ib].interaction_count += 1 }
                cnt_a := s.social[ia].interaction_count
                _assert_interaction(engine, a.id, b.id, cnt_a)
                if g_decay != nil {
                    friendship_decay_record(g_decay, a.id, b.id, tick)
                }
                // Dialogue bubble (low probability to avoid spam)
                if g_bubbles != nil && dependent_next(&s.rng) < 0.05 {
                    rel_tag := "acquaintance"
                    if ia < MAX_RESIDENTS && s.social[ia].has_crush { rel_tag = "crush" }
                    bubble_on_interact(g_bubbles, a, b, rel_tag, &s.rng)
                }

                // 2. Crush development (gate: eligible query + RNG threshold)
                if !s.social[ia].has_crush {
                    chance := 0.003  // ~0.3% per proximity tick per character
                    roll   := dependent_next(&s.rng)
                    if roll < chance {
                        buf_a, buf_b, goal_buf: [128]u8
                        atom_a := character_atom(a.id, buf_a[:])
                        atom_b := character_atom(b.id, buf_b[:])
                        gs := fmt.bprintf(goal_buf[:], "eligible(%s, %s)", atom_a, atom_b)
                        goal_buf[len(gs)] = 0
                        if _epilog_bool(engine, string(goal_buf[:len(gs)])) {
                            _assert_crush(engine, a.id, b.id)
                            s.social[ia].has_crush = true
                            // Event log
                            msg_buf: [EVENT_MSG_LEN]u8
                            name_a := character_name(a)
                            name_b := character_name(b)
                            ms := fmt.bprintf(msg_buf[:], "%s develops a crush on %s", name_a, name_b)
                            event_log_push(&s.log, tick, string(msg_buf[:len(ms)]))
                        }
                    }
                }
            }
        }
    }

    // 3. Re-derive moods and assert them
    for i in 0..<res.count {
        c  := &res.chars[i]
        ia := int(c.id - 1)
        if ia >= MAX_RESIDENTS do continue

        buf_id, goal_buf: [64]u8
        atom := character_atom(c.id, buf_id[:])

        // Check rivals
        gs := fmt.bprintf(goal_buf[:], "rivals(%s, _)", atom)
        goal_buf[len(gs)] = 0
        if _epilog_bool(engine, string(goal_buf[:len(gs)])) {
            s.social[ia].mood = .Jealous
            _assert_mood(engine, c.id, .Jealous)
            continue
        }

        // Check crushing
        gs = fmt.bprintf(goal_buf[:], "crushing(%s, _)", atom)
        goal_buf[len(gs)] = 0
        if _epilog_bool(engine, string(goal_buf[:len(gs)])) {
            s.social[ia].mood = .Lovestruck
            _assert_mood(engine, c.id, .Lovestruck)
            continue
        }

        // Check best_friends
        gs = fmt.bprintf(goal_buf[:], "best_friends(%s, _)", atom)
        goal_buf[len(gs)] = 0
        if _epilog_bool(engine, string(goal_buf[:len(gs)])) {
            s.social[ia].mood = .Happy
            _assert_mood(engine, c.id, .Happy)
            continue
        }

        s.social[ia].mood = .Content
        _assert_mood(engine, c.id, .Content)
    }

    // 4. Update summary counters for stats panel display
    crush_buf, rival_buf: [64]u8
    cs := fmt.bprintf(crush_buf[:], "crushing(_, _)")
    crush_buf[len(cs)] = 0
    rs := fmt.bprintf(rival_buf[:], "rivals(_, _)")
    rival_buf[len(rs)] = 0
    s.crush_count = _epilog_count(engine, string(crush_buf[:len(cs)]), 64)
    s.rival_count = _epilog_count(engine, string(rival_buf[:len(rs)]), 64) / 2  // pairs
}

/*
 * main.odin — DMLS entry point (M0–M8, complete).
 *
 * Screen state machine:
 *   .Resolution   — resolution picker (first screen)
 *   .Title        — animated title card + New/Load buttons
 *   .World_Setup  — hex seed entry, generate island
 *   .Residents    — resident list + "Add resident"
 *   .Creation     — character creation form
 *   .Rel_Seeding  — relationship tags for new character
 *   .Simulation   — 80/20 split: grid left, sidebar right
 *
 * Layout in Simulation:
 *   Left  sim_tex  (80% of SW): grid, animated char dots, hover arrows
 *   Right stat_tex (20% of SW): island stats, residents, events, navigate
 *   Dividing line drawn at stats_x().
 *
 * Save / Load (M7): F5 = save, F9 = load; auto-save every 60 ticks.
 * Cutscene overlay (M8): triggered by new social events from SimState.
 *
 * Navigation:
 *   ESC on any screen = quit.
 *   Back buttons on World_Setup, Residents, Rel_Seeding, Simulation.
 */

