STAT_RATE :: 1.0 / 10.0

// ---- Helpers ---------------------------------------------------------------

_parse_seed :: proc(s: string) -> (u64, bool) {
    val := u64(0)
    if len(s) == 0 do return 0, false
    for ch in s {
        switch ch {
        case '0'..='9': val = val * 16 + u64(ch - '0')
        case 'a'..='f': val = val * 16 + u64(ch - 'a' + 10)
        case 'A'..='F': val = val * 16 + u64(ch - 'A' + 10)
        case: return 0, false
        }
    }
    return val, true
}

_default_seed :: proc() -> u64 {
    return 0x596767647261736C
}

// ---- Save / Load wrappers --------------------------------------------------

_do_save :: proc(app: ^App) {
    save_game(SAVE_PATH, &app.world, &app.residents, &app.sim, app.engine, &app.island_name)
}

_do_load :: proc(app: ^App) -> bool {
    epilog_destroy(app.engine)
    app.engine = epilog_create()
    _load_all_rules(app)

    ok := load_game(SAVE_PATH, &app.world, &app.residents, &app.sim, app.engine, &app.island_name)
    if ok {
        zone_labels_seed(&app.zone_labels, &app.world.grid)
        sim_tick(&app.sim, &app.residents, app.engine, app.world.tick)
        app.cam_col = GRID_W / 2
        app.cam_row = GRID_H / 2
        _draw_stat_panel(app)
    }
    return ok
}

_load_all_rules :: proc(app: ^App) {
    starter_load_rules(app.engine)
}

// ---- Shared exit/back button helpers ---------------------------------------

// Draw an exit (X) button in the top-right corner.  Returns true if clicked.
_draw_exit_btn :: proc() -> bool {
    sz   := i32(36)
    x    := SW() - sz - 8
    y    := i32(8)
    rect := rl.Rectangle{f32(x), f32(y), f32(sz), f32(sz)}
    hov  := rl.CheckCollisionPointRec(rl.GetMousePosition(), rect)
    rl.DrawRectangleRec(rect, hov ? rl.Color{180, 40, 40, 255} : rl.Color{80, 30, 30, 200})
    rl.DrawRectangleLinesEx(rect, 1, rl.Color{200, 60, 60, 255})
    rl.DrawText("X", x + 11, y + 8, UI_FSIZE, COL_TEXT)
    return hov && rl.IsMouseButtonPressed(.LEFT)
}

// Draw a back button at the bottom-left.  Returns true if clicked.
_draw_back_btn :: proc() -> bool {
    rect := rl.Rectangle{f32(UI_LPAD), f32(SH() - 52), 120, 36}
    hov  := rl.CheckCollisionPointRec(rl.GetMousePosition(), rect)
    rl.DrawRectangleRec(rect, hov ? COL_HOVER : COL_INPUT)
    rl.DrawRectangleLinesEx(rect, 1, COL_MUTED)
    rl.DrawText("<- Back", UI_LPAD + 10, SH() - 42, UI_SMALL, COL_MUTED)
    return hov && rl.IsMouseButtonPressed(.LEFT)
}

// ---- World setup screen ----------------------------------------------------

_draw_world_setup :: proc(app: ^App) -> bool {
    rl.ClearBackground(COL_BG)
    rl.DrawText("DMLS", UI_LPAD, UI_PAD, 48, COL_TEXT)
    rl.DrawText("Deb's Minimal Life Simulator", UI_LPAD, UI_PAD + 54, UI_SMALL, COL_MUTED)

    y := i32(UI_PAD + 110)
    rl.DrawText("World seed (hex)", UI_LPAD, y, UI_SMALL, COL_MUTED)
    y += 22

    input_field_draw(&app.seed_field, UI_LPAD, y, 340, 38, "")
    if rl.CheckCollisionPointRec(rl.GetMousePosition(),
            rl.Rectangle{f32(UI_LPAD), f32(y), 340, 38}) &&
            rl.IsMouseButtonPressed(.LEFT) {
        app.seed_field.active = true
    }
    input_field_update(&app.seed_field)

    if app.seed_err {
        rl.DrawText("Invalid hex seed", UI_LPAD, y + 44, UI_SMALL, rl.RED)
    }

    y += 54
    rnd_rect := rl.Rectangle{f32(UI_LPAD + 350), f32(y - 54), 160, 38}
    hov_rnd  := rl.CheckCollisionPointRec(rl.GetMousePosition(), rnd_rect)
    rl.DrawRectangleRec(rnd_rect, hov_rnd ? COL_HOVER : COL_INPUT)
    rl.DrawRectangleLinesEx(rnd_rect, 1, COL_MUTED)
    rl.DrawText("Random seed", UI_LPAD + 360, y - 44, UI_SMALL, COL_MUTED)
    if hov_rnd && rl.IsMouseButtonPressed(.LEFT) {
        rng := u64(rl.GetTime() * 1e9)
        rng ~= rng << 13; rng ~= rng >> 7; rng ~= rng << 17
        buf: [20]u8
        ns := fmt.bprintf(buf[:], "%016X", rng)
        app.seed_field.len = 0
        for i in 0..<len(ns) { app.seed_field.buf[i] = buf[i] }
        app.seed_field.len = len(ns)
    }

    go_rect := rl.Rectangle{f32(UI_LPAD), f32(y), 200, 42}
    hov_go  := rl.CheckCollisionPointRec(rl.GetMousePosition(), go_rect)
    rl.DrawRectangleRec(go_rect, hov_go ? COL_ACCENT : COL_SELECT)
    rl.DrawText("Generate island ->", UI_LPAD + 12, y + 11, UI_FSIZE, COL_TEXT)

    if (hov_go && rl.IsMouseButtonPressed(.LEFT)) || rl.IsKeyPressed(.ENTER) {
        seed_str := input_field_str(&app.seed_field)
        seed     := u64(0)
        ok       := false
        if len(seed_str) == 0 {
            seed, ok = _default_seed(), true
        } else {
            seed, ok = _parse_seed(seed_str)
        }
        if !ok { app.seed_err = true; return false }
        app.seed_err = false
        world_init(&app.world, seed)
        return true
    }

    // Back button → Title
    if _draw_back_btn() {
        app.screen = .Title
    }
    if _draw_exit_btn() || rl.IsKeyPressed(.ESCAPE) {
        rl.CloseWindow()
    }
    return false
}

// ---- Character dot colour --------------------------------------------------

_char_color :: proc(c: ^Character) -> rl.Color {
    return char_palette_color(c.sprite)
}

// ---- Grid-to-screen coordinate mapping ------------------------------------

_grid_to_screen :: proc(gc, gr, cam_col, cam_row, view_w, view_h: i32) -> (px, py: i32, visible: bool) {
    cpx          := render_cell_px()
    visible_cols := view_w  / cpx + 2
    visible_rows := view_h / cpx + 2
    start_col    := cam_col - visible_cols / 2
    start_row    := cam_row - visible_rows / 2
    dc           := gc - start_col
    dr           := gr - start_row
    if dc < 0 || dc >= visible_cols || dr < 0 || dr >= visible_rows {
        return 0, 0, false
    }
    return dc * cpx, dr * cpx, true
}

// ---- Hover arrow query (c-callback, no context) ----------------------------

MAX_ARROW_TAG :: 24

_HoverRelEntry :: struct {
    id  : u32,
    tag : [MAX_ARROW_TAG]u8,
}

_HoverRelAccum :: struct {
    entries : [MAX_RESIDENTS]_HoverRelEntry,
    count   : int,
}

_hover_rel_cb :: proc "c" (soln: ^EpilogSolution, ud: rawptr) -> EpilogSignal {
    acc := cast(^_HoverRelAccum)ud
    if acc.count >= MAX_RESIDENTS do return .EPILOG_STOP

    other_atom: cstring
    tag_atom  : cstring

    for i in 0..<epilog_soln_var_count(soln) {
        vname := epilog_soln_var_name(soln, i)
        val   := epilog_soln_var_atom(soln, i)
        if vname == nil || val == nil do continue
        switch string(vname) {
        case "Other": other_atom = val
        case "Tag":   tag_atom   = val
        }
    }

    if other_atom != nil {
        other_str := string(other_atom)
        other_id  := u32(0)
        if len(other_str) > 5 && other_str[:5] == "char_" {
            for ch in other_str[5:] {
                if ch >= '0' && ch <= '9' {
                    other_id = other_id * 10 + u32(ch - '0')
                }
            }
        }
        idx := acc.count
        acc.entries[idx].id = other_id
        if tag_atom != nil {
            ts := string(tag_atom)
            n  := min(len(ts), MAX_ARROW_TAG - 1)
            copy(acc.entries[idx].tag[:], ts[:n])
            acc.entries[idx].tag[n] = 0
        }
        acc.count += 1
    }
    return .EPILOG_NEXT
}

// Also query crush/2 and rival state for additional arrow colours
_CrushAccum :: struct {
    ids   : [MAX_RESIDENTS]u32,
    count : int,
}

_crush_cb :: proc "c" (soln: ^EpilogSolution, ud: rawptr) -> EpilogSignal {
    acc := cast(^_CrushAccum)ud
    if acc.count >= MAX_RESIDENTS do return .EPILOG_STOP
    for i in 0..<epilog_soln_var_count(soln) {
        vname := epilog_soln_var_name(soln, i)
        val   := epilog_soln_var_atom(soln, i)
        if vname == nil || val == nil do continue
        if string(vname) == "Y" {
            other_str := string(val)
            other_id  := u32(0)
            if len(other_str) > 5 && other_str[:5] == "char_" {
                for ch in other_str[5:] {
                    if ch >= '0' && ch <= '9' {
                        other_id = other_id * 10 + u32(ch - '0')
                    }
                }
            }
            acc.ids[acc.count] = other_id
            acc.count += 1
        }
    }
    return .EPILOG_NEXT
}

_arrow_color_for_tag :: proc(tag: string) -> rl.Color {
    switch tag {
    case "crush", "crushing": return rl.Color{255, 150, 180, 200}  // pink
    case "friend":            return rl.Color{80,  200, 80,  200}  // green
    case "acquaintance":      return rl.Color{60,  180, 180, 200}  // teal
    case "sibling":           return rl.Color{80,  120, 240, 200}  // blue
    case "partner":           return rl.Color{220, 180, 255, 200}  // lavender
    case "rivals":            return rl.Color{220, 60,  60,  200}  // red
    }
    return rl.Color{200, 200, 60, 140}  // default yellow
}

_draw_hover_arrows :: proc(app: ^App, hovered_char: ^Character) {
    buf_id, goal_buf: [160]u8
    atom := character_atom(hovered_char.id, buf_id[:])

    // Query relationship/3 for typed arrows
    gs := fmt.bprintf(goal_buf[:], "relationship(%s, Other, Tag)", atom)
    goal_buf[len(gs)] = 0

    rel_acc := _HoverRelAccum{}
    epilog_query(app.engine, cstring(raw_data(goal_buf[:])), _hover_rel_cb, &rel_acc)

    // Also query crush(atom, Y) for pink arrows
    crush_acc := _CrushAccum{}
    gs2 := fmt.bprintf(goal_buf[:], "crush(%s, Y)", atom)
    goal_buf[len(gs2)] = 0
    epilog_query(app.engine, cstring(raw_data(goal_buf[:])), _crush_cb, &crush_acc)

    // rivals(atom, Y)
    rival_acc := _CrushAccum{}
    gs3 := fmt.bprintf(goal_buf[:], "rivals(%s, Y)", atom)
    goal_buf[len(gs3)] = 0
    epilog_query(app.engine, cstring(raw_data(goal_buf[:])), _crush_cb, &rival_acc)

    hx, hy, hv := _grid_to_screen(hovered_char.position[0], hovered_char.position[1],
                                   app.cam_col, app.cam_row, sim_w(), sim_h())
    if !hv do return

    cpx := render_cell_px()
    cx  := hx + cpx/2
    cy  := hy + cpx/2

    // Draw relationship arrows
    for i in 0..<rel_acc.count {
        e := &rel_acc.entries[i]
        other := residents_find(&app.residents, e.id)
        if other == nil do continue
        ox, oy, ov := _grid_to_screen(other.position[0], other.position[1],
                                       app.cam_col, app.cam_row, sim_w(), sim_h())
        if !ov do continue
        tag_str := strings.truncate_to_byte(string(e.tag[:]), 0)
        col := _arrow_color_for_tag(tag_str)
        rl.DrawLine(cx, cy, ox + cpx/2, oy + cpx/2, col)
    }

    // Crush arrows (pink) — may already be covered, but ensures crushes show
    for i in 0..<crush_acc.count {
        other := residents_find(&app.residents, crush_acc.ids[i])
        if other == nil do continue
        ox, oy, ov := _grid_to_screen(other.position[0], other.position[1],
                                       app.cam_col, app.cam_row, sim_w(), sim_h())
        if !ov do continue
        rl.DrawLine(cx, cy, ox + cpx/2, oy + cpx/2, rl.Color{255, 130, 180, 220})
    }

    // Rival arrows (red dashed — approximate with two short segments)
    for i in 0..<rival_acc.count {
        other := residents_find(&app.residents, rival_acc.ids[i])
        if other == nil do continue
        ox, oy, ov := _grid_to_screen(other.position[0], other.position[1],
                                       app.cam_col, app.cam_row, sim_w(), sim_h())
        if !ov do continue
        // Dashed: draw 3 segments
        dx := (ox + cpx/2) - cx
        dy := (oy + cpx/2) - cy
        for seg in 0..<3 {
            t0 := f32(seg) / 5.0
            t1 := f32(seg) / 5.0 + 0.12
            rl.DrawLine(cx + i32(f32(dx)*t0), cy + i32(f32(dy)*t0),
                        cx + i32(f32(dx)*t1), cy + i32(f32(dy)*t1),
                        rl.Color{220, 50, 50, 220})
        }
    }
}

// ---- Draw simulation view into sim_tex (60 fps) ----------------------------

_draw_sim_view :: proc(app: ^App) {
    rl.BeginTextureMode(app.sim_tex)
    rl.ClearBackground(COL_BG)

    cpx := render_cell_px()
    grid_render(&app.world.grid, 0, 0, sim_w(), sim_h(), app.cam_col, app.cam_row, cpx)

    mouse          := rl.GetMousePosition()
    app.hovered_id  = 0

    for i in 0..<app.residents.count {
        c  := &app.residents.chars[i]
        px, py, vis := _grid_to_screen(c.position[0], c.position[1],
                                        app.cam_col, app.cam_row, sim_w(), sim_h())
        if !vis do continue

        col := _char_color(c)
        draw_char_dot_animated(c, px, py, col, app.anim_time, cpx)

        // Mood icon above sprite
        ia := int(c.id - 1)
        if ia >= 0 && ia < MAX_RESIDENTS {
            draw_mood_icon(app.sim.social[ia].mood, px, py, app.anim_time, cpx)
        }

        dot_rect := rl.Rectangle{f32(px) - 4, f32(py) - 4,
                                  f32(cpx) + 8, f32(cpx) + 8}
        if rl.CheckCollisionPointRec(mouse, dot_rect) {
            app.hovered_id = c.id
        }
    }

    if app.hovered_id != 0 {
        hov_char := residents_find(&app.residents, app.hovered_id)
        if hov_char != nil {
            _draw_hover_arrows(app, hov_char)
            hx, hy, _ := _grid_to_screen(hov_char.position[0], hov_char.position[1],
                                           app.cam_col, app.cam_row, sim_w(), sim_h())
            name_cstr := strings.clone_to_cstring(character_name(hov_char), context.temp_allocator)
            rl.DrawText(name_cstr, hx + 6, hy - 18, UI_SMALL, COL_TEXT)
            ia := int(hov_char.id - 1)
            if ia >= 0 && ia < MAX_RESIDENTS {
                mood_cstr := strings.clone_to_cstring(mood_label(app.sim.social[ia].mood), context.temp_allocator)
                rl.DrawText(mood_cstr, hx + 6, hy - 2, UI_SMALL, COL_MUTED)
            }
        }
    }

    // Dialogue bubbles
    bubble_system_draw(&app.bubbles, &app.residents, app.cam_col, app.cam_row, cpx)

    // Weather effects (before overlay)
    switch app.weather.current {
    case .Rain: weather_draw_rain(app.anim_time, app.cam_col, app.cam_row)
    case .Fog:  weather_draw_fog()
    case .Wind: weather_draw_wind(app.anim_time, &app.world.grid, app.cam_col, app.cam_row, cpx)
    case .Clear: // nothing
    }

    // Day / night overlay
    dn_col := day_night_overlay(app.world.tick, app.sim_timer)
    if dn_col.a > 0 {
        rl.DrawRectangle(0, 0, sim_w(), sim_h(), dn_col)
    }
    day_night_draw_stars(app.world.tick, app.cam_col, app.cam_row, &app.world.grid)

    // Zone labels
    zone_labels_draw(&app.zone_labels, app.cam_col, app.cam_row, rl.GetFrameTime())

    rl.DrawText("WASD: pan   hover: inspect   F5: save   F9: load   Space: pause   +/-: speed",
                8, sim_h() - 20, UI_SMALL, COL_MUTED)
    rl.EndTextureMode()
}

// ---- Colour-coded event text -----------------------------------------------
// Scans a string for known character names and draws each token in the
// character's palette colour, drawing other text in COL_TEXT.

_draw_event_coloured :: proc(app: ^App, text: string, x, y: i32) {
    cx := x
    i  := 0
    for i < len(text) {
        // Try to match a character name at position i
        matched_len    := 0
        matched_color  := COL_TEXT

        for ci in 0..<app.residents.count {
            c    := &app.residents.chars[ci]
            name := character_name(c)
            if i + len(name) <= len(text) && text[i:i+len(name)] == name {
                if matched_len < len(name) {
                    matched_len   = len(name)
                    matched_color = _char_color(c)
                }
            }
        }

        if matched_len > 0 {
            seg  := strings.clone_to_cstring(text[i:i+matched_len], context.temp_allocator)
            rl.DrawText(seg, cx, y, UI_SMALL, matched_color)
            cx += rl.MeasureText(seg, UI_SMALL)
            i  += matched_len
        } else {
            // Advance until next potential name start or end of string
            j := i + 1
            for j < len(text) {
                found := false
                for ci in 0..<app.residents.count {
                    c    := &app.residents.chars[ci]
                    name := character_name(c)
                    if j + len(name) <= len(text) && text[j:j+len(name)] == name {
                        found = true
                        break
                    }
                }
                if found do break
                j += 1
            }
            seg  := strings.clone_to_cstring(text[i:j], context.temp_allocator)
            rl.DrawText(seg, cx, y, UI_SMALL, COL_TEXT)
            cx += rl.MeasureText(seg, UI_SMALL)
            i   = j
        }
    }
}

// ---- Draw stats sidebar into stat_tex (10 fps) ------------------------------

_draw_stat_panel :: proc(app: ^App) {
    rl.BeginTextureMode(app.stat_tex)
    rl.ClearBackground(COL_PANEL)

    sw := stat_w()
    y  := i32(UI_PAD)
    lx := i32(UI_PAD)

    rl.DrawText("ISLAND STATS", lx, y, UI_SMALL, COL_ACCENT)
    y += 20

    // Speed buttons: [▶ 1×]  [▶▶ 4×]  [▶▶▶ 16×]  [⏸]
    speed_labels := [4]cstring{"|| Pause", "> 1x", ">> 4x", ">>> 16x"}
    speed_bw := i32(56)
    sx := lx
    for si in 0..<4 {
        sel := app.sim_speed == si
        br  := rl.Rectangle{f32(sx), f32(y), f32(speed_bw), 22}
        bg  := sel ? COL_ACCENT : COL_INPUT
        hov := rl.CheckCollisionPointRec(rl.GetMousePosition(), br)
        if hov { bg = sel ? COL_ACCENT : COL_HOVER }
        rl.DrawRectangleRec(br, bg)
        rl.DrawRectangleLinesEx(br, 1, sel ? COL_ACCENT : COL_MUTED)
        rl.DrawText(speed_labels[si], sx + 4, y + 4, UI_SMALL - 2, COL_TEXT)
        sx += speed_bw + 2
    }
    y += 28

    iname_cstr := strings.clone_to_cstring(island_name_str(&app.island_name), context.temp_allocator)
    rl.DrawText(iname_cstr, lx, y, UI_FSIZE, COL_TEXT)
    y += 24

    seed_buf: [24]u8
    rl.DrawText("Seed:", lx, y, UI_SMALL, COL_MUTED)
    seed_cstr := world_seed_string(&app.world, seed_buf[:])
    rl.DrawText(seed_cstr, lx + 50, y, UI_SMALL, COL_TEXT)
    y += 20

    stat_lines: [6][56]u8
    sl0 := fmt.bprintf(stat_lines[0][:], "Tick:      %d", app.world.tick)
    stat_lines[0][len(sl0)] = 0
    sl1 := fmt.bprintf(stat_lines[1][:], "Residents: %d", app.residents.count)
    stat_lines[1][len(sl1)] = 0
    sl2 := fmt.bprintf(stat_lines[2][:], "Crushes:   %d", app.sim.crush_count)
    stat_lines[2][len(sl2)] = 0
    sl3 := fmt.bprintf(stat_lines[3][:], "Rivals:    %d pairs", app.sim.rival_count)
    stat_lines[3][len(sl3)] = 0
    sl4 := fmt.bprintf(stat_lines[4][:], "Weather:   %s (~%d ticks)",
        weather_label(app.weather.current), app.weather.ticks_remaining)
    stat_lines[4][len(sl4)] = 0
    // Day/night phase label
    phase_str := ""
    switch day_phase_for_tick(app.world.tick) {
    case .Dawn:  phase_str = "Dawn"
    case .Day:   phase_str = "Day"
    case .Dusk:  phase_str = "Dusk"
    case .Night: phase_str = "Night"
    }
    sl5 := fmt.bprintf(stat_lines[5][:], "Time:      %s", phase_str)
    stat_lines[5][len(sl5)] = 0
    for &ln in stat_lines {
        rl.DrawText(cstring(raw_data(ln[:])), lx, y, UI_SMALL, COL_TEXT)
        y += 18
    }
    y += 8

    rl.DrawLine(lx, y, sw - lx, y, COL_MUTED)
    y += 10

    rl.DrawText("RESIDENTS", lx, y, UI_SMALL, COL_ACCENT)
    y += 20

    for i in 0..<app.residents.count {
        c  := &app.residents.chars[i]
        ia := int(c.id - 1)
        rl.DrawRectangle(lx, y + 3, 10, 10, _char_color(c))
        name_cstr := strings.clone_to_cstring(character_name(c), context.temp_allocator)
        rl.DrawText(name_cstr, lx + 16, y, UI_SMALL, COL_TEXT)
        if ia >= 0 && ia < MAX_RESIDENTS {
            mood_cstr := strings.clone_to_cstring(mood_label(app.sim.social[ia].mood), context.temp_allocator)
            rl.DrawText(mood_cstr, lx + 110, y, UI_SMALL, COL_MUTED)
        }
        y += 18
    }
    if app.residents.count == 0 {
        rl.DrawText("none yet", lx, y, UI_SMALL, COL_MUTED)
        y += 18
    }
    y += 8

    rl.DrawLine(lx, y, sw - lx, y, COL_MUTED)
    y += 10

    rl.DrawText("EVENTS", lx, y, UI_SMALL, COL_ACCENT)
    y += 20

    MAX_SHOWN :: 8
    shown := min(app.sim.log.count, MAX_SHOWN)
    if shown == 0 {
        rl.DrawText("no events yet", lx, y, UI_SMALL, COL_MUTED)
        y += 18
    } else {
        for i in 0..<shown {
            e := event_log_get(&app.sim.log, i)
            if e == nil do continue
            tick_buf: [20]u8
            ts := fmt.bprintf(tick_buf[:], "[%d] ", e.tick)
            tick_buf[len(ts)] = 0
            tw := rl.MeasureText(cstring(raw_data(tick_buf[:])), UI_SMALL)
            rl.DrawText(cstring(raw_data(tick_buf[:])), lx, y, UI_SMALL, COL_MUTED)
            _draw_event_coloured(app, event_entry_str(e), lx + tw, y)
            y += 18
        }
    }

    y += 8
    rl.DrawLine(lx, y, sw - lx, y, COL_MUTED)
    y += 10

    // Minimap
    rl.DrawText("MAP", lx, y, UI_SMALL, COL_ACCENT)
    y += 18
    minimap_draw(&app.world.grid, &app.residents, lx, y)
    y += MINIMAP_H + 10

    rl.DrawLine(lx, y, sw - lx, y, COL_MUTED)
    y += 10

    rl.DrawText("NAVIGATE", lx, y, UI_SMALL, COL_ACCENT)
    y += 20

    // "Residents" button — clicks handled in window coords by _handle_stat_clicks
    res_rect := rl.Rectangle{f32(lx), f32(y), 160, 30}
    hov_res  := rl.CheckCollisionPointRec(rl.GetMousePosition(), res_rect)
    rl.DrawRectangleRec(res_rect, hov_res ? COL_HOVER : COL_INPUT)
    rl.DrawText("Residents ->", lx + 8, y + 7, UI_SMALL, COL_TEXT)
    y += 40

    // Exit button inside sidebar
    exit_rect := rl.Rectangle{f32(lx), f32(y), 120, 30}
    hov_exit  := rl.CheckCollisionPointRec(rl.GetMousePosition(), exit_rect)
    rl.DrawRectangleRec(exit_rect, hov_exit ? rl.Color{180, 40, 40, 255} : rl.Color{80, 30, 30, 200})
    rl.DrawText("Quit", lx + 8, y + 7, UI_SMALL, COL_TEXT)

    rl.EndTextureMode()
}

// ---- Stat sidebar button clicks (window/composite coords) -------------------

_handle_stat_clicks :: proc(app: ^App) {
    ox := stats_x() + i32(UI_PAD)

    // Speed buttons at (UI_PAD + 20 + 28) from top of stat panel
    speed_y    := i32(UI_PAD) + 20 + 0   // ISLAND STATS header + 20
    speed_bw   := i32(56)
    for si in 0..<4 {
        br := rl.Rectangle{f32(ox + i32(si) * (speed_bw + 2)), f32(speed_y), f32(speed_bw), 22}
        if rl.CheckCollisionPointRec(rl.GetMousePosition(), br) &&
           rl.IsMouseButtonPressed(.LEFT) {
            app.sim_speed = si
        }
    }

    res_rows  := i32(app.residents.count)
    res_empty := app.residents.count == 0 ? i32(18) : i32(0)
    evt_shown := i32(min(app.sim.log.count, 8))
    evt_empty := app.sim.log.count == 0 ? i32(18) : i32(0)

    // Reconstruct y position of the Residents → button (must match _draw_stat_panel layout)
    // Now has extra 28px for speed buttons row, 2 extra stat lines, and minimap block
    base_y := i32(UI_PAD) +
        i32(20 + 28 + 24 + 20 + 18*6 + 8) +   // ISLAND STATS block (speed row + 6 stat lines)
        i32(10 + 20) +                           // divider + RESIDENTS header
        i32(18)*res_rows + res_empty + i32(8) +
        i32(10 + 10 + 20) +                      // divider + EVENTS header
        i32(18)*evt_shown + evt_empty + i32(8) +
        i32(10 + 18 + MINIMAP_H + 10 + 10 + 10 + 20)  // MAP section + divider + NAVIGATE header

    // Resident rows in the sidebar (for backstory on click)
    res_list_y := i32(UI_PAD) + 20 + 28 + 24 + 20 + 18*6 + 8 + 10 + 20
    for i in 0..<app.residents.count {
        row_rect := rl.Rectangle{f32(ox), f32(res_list_y + i32(i)*18), 200, 18}
        if rl.CheckCollisionPointRec(rl.GetMousePosition(), row_rect) &&
           rl.IsMouseButtonPressed(.LEFT) {
            backstory_open(&app.backstory, app.residents.chars[i].id,
                           &app.residents, app.engine)
        }
    }

    res_rect := rl.Rectangle{f32(ox), f32(base_y), 160, 30}
    if rl.CheckCollisionPointRec(rl.GetMousePosition(), res_rect) &&
       rl.IsMouseButtonPressed(.LEFT) {
        app.screen = .Residents
        app.resident_list = {}
    }

    exit_y    := base_y + 40
    exit_rect := rl.Rectangle{f32(ox), f32(exit_y), 120, 30}
    if rl.CheckCollisionPointRec(rl.GetMousePosition(), exit_rect) &&
       rl.IsMouseButtonPressed(.LEFT) {
        rl.CloseWindow()
    }
}

// ---- Cutscene check — trigger when new event appears -----------------------

_last_event_count: int

_check_cutscene :: proc(app: ^App) {
    if app.sim.log.count > _last_event_count {
        e := event_log_get(&app.sim.log, 0)
        if e != nil {
            cutscene_trigger(&app.cutscene, event_entry_str(e))
        }
        _last_event_count = app.sim.log.count
    }
}

// ---- Simulation update + composite -----------------------------------------

_update_simulation :: proc(app: ^App) {
    dt := rl.GetFrameTime()
    app.anim_time += dt

    // ESC → quit
    if rl.IsKeyPressed(.ESCAPE) {
        rl.CloseWindow()
        return
    }

    // WASD pan
    if rl.IsKeyDown(.W) { app.cam_row -= 2 }
    if rl.IsKeyDown(.S) { app.cam_row += 2 }
    if rl.IsKeyDown(.A) { app.cam_col -= 2 }
    if rl.IsKeyDown(.D) { app.cam_col += 2 }
    app.cam_col = clamp(app.cam_col, 0, GRID_W - 1)
    app.cam_row = clamp(app.cam_row, 0, GRID_H - 1)

    // F5 = save, F9 = load
    if rl.IsKeyPressed(.F5) {
        _do_save(app)
    }
    if rl.IsKeyPressed(.F9) {
        if _do_load(app) {
            _draw_stat_panel(app)
        }
    }

    // Speed keyboard shortcuts
    if rl.IsKeyPressed(.SPACE) {
        if app.sim_speed == 0 { app.sim_speed = 1 } else { app.sim_speed = 0 }
    }
    if rl.IsKeyPressed(.KP_ADD) || rl.IsKeyPressed(.EQUAL) {
        if app.sim_speed < 3 { app.sim_speed += 1 }
    }
    if rl.IsKeyPressed(.KP_SUBTRACT) || rl.IsKeyPressed(.MINUS) {
        if app.sim_speed > 1 { app.sim_speed -= 1 }
    }

    // Sim tick — rate depends on sim_speed
    // Speed 0=paused, 1=1Hz, 2=4Hz, 3=16Hz
    _SPEED_HZ := [4]f32{0, 1.0, 4.0, 16.0}
    tick_hz := _SPEED_HZ[app.sim_speed]
    tick_interval := tick_hz > 0 ? 1.0 / tick_hz : 1e9

    app.sim_timer += dt
    for app.sim_speed > 0 && app.sim_timer >= tick_interval {
        app.sim_timer -= tick_interval
        world_tick_wander(&app.world, &app.residents)
        sim_tick(&app.sim, &app.residents, app.engine, app.world.tick)
        weather_tick(&app.weather, &app.sim.rng)
        friendship_decay_tick(&app.decay, &app.residents, app.engine, &app.sim, app.world.tick)
        confession_tick(&app.confession, &app.sim, &app.residents, app.engine, app.world.tick)
        confrontation_tick(&app.confrontation, &app.sim, &app.residents, app.engine, app.world.tick)
        _check_cutscene(app)

        // Auto-save every 60 ticks
        if app.world.tick - app.last_autosave_tick >= 60 {
            _do_save(app)
            app.last_autosave_tick = app.world.tick
        }
    }

    // Redraw at appropriate rates
    _draw_sim_view(app)
    app.stat_timer += dt
    if app.stat_timer >= STAT_RATE {
        app.stat_timer = 0
        _draw_stat_panel(app)
    }

    // Composite — 80/20 side-by-side
    rl.ClearBackground(rl.BLACK)

    // Left: grid (80%)
    src_sim := rl.Rectangle{0, 0, f32(sim_w()), -f32(sim_h())}
    dst_sim := rl.Rectangle{0, 0, f32(sim_w()),  f32(sim_h())}
    rl.DrawTexturePro(app.sim_tex.texture, src_sim, dst_sim, {0, 0}, 0, rl.WHITE)

    // Right: sidebar (20%)
    src_stat := rl.Rectangle{0, 0, f32(stat_w()), -f32(stat_h())}
    dst_stat := rl.Rectangle{f32(stats_x()), 0, f32(stat_w()), f32(stat_h())}
    rl.DrawTexturePro(app.stat_tex.texture, src_stat, dst_stat, {0, 0}, 0, rl.WHITE)

    // Dividing line
    rl.DrawLine(stats_x(), 0, stats_x(), SH(), COL_MUTED)

    _handle_stat_clicks(app)

    // Tier 3: update bubbles + draw prompts
    bubble_system_update(&app.bubbles, dt)
    // Note: bubbles are drawn inside _draw_sim_view pass already via the
    // bubble_system_draw call — we just update timing here.

    // Confession prompt
    if app.confession.state == .Waiting {
        conf_res := confession_draw_prompt(&app.confession, &app.residents, dt)
        if conf_res != 0 {
            confession_resolve(&app.confession, conf_res, &app.sim, &app.residents,
                               app.engine, app.world.tick)
        } else if app.confession.timer <= 0 {
            confession_resolve(&app.confession, 0, &app.sim, &app.residents,
                               app.engine, app.world.tick)
        }
    }

    // Confrontation prompt
    if app.confrontation.state == .Waiting {
        res2 := confrontation_draw_prompt(&app.confrontation, &app.residents, dt)
        if res2 != 0 {
            confrontation_resolve(res2, app.confrontation.char_a, app.confrontation.char_b,
                                   &app.sim, &app.residents, app.engine, app.world.tick)
        }
    }

    // Backstory panel (drawn on top of everything)
    backstory_draw(&app.backstory, &app.residents, &app.sim, &app.sim.log)

    // M8 cutscene overlay on top of everything
    cutscene_update(&app.cutscene)
}

// ---- Main ------------------------------------------------------------------

main :: proc() {
    rl.SetConfigFlags({.WINDOW_RESIZABLE})
    g_screen.w = SCREEN_W
    g_screen.h = SCREEN_H
    rl.InitWindow(SCREEN_W, SCREEN_H, "DMLS — Deb's Minimal Life Simulator")
    rl.SetTargetFPS(60)
    defer rl.CloseWindow()

    app := new(App)
    defer free(app)

    app.engine = epilog_create()
    defer epilog_destroy(app.engine)

    residents_init(&app.residents)
    app.screen    = .Resolution
    app.cam_col   = GRID_W / 2
    app.cam_row   = GRID_H / 2
    app.title_rng = 0xFEEDBEEF_CAFEBABE
    app.sim_speed = 1
    weather_init(&app.weather)
    g_decay   = &app.decay
    g_bubbles = &app.bubbles

    {
        def := _default_seed()
        ds  := fmt.bprintf(app.seed_field.buf[:], "%016X", def)
        app.seed_field.len = len(ds)
        app.seed_field.active = true
    }

    _load_all_rules(app)
    resolution_picker_init(&app.res_picker)

    // Allocate RenderTextures at maximum possible sizes.
    // sim_tex: widest sim viewport = 80% of 1920 = 1536, tallest = 1080.
    // stat_tex: widest sidebar = 20% of 1920 = 384, tallest = 1080.
    app.sim_tex  = rl.LoadRenderTexture(SCREEN_W * 80 / 100, SCREEN_H)
    app.stat_tex = rl.LoadRenderTexture(SCREEN_W - SCREEN_W * 80 / 100, SCREEN_H)
    app.rt_ready = true
    defer rl.UnloadRenderTexture(app.sim_tex)
    defer rl.UnloadRenderTexture(app.stat_tex)

    title_screen_init(&app.title)

    for !rl.WindowShouldClose() {
        rl.BeginDrawing()
        free_all(context.temp_allocator)

        switch app.screen {

        case .Resolution:
            if resolution_picker_update(&app.res_picker) {
                app.screen = .Title
            }
            // Exit button on resolution picker
            if _draw_exit_btn() || rl.IsKeyPressed(.ESCAPE) {
                rl.CloseWindow()
            }

        case .Title:
            result := title_screen_update(&app.title, &app.island_name, &app.title_rng)
            switch result {
            case 1:
                app.screen = .World_Setup
            case 2:
                if _do_load(app) {
                    app.screen = .Simulation
                } else {
                    app.title.load_err   = true
                    app.title.load_err_t = 3.0
                }
            }
            // Exit button on title screen
            if _draw_exit_btn() || rl.IsKeyPressed(.ESCAPE) {
                rl.CloseWindow()
            }

        case .World_Setup:
            // Back + exit drawn inside _draw_world_setup
            if _draw_world_setup(app) {
                zone_labels_seed(&app.zone_labels, &app.world.grid)
                starters_seed(&app.residents, &app.world, app.engine)
                sim_init(&app.sim, app.world.seed)
                app.screen = .Residents
            }

        case .Residents:
            if resident_list_update(&app.resident_list, &app.residents, app.engine) {
                creation_screen_init(&app.creation)
                app.screen = .Creation
            }
            // "Simulate ->" button
            sim_rect := rl.Rectangle{f32(SW() - 200), f32(SH() - 60), 180, 42}
            hov_sim  := rl.CheckCollisionPointRec(rl.GetMousePosition(), sim_rect)
            if app.residents.count > 0 {
                rl.DrawRectangleRec(sim_rect, hov_sim ? COL_ACCENT2 : COL_ACCENT)
                rl.DrawText("Simulate ->", SW() - 188, SH() - 46, UI_FSIZE, COL_TEXT)
                if hov_sim && rl.IsMouseButtonPressed(.LEFT) {
                    app.screen = .Simulation
                    _draw_stat_panel(app)
                }
            }
            // Back → World_Setup
            if _draw_back_btn() {
                app.screen = .World_Setup
            }
            if _draw_exit_btn() || rl.IsKeyPressed(.ESCAPE) {
                rl.CloseWindow()
            }

        case .Creation:
            new_char: Character
            if creation_screen_update(&app.creation, &new_char) {
                app.pending_char = new_char
                app.pending_id   = residents_add(&app.residents, new_char)
                epilog_assert_character(app.engine, residents_find(&app.residents, app.pending_id))
                world_spawn_character(&app.world, &app.residents, app.pending_id)
                rel_seeding_init(&app.rel_seeding, app.pending_id, &app.residents)
                app.screen = .Rel_Seeding
            }
            // Back → Residents
            if _draw_back_btn() {
                app.screen = .Residents
            }
            if _draw_exit_btn() || rl.IsKeyPressed(.ESCAPE) {
                rl.CloseWindow()
            }

        case .Rel_Seeding:
            if rel_seeding_update(&app.rel_seeding, &app.residents) {
                rel_seeding_commit(&app.rel_seeding, &app.residents, app.engine)
                app.screen = .Residents
                app.resident_list = {}
            }
            // Back → Residents (discards pending character)
            if _draw_back_btn() {
                app.screen = .Residents
            }
            if _draw_exit_btn() || rl.IsKeyPressed(.ESCAPE) {
                rl.CloseWindow()
            }

        case .Simulation:
            _update_simulation(app)
        }

        rl.EndDrawing()
    }
}

package dmls

import "core:fmt"
import "core:strings"
import "core:c"

// ---- Enumerations ----------------------------------------------------------

Gender :: enum u8 {
    Male,
    Female,
    Nonbinary,
}

DatingPref :: enum u8 {
    Male,
    Female,
    Any,
    None,
}

Pronouns :: enum u8 {
    He_Him,
    She_Her,
    They_Them,
}

Personality :: enum u8 {
    Ambitious_Achiever,
    Outgoing_Merrymaker,
    Outgoing_Dynamo,
    Laid_Back_Guy,
    Sweetie,
    Cranky,
}

RelationshipTag :: enum u8 {
    Stranger,
    Acquaintance,
    Friend,
    Sibling,
    Partner,
}

// ---- Character struct ------------------------------------------------------

MAX_NAME_LEN  :: 32
MAX_RESIDENTS :: 64

Character :: struct {
    id          : u32,
    name        : [MAX_NAME_LEN]u8,
    nickname    : [MAX_NAME_LEN]u8,
    age         : u8,
    gender      : Gender,
    dating_pref : DatingPref,
    personality : Personality,
    pronouns    : Pronouns,
    position    : [2]i32,
    sprite      : u32,
}

character_name :: proc(c: ^Character) -> string {
    return strings.truncate_to_byte(string(c.name[:]), 0)
}

character_nickname :: proc(c: ^Character) -> string {
    return strings.truncate_to_byte(string(c.nickname[:]), 0)
}

character_atom :: proc(id: u32, buf: []u8) -> cstring {
    s := fmt.bprintf(buf, "char_%d", id)
    buf[len(s)] = 0
    return cstring(raw_data(buf))
}

// ---- Resident registry -----------------------------------------------------

Residents :: struct {
    chars  : [MAX_RESIDENTS]Character,
    count  : u32,
    next_id: u32,
    rel    : [MAX_RESIDENTS][MAX_RESIDENTS]RelationshipTag,
}

residents_init :: proc(r: ^Residents) {
    r^ = {}
    r.next_id = 1
}

residents_add :: proc(r: ^Residents, c: Character) -> u32 {
    assert(r.count < MAX_RESIDENTS)
    idx := r.count
    r.chars[idx] = c
    r.chars[idx].id = r.next_id
    r.next_id += 1
    r.count += 1
    return r.chars[idx].id
}

residents_find :: proc(r: ^Residents, id: u32) -> ^Character {
    for i in 0..<r.count {
        if r.chars[i].id == id do return &r.chars[i]
    }
    return nil
}

// ---- Display helpers -------------------------------------------------------

gender_label :: proc(g: Gender) -> string {
    switch g {
    case .Male:      return "Male"
    case .Female:    return "Female"
    case .Nonbinary: return "Nonbinary"
    }
    return ""
}

dating_pref_label :: proc(d: DatingPref) -> string {
    switch d {
    case .Male:   return "Men"
    case .Female: return "Women"
    case .Any:    return "Anyone"
    case .None:   return "Nobody"
    }
    return ""
}

pronouns_label :: proc(p: Pronouns) -> string {
    switch p {
    case .He_Him:    return "he/him"
    case .She_Her:   return "she/her"
    case .They_Them: return "they/them"
    }
    return ""
}

personality_label :: proc(p: Personality) -> string {
    switch p {
    case .Ambitious_Achiever:  return "Ambitious Achiever"
    case .Outgoing_Merrymaker: return "Outgoing Merrymaker"
    case .Outgoing_Dynamo:     return "Outgoing Dynamo"
    case .Laid_Back_Guy:       return "Laid-Back Guy"
    case .Sweetie:             return "Sweetie"
    case .Cranky:              return "Cranky"
    }
    return ""
}

personality_atom :: proc(p: Personality) -> cstring {
    switch p {
    case .Ambitious_Achiever:  return "ambitious_achiever"
    case .Outgoing_Merrymaker: return "outgoing_merrymaker"
    case .Outgoing_Dynamo:     return "outgoing_dynamo"
    case .Laid_Back_Guy:       return "laid_back_guy"
    case .Sweetie:             return "sweetie"
    case .Cranky:              return "cranky"
    }
    return "unknown"
}

dating_pref_atom :: proc(d: DatingPref) -> cstring {
    switch d {
    case .Male:   return "male"
    case .Female: return "female"
    case .Any:    return "any"
    case .None:   return "none"
    }
    return "none"
}

relationship_atom :: proc(t: RelationshipTag) -> cstring {
    switch t {
    case .Stranger:     return "stranger"
    case .Acquaintance: return "acquaintance"
    case .Friend:       return "friend"
    case .Sibling:      return "sibling"
    case .Partner:      return "partner"
    }
    return "stranger"
}

// ---- Assert character into Epilog ------------------------------------------

epilog_assert_character :: proc(engine: ^EpilogEngine, c: ^Character) {
    buf_id : [32]u8
    buf_src: [256]u8

    atom := character_atom(c.id, buf_id[:])

    gender_str: cstring
    switch c.gender {
    case .Male:      gender_str = "male"
    case .Female:    gender_str = "female"
    case .Nonbinary: gender_str = "nonbinary"
    }

    s := fmt.bprintf(buf_src[:], "character(%s, %s).", atom, personality_atom(c.personality))
    buf_src[len(s)] = 0
    epilog_load_string(engine, cstring(raw_data(buf_src[:])))

    s = fmt.bprintf(buf_src[:], "dating_pref(%s, %s).", atom, dating_pref_atom(c.dating_pref))
    buf_src[len(s)] = 0
    epilog_load_string(engine, cstring(raw_data(buf_src[:])))

    s = fmt.bprintf(buf_src[:], "gender(%s, %s).", atom, gender_str)
    buf_src[len(s)] = 0
    epilog_load_string(engine, cstring(raw_data(buf_src[:])))
}

epilog_assert_relationship :: proc(engine: ^EpilogEngine, id_a, id_b: u32, tag: RelationshipTag) {
    buf_a  : [32]u8
    buf_b  : [32]u8
    buf_src: [128]u8

    atom_a := character_atom(id_a, buf_a[:])
    atom_b := character_atom(id_b, buf_b[:])

    s := fmt.bprintf(buf_src[:], "relationship(%s, %s, %s).", atom_a, atom_b, relationship_atom(tag))
    buf_src[len(s)] = 0
    epilog_load_string(engine, cstring(raw_data(buf_src[:])))
}

/*
 * social_events.odin — Tier 3 social depth features:
 *
 *   3.1 Dialogue bubbles — short speech bubbles on character interaction
 *   3.2 Crush confession — Accept/Reject prompt + auto-resolve
 *   3.3 Rival confrontation — Let it happen / Intervene prompt
 *   3.4 Friendship decay — friend→acquaintance→stranger over idle ticks
 *   3.5 Character backstory panel — full detail view on click
 */

package dmls

import rl      "vendor:raylib"
import "core:fmt"
import "core:strings"

// ============================================================
// 3.1  Dialogue Bubbles
// ============================================================

MAX_BUBBLES :: 8

DialogueBubble :: struct {
    char_id : u32,
    msg     : [48]u8,
    msg_len : int,
    timer   : f32,       // seconds remaining
}

BubbleSystem :: struct {
    bubbles : [MAX_BUBBLES]DialogueBubble,
    count   : int,
}

_FRIEND_LINES := []string{
    "Did you eat today?",
    "I found something interesting.",
    "Walk with me?",
    "Good to see you.",
}

_CRUSH_LINES := []string{
    "Oh— hi.",
    "...",
    "Hey.",
    "You look nice today.",
}

_RIVAL_LINES := []string{""}  // rivals don't speak — just a pause

_NICK_LINES := []string{
    "Sunflower.",
    "Hey, sunflower.",
    "There you are.",
}

_ACQUAINTANCE_LINES := []string{
    "Hey.",
    "Oh, it's you.",
    "Hi.",
}

_bubble_push :: proc(bs: ^BubbleSystem, id: u32, msg: string) {
    // Replace existing bubble for same char if any
    for i in 0..<bs.count {
        if bs.bubbles[i].char_id == id {
            b := &bs.bubbles[i]
            b.timer = 3.0
            n := min(len(msg), 47)
            copy(b.msg[:], msg[:n])
            b.msg[n] = 0
            b.msg_len = n
            return
        }
    }
    if bs.count >= MAX_BUBBLES do return
    b := &bs.bubbles[bs.count]
    b.char_id = id
    b.timer   = 3.0
    n := min(len(msg), 47)
    copy(b.msg[:], msg[:n])
    b.msg[n] = 0
    b.msg_len = n
    bs.count += 1
}

bubble_system_update :: proc(bs: ^BubbleSystem, dt: f32) {
    i := 0
    for i < bs.count {
        bs.bubbles[i].timer -= dt
        if bs.bubbles[i].timer <= 0 {
            bs.bubbles[i] = bs.bubbles[bs.count-1]
            bs.count -= 1
        } else {
            i += 1
        }
    }
}

// Call when two characters interact (proximity tick).
// relationship: "friend", "acquaintance", "crush", "stranger", etc.
bubble_on_interact :: proc(bs: ^BubbleSystem, a, b: ^Character,
                           relationship: string, rng: ^DependentRNG) {
    lines: []string
    switch relationship {
    case "friend":       lines = _FRIEND_LINES
    case "crush":        lines = _CRUSH_LINES
    case "acquaintance": lines = _ACQUAINTANCE_LINES
    case:                return  // strangers don't speak
    }
    if len(lines) == 0 do return
    idx  := int(dependent_next(rng) * f64(len(lines))) % len(lines)
    _bubble_push(bs, a.id, lines[idx])
}

// Draw all active bubbles.
bubble_system_draw :: proc(bs: ^BubbleSystem, res: ^Residents,
                           cam_col, cam_row, cpx: i32) {
    for i in 0..<bs.count {
        b := &bs.bubbles[i]
        c := residents_find(res, b.char_id)
        if c == nil do continue

        px, py, vis := _grid_to_screen(c.position[0], c.position[1],
                                        cam_col, cam_row, sim_w(), sim_h())
        if !vis do continue

        msg_str  := string(b.msg[:b.msg_len])
        msg_cstr := strings.clone_to_cstring(msg_str, context.temp_allocator)
        tw       := rl.MeasureText(msg_cstr, UI_SMALL - 2)
        bx       := px - tw/2
        by       := py - cpx - 22
        bw       := tw + 8
        bh       := i32(18)

        // Fade with timer
        alpha := u8(clamp(int(b.timer * 80), 0, 200))

        rl.DrawRectangle(bx - 4, by, bw, bh, rl.Color{30, 30, 50, alpha})
        rl.DrawRectangleLinesEx(rl.Rectangle{f32(bx-4), f32(by), f32(bw), f32(bh)},
                                 1, rl.Color{150, 130, 200, alpha})
        rl.DrawText(msg_cstr, bx, by + 2, UI_SMALL - 2,
                    rl.Color{220, 220, 230, alpha})
    }
}

// ============================================================
// 3.2  Crush Confession Event
// ============================================================

ConfessionState :: enum { None, Waiting, Resolved }

ConfessionEvent :: struct {
    state       : ConfessionState,
    from_id     : u32,
    on_id       : u32,
    timer       : f32,      // seconds before auto-resolve
    crush_ticks : [MAX_RESIDENTS][MAX_RESIDENTS]u64,  // tick when crush started
}

confession_tick :: proc(ce: ^ConfessionEvent, sim: ^SimState, res: ^Residents,
                        engine: ^EpilogEngine, tick: u64) {
    if ce.state == .Waiting do return  // already pending player input

    // Check all crush pairs: crush for 20+ ticks AND interaction_count > 15
    for i in 0..<res.count {
        a := &res.chars[i]
        ia := int(a.id - 1)
        if ia >= MAX_RESIDENTS || !sim.social[ia].has_crush do continue

        // Find who they're crushing on
        crush_on := _find_crush_target(engine, a.id)
        if crush_on == 0 do continue

        // Check ticks
        start_tick := ce.crush_ticks[ia][int(crush_on-1)]
        if start_tick == 0 {
            ce.crush_ticks[ia][int(crush_on-1)] = tick
            continue
        }
        if tick - start_tick < 20 do continue
        if sim.social[ia].interaction_count < 15 do continue

        // Fire confession
        ce.state   = .Waiting
        ce.from_id = a.id
        ce.on_id   = crush_on
        ce.timer   = 10.0

        // Log the approach
        b := residents_find(res, crush_on)
        if b != nil {
            msg_buf: [EVENT_MSG_LEN]u8
            ms := fmt.bprintf(msg_buf[:], "%s: \"I have something to tell you.\"",
                character_name(a))
            event_log_push(&sim.log, tick, string(msg_buf[:len(ms)]))
        }
        return
    }
}

_find_crush_target :: proc(engine: ^EpilogEngine, from_id: u32) -> u32 {
    buf_a, goal: [128]u8
    atom_a := character_atom(from_id, buf_a[:])

    result := u32(0)

    CrushTargetCB :: struct { target: u32 }
    cb_data := CrushTargetCB{}

    crush_target_cb :: proc "c" (soln: ^EpilogSolution, ud: rawptr) -> EpilogSignal {
        data := cast(^CrushTargetCB)ud
        for i in 0..<epilog_soln_var_count(soln) {
            vname := epilog_soln_var_name(soln, i)
            val   := epilog_soln_var_atom(soln, i)
            if vname == nil || val == nil do continue
            if string(vname) == "Y" {
                s := string(val)
                if len(s) > 5 && s[:5] == "char_" {
                    id := u32(0)
                    for ch in s[5:] {
                        if ch >= '0' && ch <= '9' { id = id*10 + u32(ch-'0') }
                    }
                    data.target = id
                }
            }
        }
        return .EPILOG_STOP
    }

    gs := fmt.bprintf(goal[:], "crush(%s, Y)", atom_a)
    goal[len(gs)] = 0
    epilog_query(engine, cstring(raw_data(goal[:])), crush_target_cb, &cb_data)
    result = cb_data.target
    return result
}

// Call every frame when state == .Waiting — draws the prompt.
// Returns: 0=still waiting, 1=accepted, 2=rejected
confession_draw_prompt :: proc(ce: ^ConfessionEvent, res: ^Residents, dt: f32) -> int {
    if ce.state != .Waiting do return 0

    ce.timer -= dt
    from := residents_find(res, ce.from_id)
    on   := residents_find(res, ce.on_id)
    if from == nil || on == nil { ce.state = .None; return 0 }

    // Overlay
    rl.DrawRectangle(0, 0, SW(), SH(), rl.Color{10, 10, 20, 160})

    cw := i32(480)
    ch := i32(140)
    cx := (SW() - cw) / 2
    cy := (SH() - ch) / 2
    rl.DrawRectangle(cx, cy, cw, ch, rl.Color{30, 28, 50, 240})
    rl.DrawRectangleLinesEx(rl.Rectangle{f32(cx), f32(cy), f32(cw), f32(ch)},
                             2, rl.Color{255, 130, 180, 200})

    // Names in their colours
    from_name := strings.clone_to_cstring(character_name(from), context.temp_allocator)
    on_name   := strings.clone_to_cstring(character_name(on),   context.temp_allocator)
    rl.DrawText(from_name, cx + 20, cy + 16, UI_FSIZE, char_palette_color(from.sprite))
    rl.DrawText(" confesses to ", cx + 20 + rl.MeasureText(from_name, UI_FSIZE), cy + 16, UI_FSIZE, COL_TEXT)
    rl.DrawText(on_name, cx + 20 + rl.MeasureText(from_name, UI_FSIZE) +
                rl.MeasureText(" confesses to ", UI_FSIZE), cy + 16, UI_FSIZE, char_palette_color(on.sprite))

    // Timer bar
    bar_w := i32(f32(cw - 40) * (ce.timer / 10.0))
    rl.DrawRectangle(cx + 20, cy + 46, cw - 40, 4, COL_MUTED)
    rl.DrawRectangle(cx + 20, cy + 46, bar_w, 4, rl.Color{255, 130, 180, 255})

    // Buttons
    acc_rect := rl.Rectangle{f32(cx + 60), f32(cy + 70), 140, 44}
    rej_rect := rl.Rectangle{f32(cx + 280), f32(cy + 70), 140, 44}
    hov_acc  := rl.CheckCollisionPointRec(rl.GetMousePosition(), acc_rect)
    hov_rej  := rl.CheckCollisionPointRec(rl.GetMousePosition(), rej_rect)
    rl.DrawRectangleRec(acc_rect, hov_acc ? COL_CONFIRM : rl.Color{40, 120, 70, 255})
    rl.DrawRectangleRec(rej_rect, hov_rej ? COL_ACCENT2 : rl.Color{120, 40, 60, 255})
    rl.DrawText("Accept", cx + 84, cy + 82, UI_FSIZE, COL_TEXT)
    rl.DrawText("Reject", cx + 304, cy + 82, UI_FSIZE, COL_TEXT)

    if (hov_acc && rl.IsMouseButtonPressed(.LEFT)) {
        ce.state = .Resolved; return 1
    }
    if (hov_rej && rl.IsMouseButtonPressed(.LEFT)) {
        ce.state = .Resolved; return 2
    }

    // Auto-resolve after 10 seconds based on target's mood
    if ce.timer <= 0 {
        ce.state = .Resolved
        on_idx := int(on.id - 1)
        // (caller will resolve based on mood — return 0 means timer expired)
        return 0
    }
    return 0
}

confession_resolve :: proc(ce: ^ConfessionEvent, result: int,
                            sim: ^SimState, res: ^Residents,
                            engine: ^EpilogEngine, tick: u64) {
    from := residents_find(res, ce.from_id)
    on   := residents_find(res, ce.on_id)
    if from == nil || on == nil do return

    buf_a, buf_b, src: [256]u8
    atom_a := character_atom(ce.from_id, buf_a[:])
    atom_b := character_atom(ce.on_id,   buf_b[:])

    accepted := result == 1
    if result == 0 {
        // Auto-resolve by mood
        on_idx := int(on.id - 1)
        m := on_idx >= 0 && on_idx < MAX_RESIDENTS ? sim.social[on_idx].mood : Mood.Content
        accepted = m == .Lovestruck || (m == .Content && sim.rng.state & 1 == 0)
    }

    if accepted {
        // Assert partner relationship
        s := fmt.bprintf(src[:], "partner(%s, %s).", atom_a, atom_b)
        src[len(s)] = 0
        epilog_load_string(engine, cstring(raw_data(src[:])))
        s = fmt.bprintf(src[:], "partner(%s, %s).", atom_b, atom_a)
        src[len(s)] = 0
        epilog_load_string(engine, cstring(raw_data(src[:])))

        ia := int(from.id - 1)
        ib := int(on.id - 1)
        if ia >= 0 && ia < MAX_RESIDENTS { sim.social[ia].mood = .Happy }
        if ib >= 0 && ib < MAX_RESIDENTS { sim.social[ib].mood = .Happy }

        msg: [EVENT_MSG_LEN]u8
        ms := fmt.bprintf(msg[:], "%s and %s are now partners",
            character_name(from), character_name(on))
        event_log_push(&sim.log, tick, string(msg[:len(ms)]))
    } else {
        // Retract crush (mark as no crush)
        ia := int(from.id - 1)
        ib := int(on.id - 1)
        if ia >= 0 && ia < MAX_RESIDENTS {
            sim.social[ia].has_crush = false
            sim.social[ia].mood = .Sad
        }
        if ib >= 0 && ib < MAX_RESIDENTS { sim.social[ib].mood = .Content }

        msg: [EVENT_MSG_LEN]u8
        ms := fmt.bprintf(msg[:], "%s was rejected by %s",
            character_name(from), character_name(on))
        event_log_push(&sim.log, tick, string(msg[:len(ms)]))
    }
    ce.state = .None
}

// ============================================================
// 3.3  Rival Confrontation Event
// ============================================================

ConfrontationState :: enum { None, Waiting }

ConfrontationEvent :: struct {
    state    : ConfrontationState,
    char_a   : u32,
    char_b   : u32,
    timer    : f32,
    cooldown : [MAX_RESIDENTS][MAX_RESIDENTS]u64,
}

CONFRONT_DIST     :: 5
CONFRONT_MIN_TICK :: 30

confrontation_tick :: proc(ce: ^ConfrontationEvent, sim: ^SimState,
                            res: ^Residents, engine: ^EpilogEngine, tick: u64) {
    if ce.state == .Waiting do return

    for i in 0..<res.count {
        for j in i+1..<res.count {
            a := &res.chars[i]
            b := &res.chars[j]
            ia := int(a.id - 1)
            ib := int(b.id - 1)
            if ia >= MAX_RESIDENTS || ib >= MAX_RESIDENTS do continue

            // Check cooldown
            if ce.cooldown[ia][ib] + CONFRONT_MIN_TICK > tick do continue

            // Check rivals
            buf_a, buf_b2, goal: [128]u8
            atom_a := character_atom(a.id, buf_a[:])
            atom_b := character_atom(b.id, buf_b2[:])
            gs := fmt.bprintf(goal[:], "rivals(%s, %s)", atom_a, atom_b)
            goal[len(gs)] = 0
            if !_epilog_bool(engine, string(goal[:len(gs)])) do continue

            // Check proximity
            dx := a.position[0] - b.position[0]
            dy := a.position[1] - b.position[1]
            if dx < 0 { dx = -dx }
            if dy < 0 { dy = -dy }
            if dx + dy > CONFRONT_DIST do continue

            // Fire confrontation
            ce.state  = .Waiting
            ce.char_a = a.id
            ce.char_b = b.id
            ce.timer  = 15.0
            ce.cooldown[ia][ib] = tick
            ce.cooldown[ib][ia] = tick

            msg: [EVENT_MSG_LEN]u8
            ms := fmt.bprintf(msg[:], "%s and %s face each other",
                character_name(a), character_name(b))
            event_log_push(&sim.log, tick, string(msg[:len(ms)]))
            return
        }
    }
}

// Returns 0=waiting, 1=let it happen, 2=intervene
confrontation_draw_prompt :: proc(ce: ^ConfrontationEvent,
                                   res: ^Residents, dt: f32) -> int {
    if ce.state != .Waiting do return 0

    ce.timer -= dt
    a := residents_find(res, ce.char_a)
    b := residents_find(res, ce.char_b)
    if a == nil || b == nil { ce.state = .None; return 0 }

    rl.DrawRectangle(0, 0, SW(), SH(), rl.Color{20, 5, 5, 150})

    cw := i32(500)
    ch := i32(140)
    cx := (SW() - cw) / 2
    cy := (SH() - ch) / 2
    rl.DrawRectangle(cx, cy, cw, ch, rl.Color{40, 20, 20, 240})
    rl.DrawRectangleLinesEx(rl.Rectangle{f32(cx), f32(cy), f32(cw), f32(ch)},
                             2, rl.Color{220, 60, 60, 200})

    an := strings.clone_to_cstring(character_name(a), context.temp_allocator)
    bn := strings.clone_to_cstring(character_name(b), context.temp_allocator)
    rl.DrawText(an, cx+20, cy+16, UI_FSIZE, char_palette_color(a.sprite))
    rl.DrawText(" vs ", cx+20+rl.MeasureText(an,UI_FSIZE), cy+16, UI_FSIZE, COL_TEXT)
    rl.DrawText(bn, cx+20+rl.MeasureText(an,UI_FSIZE)+rl.MeasureText(" vs ",UI_FSIZE),
                cy+16, UI_FSIZE, char_palette_color(b.sprite))
    rl.DrawText("Rivals are confronting each other!", cx+20, cy+44, UI_SMALL, COL_MUTED)

    bar_w := i32(f32(cw-40) * (ce.timer/15.0))
    rl.DrawRectangle(cx+20, cy+64, cw-40, 4, COL_MUTED)
    rl.DrawRectangle(cx+20, cy+64, bar_w, 4, rl.Color{220,60,60,255})

    lit_rect := rl.Rectangle{f32(cx+40), f32(cy+80), 160, 40}
    int_rect := rl.Rectangle{f32(cx+300), f32(cy+80), 160, 40}
    hov_l := rl.CheckCollisionPointRec(rl.GetMousePosition(), lit_rect)
    hov_i := rl.CheckCollisionPointRec(rl.GetMousePosition(), int_rect)
    rl.DrawRectangleRec(lit_rect, hov_l ? rl.Color{160,40,40,255} : rl.Color{100,30,30,255})
    rl.DrawRectangleRec(int_rect, hov_i ? COL_ACCENT : COL_SELECT)
    rl.DrawText("Let it happen", cx+50, cy+92, UI_SMALL, COL_TEXT)
    rl.DrawText("Intervene", cx+318, cy+92, UI_SMALL, COL_TEXT)

    if hov_l && rl.IsMouseButtonPressed(.LEFT) { ce.state = .None; return 1 }
    if hov_i && rl.IsMouseButtonPressed(.LEFT) { ce.state = .None; return 2 }
    if ce.timer <= 0                           { ce.state = .None; return 1 }  // auto: let it happen
    return 0
}

confrontation_resolve :: proc(result: int, char_a, char_b: u32,
                               sim: ^SimState, res: ^Residents,
                               engine: ^EpilogEngine, tick: u64) {
    a := residents_find(res, char_a)
    b := residents_find(res, char_b)
    if a == nil || b == nil do return

    ia := int(char_a - 1)
    ib := int(char_b - 1)

    if result == 1 {
        // Let it happen — one dominates
        winner_is_a := sim.rng.state & 1 == 0
        dom_id  := winner_is_a ? char_a : char_b
        sub_idx := winner_is_a ? ib : ia

        buf: [256]u8
        atom := character_atom(dom_id, buf[:])
        s := fmt.bprintf(buf[32:], "dominant_rival(%s).", atom)
        buf[32+len(s)] = 0
        epilog_load_string(engine, cstring(raw_data(buf[32:])))

        if sub_idx >= 0 && sub_idx < MAX_RESIDENTS {
            sim.social[sub_idx].mood = .Sad
        }
        dom_char := residents_find(res, dom_id)
        if dom_char != nil {
            msg: [EVENT_MSG_LEN]u8
            ms := fmt.bprintf(msg[:], "%s emerged dominant from the confrontation",
                character_name(dom_char))
            event_log_push(&sim.log, tick, string(msg[:len(ms)]))
        }
    } else {
        // Intervene — both reset to content, cooldown already set
        if ia >= 0 && ia < MAX_RESIDENTS { sim.social[ia].mood = .Content }
        if ib >= 0 && ib < MAX_RESIDENTS { sim.social[ib].mood = .Content }

        msg: [EVENT_MSG_LEN]u8
        ms := fmt.bprintf(msg[:], "Confrontation between %s and %s was defused",
            character_name(a), character_name(b))
        event_log_push(&sim.log, tick, string(msg[:len(ms)]))
    }
}

// ============================================================
// 3.4  Friendship Decay
// ============================================================
// Track last-interaction tick per pair. Decay friend→acquaintance
// if no interaction in 30 ticks, acquaintance→stranger in 50.

FriendshipDecay :: struct {
    last_interact : [MAX_RESIDENTS][MAX_RESIDENTS]u64,
}

friendship_decay_record :: proc(fd: ^FriendshipDecay, id_a, id_b: u32, tick: u64) {
    ia := int(id_a - 1)
    ib := int(id_b - 1)
    if ia >= MAX_RESIDENTS || ib >= MAX_RESIDENTS do return
    fd.last_interact[ia][ib] = tick
    fd.last_interact[ib][ia] = tick
}

friendship_decay_tick :: proc(fd: ^FriendshipDecay, res: ^Residents,
                               engine: ^EpilogEngine, sim: ^SimState, tick: u64) {
    buf_a, buf_b, src: [256]u8

    for i in 0..<res.count {
        for j in i+1..<res.count {
            a := &res.chars[i]
            b := &res.chars[j]
            ia := int(a.id - 1)
            ib := int(b.id - 1)
            if ia >= MAX_RESIDENTS || ib >= MAX_RESIDENTS do continue

            last := fd.last_interact[ia][ib]
            if last == 0 do continue

            idle := tick - last

            // Query current relationship
            atom_a := character_atom(a.id, buf_a[:])
            atom_b := character_atom(b.id, buf_b[:])

            // Check friend decay (30 ticks idle)
            if idle == 30 {
                gs := fmt.bprintf(src[:], "friend(%s, %s)", atom_a, atom_b)
                src[len(gs)] = 0
                if _epilog_bool(engine, string(src[:len(gs)])) {
                    // Downgrade to acquaintance
                    s := fmt.bprintf(src[:], "acquaintance(%s, %s).", atom_a, atom_b)
                    src[len(s)] = 0
                    epilog_load_string(engine, cstring(raw_data(src[:])))
                    s = fmt.bprintf(src[:], "acquaintance(%s, %s).", atom_b, atom_a)
                    src[len(s)] = 0
                    epilog_load_string(engine, cstring(raw_data(src[:])))

                    msg: [EVENT_MSG_LEN]u8
                    ms := fmt.bprintf(msg[:], "%s and %s drifted apart (friend -> acquaintance)",
                        character_name(a), character_name(b))
                    event_log_push(&sim.log, tick, string(msg[:len(ms)]))
                }
            }

            // Check acquaintance decay (50 ticks idle)
            if idle == 50 {
                gs := fmt.bprintf(src[:], "acquaintance(%s, %s)", atom_a, atom_b)
                src[len(gs)] = 0
                if _epilog_bool(engine, string(src[:len(gs)])) {
                    s := fmt.bprintf(src[:], "stranger(%s, %s).", atom_a, atom_b)
                    src[len(s)] = 0
                    epilog_load_string(engine, cstring(raw_data(src[:])))

                    msg: [EVENT_MSG_LEN]u8
                    ms := fmt.bprintf(msg[:], "%s and %s became strangers (acquaintance -> stranger)",
                        character_name(a), character_name(b))
                    event_log_push(&sim.log, tick, string(msg[:len(ms)]))
                }
            }
        }
    }
}

// ============================================================
// 3.5  Character Backstory Panel
// ============================================================

BackstoryPanel :: struct {
    open        : bool,
    char_id     : u32,
    rel_results : [MAX_REL_RESULTS]RelResult,
    rel_count   : int,
    scroll      : i32,
}

backstory_open :: proc(bp: ^BackstoryPanel, id: u32,
                        res: ^Residents, engine: ^EpilogEngine) {
    bp.open    = true
    bp.char_id = id
    bp.scroll  = 0
    // Reuse _query_relationships from residents.odin via ResidentListScreen helper
    tmp: ResidentListScreen
    tmp.selected_id = id
    _query_relationships(&tmp, id, res, engine)
    bp.rel_count = tmp.rel_count
    for i in 0..<tmp.rel_count {
        bp.rel_results[i] = tmp.rel_results[i]
    }
}

backstory_draw :: proc(bp: ^BackstoryPanel, res: ^Residents,
                        sim: ^SimState, log: ^EventLog) -> bool {
    if !bp.open do return false

    c := residents_find(res, bp.char_id)
    if c == nil { bp.open = false; return false }

    // Close on ESC or click outside
    if rl.IsKeyPressed(.ESCAPE) {
        bp.open = false
        return false
    }

    // Panel dimensions
    pw := i32(340)
    ph := i32(500)
    px := (SW() - pw) / 2
    py := (SH() - ph) / 2

    // Darken background
    rl.DrawRectangle(0, 0, SW(), SH(), rl.Color{0, 0, 0, 140})

    // Click outside closes
    panel_rect := rl.Rectangle{f32(px), f32(py), f32(pw), f32(ph)}
    if rl.IsMouseButtonPressed(.LEFT) &&
       !rl.CheckCollisionPointRec(rl.GetMousePosition(), panel_rect) {
        bp.open = false
        return false
    }

    rl.DrawRectangle(px, py, pw, ph, rl.Color{20, 20, 35, 248})
    rl.DrawRectangleLinesEx(panel_rect, 2, char_palette_color(c.sprite))

    y  := py + 12
    lx := px + 14

    // Name + personality + age
    name_cstr := strings.clone_to_cstring(character_name(c), context.temp_allocator)
    rl.DrawText(name_cstr, lx, y, UI_HSIZE, char_palette_color(c.sprite))
    y += UI_HSIZE + 4

    pers_cstr := strings.clone_to_cstring(personality_label(c.personality), context.temp_allocator)
    age_buf: [32]u8
    age_s := fmt.bprintf(age_buf[:], " · %d", c.age)
    age_buf[len(age_s)] = 0
    rl.DrawText(pers_cstr, lx, y, UI_SMALL, COL_MUTED)
    rl.DrawText(cstring(raw_data(age_buf[:])), lx + rl.MeasureText(pers_cstr, UI_SMALL), y, UI_SMALL, COL_MUTED)
    y += UI_SMALL + 4

    // Divider
    rl.DrawLine(lx, y, px + pw - lx, y, COL_MUTED); y += 10

    // Relationships
    rl.DrawText("RELATIONSHIPS", lx, y, UI_SMALL, COL_ACCENT); y += UI_SMALL + 4
    if bp.rel_count == 0 {
        rl.DrawText("none", lx + 8, y, UI_SMALL, COL_MUTED); y += UI_SMALL + 4
    } else {
        for ri in 0..<bp.rel_count {
            r := &bp.rel_results[ri]
            row_buf: [64]u8
            nr := fmt.bprintf(row_buf[:], "  %s  —  %s", r.other_name, r.tag)
            row_buf[len(nr)] = 0
            rl.DrawText(cstring(raw_data(row_buf[:])), lx, y, UI_SMALL, COL_TEXT)
            y += UI_SMALL + 2
        }
    }
    y += 6

    // Divider
    rl.DrawLine(lx, y, px + pw - lx, y, COL_MUTED); y += 10

    // Mood + interaction count
    ia := int(c.id - 1)
    rl.DrawText("MOOD", lx, y, UI_SMALL, COL_ACCENT); y += UI_SMALL + 2
    if ia >= 0 && ia < MAX_RESIDENTS {
        mood_cstr := strings.clone_to_cstring(mood_label(sim.social[ia].mood), context.temp_allocator)
        rl.DrawText(mood_cstr, lx + 8, y, UI_FSIZE, COL_TEXT)
    }
    y += UI_FSIZE + 6

    // Divider
    rl.DrawLine(lx, y, px + pw - lx, y, COL_MUTED); y += 10

    // Last 5 events mentioning this character
    rl.DrawText("RECENT EVENTS", lx, y, UI_SMALL, COL_ACCENT); y += UI_SMALL + 4
    name_str := character_name(c)
    shown := 0
    for ei in 0..<log.count {
        if shown >= 5 do break
        e := event_log_get(log, ei)
        if e == nil do continue
        msg := event_entry_str(e)
        if strings.contains(msg, name_str) {
            trunc := msg
            if len(trunc) > 38 { trunc = trunc[:38] }
            msg_cstr := strings.clone_to_cstring(trunc, context.temp_allocator)
            rl.DrawText(msg_cstr, lx + 4, y, UI_SMALL - 2, COL_TEXT)
            y += UI_SMALL
            shown += 1
        }
    }
    if shown == 0 {
        rl.DrawText("none yet", lx + 4, y, UI_SMALL, COL_MUTED)
        y += UI_SMALL
    }

    // Close hint
    rl.DrawText("[ESC] to close", lx, py + ph - 20, UI_SMALL - 2, COL_MUTED)

    return true
}

/*
 * world.odin — World seed system and character placement / wandering (M3).
 */

package dmls

import "core:fmt"

// ---- World -----------------------------------------------------------------

World :: struct {
    seed        : u64,
    grid        : Grid,
    rng         : u64,              // LCG state for placement/wandering
    tick        : u64,
    // Per-character position cache (mirrors grid occupant)
    positions   : [MAX_RESIDENTS][2]i32,    // [id-1] = {col, row}
}

world_init :: proc(w: ^World, seed: u64) {
    w.seed = seed
    w.rng  = seed
    w.tick = 0
    grid_generate(&w.grid, seed)
    landmarks_place(&w.grid, seed)
}

// Spawn a newly created character onto the grid.
world_spawn_character :: proc(w: ^World, res: ^Residents, id: u32) -> bool {
    c := residents_find(res, id)
    if c == nil do return false

    col, row, ok := grid_find_spawn(&w.grid, &w.rng)
    if !ok do return false

    if !grid_place_character(&w.grid, id, col, row) do return false

    c.position = {col, row}
    idx := id - 1
    if int(idx) < MAX_RESIDENTS {
        w.positions[idx] = {col, row}
    }
    return true
}

// One wander step per character — moves to a random adjacent walkable cell.
world_tick_wander :: proc(w: ^World, res: ^Residents) {
    dx := [4]i32{0, 0, 1, -1}
    dy := [4]i32{1, -1, 0, 0}

    for i in 0..<res.count {
        c   := &res.chars[i]
        col := c.position[0]
        row := c.position[1]

        // Pick a random direction
        w.rng = w.rng * 6364136223846793005 + 1442695040888963407
        dir  := int((w.rng >> 33) % 4)

        nc := col + dx[dir]

/*
 * screen_cfg.odin — Runtime screen resolution configuration.
 *
 * Three supported resolutions: 640×320, 1920×720, 1920×1080.
 * The player picks one on the title screen before generating the world.
 *
 * SCREEN_W / SCREEN_H compile-time constants remain as the maximum dimensions
 * (1920×1080) used only for RenderTexture allocation and rl.InitWindow.
 * All rendering code reads SW() / SH() for the active dimensions.
 *
 * Derived layout values (stats panel split, sim panel dimensions) are also
 * exposed as procs so they react to resolution changes automatically.
 */

package dmls

import rl "vendor:raylib"

// ---- Resolution enum -------------------------------------------------------

ScreenSize :: enum {
    S_640x320,
    S_1920x720,
    S_1920x1080,
}

SCREEN_SIZE_LABELS := [ScreenSize]cstring{
    .S_640x320   = "640 × 320  (Compact)",
    .S_1920x720  = "1920 × 720  (Wide)",
    .S_1920x1080 = "1920 × 1080  (Full HD)",
}

SCREEN_SIZE_W := [ScreenSize]i32{
    .S_640x320   = 640,
    .S_1920x720  = 1920,
    .S_1920x1080 = 1920,
}

SCREEN_SIZE_H := [ScreenSize]i32{
    .S_640x320   = 320,
    .S_1920x720  = 720,
    .S_1920x1080 = 1080,
}

// ---- Active screen state (global) -----------------------------------------

ScreenCfg :: struct {
    w    : i32,
    h    : i32,
    size : ScreenSize,
}

g_screen : ScreenCfg

screen_cfg_set :: proc(sz: ScreenSize) {
    g_screen.size = sz
    g_screen.w    = SCREEN_SIZE_W[sz]
    g_screen.h    = SCREEN_SIZE_H[sz]
    rl.SetWindowSize(g_screen.w, g_screen.h)
}

// Convenience accessors used everywhere in rendering code.
SW :: #force_inline proc() -> i32 { return g_screen.w }
SH :: #force_inline proc() -> i32 { return g_screen.h }

// Derived layout values — 80 / 20 split: left 80% = grid sim, right 20% = sidebar.
// sim_w / sim_h = the grid viewport dimensions.
// stat_w / stat_h = the sidebar dimensions.
// stats_x = x pixel where the sidebar begins (= sim_w).
sim_w   :: #force_inline proc() -> i32 { return SW() * 80 / 100 }
sim_h   :: #force_inline proc() -> i32 { return SH() }
stats_x :: #force_inline proc() -> i32 { return sim_w() }
stat_w  :: #force_inline proc() -> i32 { return SW() - sim_w() }
stat_h  :: #force_inline proc() -> i32 { return SH() }

// Dynamic cell pixel size: fit as many cells as possible into the sim viewport.
// Result is at least 1.
render_cell_px :: #force_inline proc() -> i32 {
    px := sim_w() / GRID_W
    if px < 1 { px = 1 }
    return px
}

// ---- Character colour palette (8 distinct colours, indexed by sprite) ------
//
// Each of the 8 sprite slots has a fixed canonical colour.
// Starter characters are assigned slots 0–3 matching their canonical look.
//   0 = [NAME] — warm amber / gold
//   1 = Uriel     — soft sky blue
//   2 = Anna Croft — vivid coral red
//   3 = Saloni    — peach / warm orange
//   4–7           — available for player-created characters

CHAR_PALETTE := [SPRITE_COUNT]rl.Color{
    rl.Color{230, 180,  60, 255},  // 0 [NAME]  — amber gold
    rl.Color{ 80, 180, 230, 255},  // 1 Uriel       — sky blue
    rl.Color{220,  70,  70, 255},  // 2 Anna Croft  — coral red
    rl.Color{240, 150,  80, 255},  // 3 Saloni      — warm peach
    rl.Color{100, 210, 140, 255},  // 4              — mint green
    rl.Color{170,  90, 220, 255},  // 5              — violet
    rl.Color{220, 210,  80, 255},  // 6              — yellow
    rl.Color{180, 180, 200, 255},  // 7              — silver
}

char_palette_color :: proc(sprite: u32) -> rl.Color {
    idx := int(sprite) % SPRITE_COUNT
    return CHAR_PALETTE[idx]
}

// ---- Resolution picker UI --------------------------------------------------
// Drawn on the title screen before island naming.
// Returns true when the player has confirmed a choice.

ResolutionPicker :: struct {
    chosen   : ScreenSize,
    confirmed: bool,
}

resolution_picker_init :: proc(p: ^ResolutionPicker) {
    p.chosen    = .S_1920x1080
    p.confirmed = false
}

// Draw and handle input. Returns true once confirmed.
resolution_picker_update :: proc(p: ^ResolutionPicker) -> bool {
    rl.ClearBackground(COL_BG)

    cy := SH() / 2 - 120
    rl.DrawText("Choose resolution", UI_LPAD, cy - 40, UI_HSIZE, COL_TEXT)

    for sz in ScreenSize {
        label := SCREEN_SIZE_LABELS[sz]
        sel   := p.chosen == sz
        rect  := rl.Rectangle{f32(UI_LPAD), f32(cy), 400, 44}
        bg    := sel ? COL_SELECT : COL_INPUT
        hov   := rl.CheckCollisionPointRec(rl.GetMousePosition(), rect)
        if hov { bg = sel ? COL_ACCENT : COL_HOVER }
        rl.DrawRectangleRec(rect, bg)
        rl.DrawRectangleLinesEx(rect, 1, sel ? COL_ACCENT : COL_MUTED)
        rl.DrawText(label, UI_LPAD + 14, cy + 12, UI_FSIZE, COL_TEXT)
        if hov && rl.IsMouseButtonPressed(.LEFT) {
            p.chosen = sz
        }
        cy += 54
    }

    cy += 10
    ok_rect := rl.Rectangle{f32(UI_LPAD), f32(cy), 200, 44}
    hov_ok  := rl.CheckCollisionPointRec(rl.GetMousePosition(), ok_rect)
    rl.DrawRectangleRec(ok_rect, hov_ok ? COL_ACCENT : COL_SELECT)
    rl.DrawText("Confirm ->", UI_LPAD + 16, cy + 12, UI_FSIZE, COL_TEXT)

    if (hov_ok && rl.IsMouseButtonPressed(.LEFT)) || rl.IsKeyPressed(.ENTER) {
        screen_cfg_set(p.chosen)
        p.confirmed = true
        return true
    }
    return false
}

