}

shared_set_quit :: proc() {
    sync.lock(&g_shared.mu)
    g_shared.quit_req = true
    sync.unlock(&g_shared.mu)
}

shared_set_save :: proc() {
    sync.lock(&g_shared.mu)
    g_shared.save_req = true
    sync.unlock(&g_shared.mu)
}

shared_poll_controls :: proc() -> (speed_req: int, quit: bool, save: bool) {
    sync.lock(&g_shared.mu)
    speed_req = g_shared.speed_req
    quit      = g_shared.quit_req
    save      = g_shared.save_req
    g_shared.speed_req = -1
    g_shared.quit_req  = false
    g_shared.save_req  = false
    sync.unlock(&g_shared.mu)
    return
}

// Prompt state
shared_set_prompt :: proc(id, kind, from, to: string, tick: u64) {
    sync.lock(&g_shared.mu)
    _snap_str(g_shared.prompt_id[:],   id)
