    } else {
        frame[1] = 127
        frame[2] = 0; frame[3] = 0; frame[4] = 0; frame[5] = 0
        frame[6] = u8((plen >> 24) & 0xFF)
        frame[7] = u8((plen >> 16) & 0xFF)
