    parts := strings.fields(lines[0], context.temp_allocator)
    if len(parts) < 2 do return {}, false

    switch parts[0] {
    case "GET":    req.method = .GET
    case "POST":   req.method = .POST
    case "DELETE": req.method = .DELETE
    case:          req.method = .UNKNOWN
    }

    full_path := parts[1]
    if qi := strings.index(full_path, "?"); qi >= 0 {
        req.path  = strings.clone(full_path[:qi], context.temp_allocator)
        req.query = strings.clone(full_path[qi+1:], context.temp_allocator)
    } else {
        req.path  = strings.clone(full_path, context.temp_allocator)
        req.query = ""
    }

