        "HTTP/1.1 101 Switching Protocols\r\n" +
        "Upgrade: websocket\r\n" +
        "Connection: Upgrade\r\n" +
        "Sec-WebSocket-Accept: %s\r\n\r\n", b64)

    _, err := net.send_tcp(sock, transmute([]u8)resp)
    return err == nil
}

// ---- Read a WebSocket frame from a connected client -----------------------
// Returns the payload or "" on close/error; sets *closed=true on close.
ws_read_frame :: proc(sock: net.TCP_Socket) -> (payload: string, closed: bool) {
    hdr: [2]u8
    _, err := net.recv_tcp(sock, hdr[:])
    if err != nil do return "", true

    opcode := hdr[0] & 0x0F
    masked  := (hdr[1] & 0x80) != 0
    plen    := int(hdr[1] & 0x7F)

    if opcode == 8 do return "", true   // close frame

    if plen == 126 {
        ext: [2]u8
        net.recv_tcp(sock, ext[:])
        plen = int(ext[0]) << 8 | int(ext[1])
    } else if plen == 127 {
        ext: [8]u8
        net.recv_tcp(sock, ext[:])
        plen = int(ext[4]) << 24 | int(ext[5]) << 16 | int(ext[6]) << 8 | int(ext[7])
    }

    mask: [4]u8
    if masked {
        net.recv_tcp(sock, mask[:])
    }

    if plen == 0 do return "", false

    buf := make([]u8, plen, context.temp_allocator)
    total := 0
    for total < plen {
        n, e := net.recv_tcp(sock, buf[total:])
        if e != nil || n == 0 { return "", true }
        total += n
    }

    if masked {
        for i in 0..<plen { buf[i] ~= mask[i % 4] }
    }

    return string(buf[:plen]), false
}

// ---- HTTP response helpers -------------------------------------------------

http_ok :: proc(body: string, ctype: string = "application/json") -> HttpResponse {
    return HttpResponse{status = 200, content = body, ctype = ctype}
}

http_err :: proc(code: int, body: string) -> HttpResponse {
    return HttpResponse{status = code, content = body, ctype = "application/json"}
}

http_send :: proc(sock: net.TCP_Socket, resp: HttpResponse) {
    hdr_buf: [512]u8
    hdr := fmt.bprintf(hdr_buf[:],
        "HTTP/1.1 %d OK\r\n" +
        "Content-Type: %s; charset=utf-8\r\n" +
        "Content-Length: %d\r\n" +
        "Access-Control-Allow-Origin: *\r\n" +
        "Connection: close\r\n\r\n",
        resp.status, resp.ctype, len(resp.content))

    combined := strings.concatenate({hdr, resp.content}, context.temp_allocator)
    net.send_tcp(sock, transmute([]u8)combined)
}

// ---- HTTP listener loop ----------------------------------------------------

HttpServer :: struct {
    port    : int,
    running : bool,
    sock    : net.TCP_Socket,
}

ConnCtx :: struct {
    sock    : net.TCP_Socket,
    handler : proc(req: HttpRequest, sock: net.TCP_Socket),
}

_conn_thread :: proc(data: rawptr) {
    ctx := cast(^ConnCtx)data
    defer {
        net.close(ctx.sock)
        free(ctx)
    }
    free_all(context.temp_allocator)
    defer free_all(context.temp_allocator)

    // Read incoming data (up to 8KB)
    buf   := [8192]u8{}
    total := 0
    for {
        n, err := net.recv_tcp(ctx.sock, buf[total:])
        if err != nil || n == 0 do break
        total += n
        // Check if we have a complete header
        if bytes.contains(buf[:total], []u8{'\r','\n','\r','\n'}) do break
        if total >= len(buf) do break
    }
    if total == 0 do return

    req, ok := _parse_request(buf[:total])
    if !ok do return

    ctx.handler(req, ctx.sock)
}

http_server_run :: proc(port: int, handler: proc(req: HttpRequest, sock: net.TCP_Socket)) {
    ep := net.Endpoint{
        address = net.IP4_Address{0,0,0,0},
        port    = port,
    }
    sock, err := net.listen_tcp(ep)
    if err != nil {
        fmt.println("[api] Failed to bind port", port, ":", err)
        return
    }
    defer net.close(sock)
    fmt.println("[api] Listening on http://localhost:", port)

    for {
        client, _, aerr := net.accept_tcp(sock)
        if aerr != nil do break

        ctx := new(ConnCtx)
        ctx.sock    = client
        ctx.handler = handler
        t := thread.create_and_start_with_data(ctx, _conn_thread)
        thread.destroy(t)
    }
}

