/*
 * headless.odin — Headless simulation loop + CLI/config parsing.
 *
 * Usage:
 *   dmls --headless
 *   dmls --headless --load save.dmls
 *   dmls --headless --seed 5961641267136C
 *   dmls --port 7772
 *
 * dmls.cfg (all optional):
 *   port     = 7771
 *   headless = false
 *   speed    = 1
 *   save     = autosave.dmls
 *   seed     = 0
 */

package dmls

import "core:fmt"
import "core:os"
import "core:strings"
import "core:strconv"
import "core:time"
import "core:sync"

// ---- Config ----------------------------------------------------------------

DMLSConfig :: struct {
    port     : int,
    headless : bool,
    speed    : int,    // 0/1/4/16
    save     : string,
    seed     : u64,
    load     : string,
}

default_config :: proc() -> DMLSConfig {
    return DMLSConfig{
        port     = 7771,
        headless = false,
        speed    = 1,
        save     = "dmls_save.bin",
        seed     = 0,
        load     = "",
    }
}

parse_config :: proc() -> DMLSConfig {
    cfg := default_config()
    _read_cfg_file(&cfg, "dmls.cfg")
    _apply_cli_flags(&cfg)
    return cfg
}

_read_cfg_file :: proc(cfg: ^DMLSConfig, path: string) {
    data, ok := os.read_entire_file(path)
    if !ok do return
    defer delete(data)

    for line in strings.split_lines_iterator(&strings.clone(string(data), context.temp_allocator)) {
        line_t := strings.trim_space(line)
        if len(line_t) == 0 || line_t[0] == ';' || line_t[0] == '#' do continue
        ei := strings.index(line_t, "=")
        if ei < 0 do continue
        k := strings.trim_space(line_t[:ei])
        v := strings.trim_space(line_t[ei+1:])
        // Strip inline comment
        if ci := strings.index(v, ";"); ci >= 0 { v = strings.trim_space(v[:ci]) }

        switch k {
        case "port":
            if n, ok2 := strconv.parse_int(v); ok2 { cfg.port = n }
        case "headless":
            cfg.headless = v == "true" || v == "1"
        case "speed":
            if n, ok2 := strconv.parse_int(v); ok2 { cfg.speed = n }
        case "save":
            cfg.save = strings.clone(v, context.allocator)
        case "seed":
            if s, ok2 := _parse_seed(v); ok2 { cfg.seed = s }
        }
    }
}

_apply_cli_flags :: proc(cfg: ^DMLSConfig) {
    args := os.args
    i := 1
    for i < len(args) {
        arg := args[i]
        switch arg {
        case "--headless":
            cfg.headless = true
        case "--port":
            if i + 1 < len(args) {
                i += 1
                if n, ok := strconv.parse_int(args[i]); ok { cfg.port = n }
            }
        case "--speed":
            if i + 1 < len(args) {
                i += 1
                if n, ok := strconv.parse_int(args[i]); ok { cfg.speed = n }
            }
        case "--seed":
            if i + 1 < len(args) {
                i += 1
                if s, ok := _parse_seed(args[i]); ok { cfg.seed = s }
            }
        case "--load":
            if i + 1 < len(args) {
                i += 1
                cfg.load = args[i]
            }
        case "--save":
            if i + 1 < len(args) {
                i += 1
                cfg.save = args[i]
            }
        }
        i += 1
    }
}

// Speed value → index
_speed_val_to_idx :: proc(v: int) -> int {
    switch v {
    case 0:  return 0
    case 1:  return 1
    case 4:  return 2
    case 16: return 3
    }
    return 1
}

// ---- Headless tick loop ----------------------------------------------------

headless_run :: proc(cfg: ^DMLSConfig) {
    fmt.println("[dmls] Headless mode")

    engine := epilog_create()
    defer epilog_destroy(engine)

    world     := World{}
    residents := Residents{}
    sim       := SimState{}
    island    := IslandName{}
    weather   := WeatherState{}
    decay     := FriendshipDecay{}

    residents_init(&residents)
    g_decay = &decay

    // Load rules
    starter_load_rules(engine)

    // Load save or generate world
    loaded := false
    if len(cfg.load) > 0 {
        ok := load_game(cfg.load, &world, &residents, &sim, engine, &island)
        if ok {
            fmt.println("[dmls] Loaded:", cfg.load)
            loaded = true
        } else {
            fmt.println("[dmls] Failed to load:", cfg.load, "— generating fresh world")
        }
    }

    if !loaded {
        seed := cfg.seed
        if seed == 0 {
            // Use a quick entropy source
            t := u64(time.now()._nsec)
            t ~= t << 13; t ~= t >> 7; t ~= t << 17
            seed = t
        }
        world_init(&world, seed)
        sim_init(&sim, seed)
        weather_init(&weather)
        starters_seed(&residents, &world, engine)
        fmt.printf("[dmls] World seed: %016X\n", seed)
    }

    speed_idx := _speed_val_to_idx(cfg.speed)

    // Initialise shared snapshot
    {
        sp := new(SimSnapshot, context.temp_allocator)
        sp^ = snapshot_build(&world, &residents, &sim, &island, &weather, speed_idx, true, engine)
        shared_push_snapshot(sp)
        free_all(context.temp_allocator)
    }

    // Init shared control
    sync.lock(&g_shared.mu)
    g_shared.speed_req = -1
    sync.unlock(&g_shared.mu)

    fmt.println("[dmls] Running. Ctrl+C to quit.")

    for {
        // Poll control requests from API thread
        speed_req, quit, save := shared_poll_controls()
        if quit {
            fmt.println("[dmls] Quit requested")
            _save_headless(&world, &residents, &sim, engine, &island, cfg.save)
            break
        }
        if save {
            _save_headless(&world, &residents, &sim, engine, &island, cfg.save)
        }
        if speed_req >= 0 {
            speed_idx = speed_req
        }

        // Poll resident add/remove requests
        if req_kind, req_name, req_body, req_pending := shared_poll_res_req(); req_pending {
            if req_kind == 0 {
                _headless_add_resident(&world, &residents, engine, req_name, req_body)
            } else {
                _headless_remove_resident(&world, &residents, engine, req_name, &sim)
            }
        }

        // Tick if not paused
        _SPEED_HZ := [4]f32{0, 1.0, 4.0, 16.0}
        hz := _SPEED_HZ[speed_idx]
        if hz > 0 {
            interval := time.Duration(1e9 / f64(hz))
            world_tick_wander(&world, &residents)
            sim_tick(&sim, &residents, engine, world.tick)
            weather_tick(&weather, &sim.rng)
            friendship_decay_tick(&decay, &residents, engine, &sim, world.tick)

            // Auto-save every 60 ticks
            if world.tick % 60 == 0 && world.tick > 0 {
                _save_headless(&world, &residents, &sim, engine, &island, cfg.save)
            }

            // Push snapshot to API thread (heap-alloc to keep off stack)
            snap_ptr := new(SimSnapshot, context.temp_allocator)
            snap_ptr^ = snapshot_build(&world, &residents, &sim, &island, &weather, speed_idx, true, engine)
            shared_push_snapshot(snap_ptr)
            api_push_tick(snap_ptr^)
            free_all(context.temp_allocator)

            time.sleep(interval)
        } else {
            // Paused — just keep broadcasting (slowly)
            time.sleep(100 * time.Millisecond)
            snap = snapshot_build(&world, &residents, &sim, &island, &weather, speed_idx, true, engine)
            shared_push_snapshot(snap)
        }
    }
}

_save_headless :: proc(world: ^World, res: ^Residents, sim: ^SimState,
                        engine: ^EpilogEngine, iname: ^IslandName, path: string) {
    ok := save_game(path, world, res, sim, engine, iname)
    if ok {
        fmt.println("[dmls] Saved to", path)
    } else {
        fmt.println("[dmls] Save failed:", path)
    }
}

_headless_add_resident :: proc(world: ^World, res: ^Residents,
                                engine: ^EpilogEngine, name, body: string) {
    if res.count >= MAX_RESIDENTS do return
    // Build a minimal character from the name; full field parsing deferred.
    c := Character{}
    n := min(len(name), MAX_NAME_LEN - 1)
    copy(c.name[:], name[:n])
    c.name[n] = 0
    c.sprite   = res.count % 8
    c.personality = .Ambitious_Achiever

    id := residents_add(res, c)
    epilog_assert_character(engine, residents_find(res, id))
    world_spawn_character(world, res, id)
    fmt.println("[dmls] Added resident:", name)
}

_headless_remove_resident :: proc(world: ^World, res: ^Residents,
                                   engine: ^EpilogEngine, name: string,
                                   sim: ^SimState) {
    if res.count <= 1 {
        fmt.println("[dmls] Cannot remove last resident")
        return
    }
    for i in 0..<res.count {
        c := &res.chars[i]
        if character_name(c) == name {
            // Clear from grid
            grid_remove_character(&world.grid, c.id)
            // Compact residents slice
            res.chars[i] = res.chars[res.count - 1]
            res.count -= 1
            fmt.println("[dmls] Removed resident:", name)
            return
        }
    }
    fmt.println("[dmls] Resident not found:", name)
}

