        rs := &snap.residents[i]
        fmt.sbprintf(&b, `{"name":"%s","position":[%d,%d]}`,
            _snap_cstr(rs.name[:]), rs.position[0], rs.position[1])
    }
    strings.write_string(&b, "]}")
    ws_broadcast(strings.to_string(b))
}

_ws_emit_event :: proc(e: EventSnap) {
    b := strings.builder_make(context.temp_allocator)
    desc := _snap_cstr(e.description[:])
    kind := _snap_cstr(e.kind[:])
    fmt.sbprintf(&b, `{"type":"event","tick":%d,"kind":"%s","description":"%s","characters":[]}`,
        e.tick, kind, _json_escape(desc, context.temp_allocator))
    ws_broadcast(strings.to_string(b))
}

_ws_emit_prompt_if_active :: proc() {
    sync.lock(&g_shared.mu)
    active := g_shared.prompt_active
    pid    := strings.truncate_to_byte(string(g_shared.prompt_id[:]),   0)
    kind   := strings.truncate_to_byte(string(g_shared.prompt_kind[:]), 0)
    from   := strings.truncate_to_byte(string(g_shared.prompt_from[:]), 0)
    to     := strings.truncate_to_byte(string(g_shared.prompt_to[:]),   0)
    tick   := g_shared.prompt_tick
    sync.unlock(&g_shared.mu)

    if !active do return

    b := strings.builder_make(context.temp_allocator)
    fmt.sbprintf(&b,
        `{"type":"prompt","prompt_id":"%s","kind":"%s","from":"%s","to":"%s","tick":%d,"auto_resolve_in_ticks":10,"options":["accept","reject"]}`,
        pid, kind, from, to, tick)
    ws_broadcast(strings.to_string(b))
}

// ---- Start API (call once from main before the main loop) ------------------

api_thread_start :: proc(port: int) {
    g_api_server.port    = port
    g_api_server.running = true

    // HTTP listener thread
    http_t := thread.create_and_start_with_data(nil, proc(data: rawptr) {
        http_server_run(g_api_server.port, api_dispatch)
    })
    thread.destroy(http_t)

