/*
 * api_http.odin — Minimal HTTP/1.1 + WebSocket server over TCP.
 *
 * Uses core:net for raw TCP sockets. Handles:
 *   - HTTP GET / POST (body up to 8KB)
 *   - WebSocket upgrade (RFC 6455, text frames only)
 *   - One goroutine per accepted connection
 *
 * Single listener thread blocks on accept(); each accepted socket is handed
 * off to a new thread.  WebSocket connections self-register into WsHub.
 */

package dmls

import "core:net"
import "core:thread"
import "core:sync"
import "core:fmt"
import "core:strings"
import "core:strconv"
import "core:encoding/base64"
import sha1 "core:crypto/legacy/sha1"
import "core:bytes"

// ---- HTTP types ------------------------------------------------------------

HttpMethod :: enum { GET, POST, DELETE, UNKNOWN }

HttpRequest :: struct {
    method      : HttpMethod,
    path        : string,      // allocated from req arena
    query       : string,      // raw query string after '?'
    body        : string,      // request body (if any)
    is_ws_upgrade: bool,
    ws_key      : string,
}

HttpResponse :: struct {
    status  : int,
    content : string,
    ctype   : string,       // "application/json" | "text/html"
}

// ---- WebSocket hub ---------------------------------------------------------

MAX_WS_CONNS :: 32

WsConn :: struct {
    sock   : net.TCP_Socket,
    alive  : bool,
}

WsHub :: struct {
    mu      : sync.Mutex,
    conns   : [MAX_WS_CONNS]WsConn,
    count   : int,
}

g_ws_hub : WsHub

ws_hub_add :: proc(s: net.TCP_Socket) {
    sync.lock(&g_ws_hub.mu)
    defer sync.unlock(&g_ws_hub.mu)
    // Reuse dead slot
    for i in 0..<MAX_WS_CONNS {
        if !g_ws_hub.conns[i].alive {
            g_ws_hub.conns[i] = WsConn{sock = s, alive = true}
            if i >= g_ws_hub.count { g_ws_hub.count = i + 1 }
            return
        }
    }
}

ws_hub_remove :: proc(s: net.TCP_Socket) {
    sync.lock(&g_ws_hub.mu)
    defer sync.unlock(&g_ws_hub.mu)
    for i in 0..<g_ws_hub.count {
        if g_ws_hub.conns[i].sock == s {
            g_ws_hub.conns[i].alive = false
            return
        }
    }
}

// Broadcast a text message to all alive WS connections.
ws_broadcast :: proc(msg: string) {
    frame := ws_make_frame(msg)
    defer delete(frame)

    sync.lock(&g_ws_hub.mu)
    count := g_ws_hub.count
    socks := g_ws_hub.conns  // copy so we can unlock before send
    sync.unlock(&g_ws_hub.mu)

    for i in 0..<count {
        if !socks[i].alive do continue
        _, err := net.send_tcp(socks[i].sock, frame)
        if err != nil {
            ws_hub_remove(socks[i].sock)
            net.close(socks[i].sock)
        }
    }
}

// Build a WebSocket text frame (no masking — server→client is unmasked).
ws_make_frame :: proc(payload: string) -> []u8 {
    plen := len(payload)
    header_size := 2
    if plen > 65535 { header_size = 10 }
    else if plen > 125 { header_size = 4 }

    frame := make([]u8, header_size + plen)
    frame[0] = 0x81  // FIN=1, opcode=text(1)

    if plen <= 125 {
        frame[1] = u8(plen)
        copy(frame[2:], payload)
    } else if plen <= 65535 {
        frame[1] = 126
        frame[2] = u8(plen >> 8)
        frame[3] = u8(plen & 0xFF)
        copy(frame[4:], payload)
    } else {
        frame[1] = 127
        frame[2] = 0; frame[3] = 0; frame[4] = 0; frame[5] = 0
        frame[6] = u8((plen >> 24) & 0xFF)
        frame[7] = u8((plen >> 16) & 0xFF)
        frame[8] = u8((plen >>  8) & 0xFF)
        frame[9] = u8(plen & 0xFF)
        copy(frame[10:], payload)
    }
    return frame
}

// ---- HTTP parsing ----------------------------------------------------------

_parse_request :: proc(raw: []u8) -> (req: HttpRequest, ok: bool) {
    s := string(raw)

    // Find header/body split
    split := strings.index(s, "\r\n\r\n")
    if split < 0 do return {}, false
    headers_str := s[:split]
    body_str    := s[split+4:]

    lines := strings.split_lines(headers_str, context.temp_allocator)
    if len(lines) == 0 do return {}, false

    // Request line
    parts := strings.fields(lines[0], context.temp_allocator)
    if len(parts) < 2 do return {}, false

    switch parts[0] {
    case "GET":    req.method = .GET
    case "POST":   req.method = .POST
    case "DELETE": req.method = .DELETE
    case:          req.method = .UNKNOWN
    }

    full_path := parts[1]
    // Trim any trailing \r from the path (CRLF request lines)
    full_path = strings.trim_right(full_path, "\r")
    if qi := strings.index(full_path, "?"); qi >= 0 {
        req.path  = strings.clone(full_path[:qi], context.temp_allocator)
        req.query = strings.clone(full_path[qi+1:], context.temp_allocator)
    } else {
        req.path  = strings.clone(full_path, context.temp_allocator)
        req.query = ""
    }

    // Headers
    for i in 1..<len(lines) {
        ln := lines[i]
        ci := strings.index(ln, ":")
        if ci < 0 do continue
        key := strings.to_lower(strings.trim_space(ln[:ci]), context.temp_allocator)
        val := strings.trim_space(ln[ci+1:])
        switch key {
        case "upgrade":
            if strings.to_lower(val, context.temp_allocator) == "websocket" {
                req.is_ws_upgrade = true
            }
        case "sec-websocket-key":
            req.ws_key = strings.clone(val, context.temp_allocator)
        }
    }

    req.body = body_str
    return req, true
}

// ---- WebSocket handshake ---------------------------------------------------

WS_MAGIC :: "258EAFA5-E914-47DA-95CA-C5AB0DC85B11"

ws_handshake :: proc(sock: net.TCP_Socket, key: string) -> bool {
    // SHA1(key + magic) then base64
    concat := strings.concatenate({key, WS_MAGIC}, context.temp_allocator)

    sha: sha1.Context
    sha1.init(&sha)
    sha1.update(&sha, transmute([]u8)concat)
    digest: [20]u8
    sha1.final(&sha, digest[:])

    b64 := base64.encode(digest[:], base64.ENC_TABLE, context.temp_allocator)

    resp_buf: [512]u8
    resp := fmt.bprintf(resp_buf[:],
        "HTTP/1.1 101 Switching Protocols\r\n" +
        "Upgrade: websocket\r\n" +
        "Connection: Upgrade\r\n" +
        "Sec-WebSocket-Accept: %s\r\n\r\n", b64)

    _, err := net.send_tcp(sock, transmute([]u8)resp)
    return err == nil
}

// ---- Read a WebSocket frame from a connected client -----------------------
// Returns the payload or "" on close/error; sets *closed=true on close.
ws_read_frame :: proc(sock: net.TCP_Socket) -> (payload: string, closed: bool) {
    hdr: [2]u8
    _, err := net.recv_tcp(sock, hdr[:])
    if err != nil do return "", true

    opcode := hdr[0] & 0x0F
    masked  := (hdr[1] & 0x80) != 0
    plen    := int(hdr[1] & 0x7F)

    if opcode == 8 do return "", true   // close frame

    if plen == 126 {
        ext: [2]u8
        net.recv_tcp(sock, ext[:])
        plen = int(ext[0]) << 8 | int(ext[1])
    } else if plen == 127 {
        ext: [8]u8
        net.recv_tcp(sock, ext[:])
        plen = int(ext[4]) << 24 | int(ext[5]) << 16 | int(ext[6]) << 8 | int(ext[7])
    }

    mask: [4]u8
    if masked {
        net.recv_tcp(sock, mask[:])
    }

    if plen == 0 do return "", false

    buf := make([]u8, plen, context.temp_allocator)
    total := 0
    for total < plen {
        n, e := net.recv_tcp(sock, buf[total:])
        if e != nil || n == 0 { return "", true }
        total += n
    }

    if masked {
        for i in 0..<plen { buf[i] ~= mask[i % 4] }
    }

    return string(buf[:plen]), false
}

// ---- HTTP response helpers -------------------------------------------------

http_ok :: proc(body: string, ctype: string = "application/json") -> HttpResponse {
    return HttpResponse{status = 200, content = body, ctype = ctype}
}

http_err :: proc(code: int, body: string) -> HttpResponse {
    return HttpResponse{status = code, content = body, ctype = "application/json"}
}

http_send :: proc(sock: net.TCP_Socket, resp: HttpResponse) {
    hdr_buf: [512]u8
    hdr := fmt.bprintf(hdr_buf[:],
        "HTTP/1.1 %d OK\r\n" +
        "Content-Type: %s; charset=utf-8\r\n" +
        "Content-Length: %d\r\n" +
        "Access-Control-Allow-Origin: *\r\n" +
        "Connection: close\r\n\r\n",
        resp.status, resp.ctype, len(resp.content))

    combined := strings.concatenate({hdr, resp.content}, context.temp_allocator)
    net.send_tcp(sock, transmute([]u8)combined)
}

// ---- HTTP listener loop ----------------------------------------------------

HttpServer :: struct {
    port    : int,
    running : bool,
    sock    : net.TCP_Socket,
}

ConnCtx :: struct {
    sock    : net.TCP_Socket,
    handler : proc(req: HttpRequest, sock: net.TCP_Socket),
}

_conn_thread :: proc(data: rawptr) {
    ctx := cast(^ConnCtx)data
    defer {
        net.close(ctx.sock)
        free(ctx)
    }
    free_all(context.temp_allocator)
    defer free_all(context.temp_allocator)

    // Read incoming data (up to 8KB)
    buf   := [8192]u8{}
    total := 0
    for {
        n, err := net.recv_tcp(ctx.sock, buf[total:])
        if err != nil || n == 0 do break
        total += n
        // Check if we have a complete header
        if bytes.contains(buf[:total], []u8{'\r','\n','\r','\n'}) do break
        if total >= len(buf) do break
    }
    if total == 0 do return

    req, ok := _parse_request(buf[:total])
    if !ok do return

    ctx.handler(req, ctx.sock)
}

http_server_run :: proc(port: int, handler: proc(req: HttpRequest, sock: net.TCP_Socket)) {
    ep := net.Endpoint{
        address = net.IP4_Address{0,0,0,0},
        port    = port,
    }
    sock, err := net.listen_tcp(ep)
    if err != nil {
        fmt.println("[api] Failed to bind port", port, ":", err)
        return
    }
    defer net.close(sock)
    fmt.println("[api] Listening on http://localhost:", port)

    for {
        client, _, aerr := net.accept_tcp(sock)
        if aerr != nil do break

        ctx := new(ConnCtx)
        ctx.sock    = client
        ctx.handler = handler
        t := thread.create_and_start_with_data(ctx, _conn_thread)
        thread.destroy(t)
    }
}

/*
 * headless.odin — Headless simulation loop + CLI/config parsing.
 *
 * Usage:
 *   dmls --headless
 *   dmls --headless --load save.dmls
 *   dmls --headless --seed 5961641267136C
 *   dmls --port 7772
 *
 * dmls.cfg (all optional):
 *   port     = 7771
 *   headless = false
 *   speed    = 1
 *   save     = autosave.dmls
 *   seed     = 0
 */

package dmls

import "core:fmt"
import "core:os"
import "core:strings"
import "core:strconv"
import "core:time"
import "core:sync"

// ---- Config ----------------------------------------------------------------

DMLSConfig :: struct {
    port     : int,
    headless : bool,
    speed    : int,    // 0/1/4/16
    save     : string,
    seed     : u64,
    load     : string,
}

default_config :: proc() -> DMLSConfig {
    return DMLSConfig{
        port     = 7771,
        headless = false,
        speed    = 1,
        save     = "dmls_save.bin",
        seed     = 0,
        load     = "",
    }
}

parse_config :: proc() -> DMLSConfig {
    cfg := default_config()
    _read_cfg_file(&cfg, "dmls.cfg")
    _apply_cli_flags(&cfg)
    return cfg
}

_read_cfg_file :: proc(cfg: ^DMLSConfig, path: string) {
    data, err := os.read_entire_file_from_path(path, context.temp_allocator)
    if err != nil do return
    defer free_all(context.temp_allocator)

    text := string(data)
    for line in strings.split_lines_iterator(&text) {
        line_t := strings.trim_space(line)
        if len(line_t) == 0 || line_t[0] == ';' || line_t[0] == '#' do continue
        ei := strings.index(line_t, "=")
        if ei < 0 do continue
        k := strings.trim_space(line_t[:ei])
        v := strings.trim_space(line_t[ei+1:])
        // Strip inline comment
        if ci := strings.index(v, ";"); ci >= 0 { v = strings.trim_space(v[:ci]) }

        switch k {
        case "port":
            if n, ok2 := strconv.parse_int(v); ok2 { cfg.port = n }
        case "headless":
            cfg.headless = v == "true" || v == "1"
        case "speed":
            if n, ok2 := strconv.parse_int(v); ok2 { cfg.speed = n }
        case "save":
            cfg.save = strings.clone(v, context.allocator)
        case "seed":
            if s, ok2 := _parse_seed(v); ok2 { cfg.seed = s }
        }
    }
}

_apply_cli_flags :: proc(cfg: ^DMLSConfig) {
    args := os.args
    i := 1
    for i < len(args) {
        arg := args[i]
        switch arg {
        case "--headless":
            cfg.headless = true
        case "--port":
            if i + 1 < len(args) {
                i += 1
                if n, ok := strconv.parse_int(args[i]); ok { cfg.port = n }
            }
        case "--speed":
            if i + 1 < len(args) {
                i += 1
                if n, ok := strconv.parse_int(args[i]); ok { cfg.speed = n }
            }
        case "--seed":
            if i + 1 < len(args) {
                i += 1
                if s, ok := _parse_seed(args[i]); ok { cfg.seed = s }
            }
        case "--load":
            if i + 1 < len(args) {
                i += 1
                cfg.load = args[i]
            }
        case "--save":
            if i + 1 < len(args) {
                i += 1
                cfg.save = args[i]
            }
        }
        i += 1
    }
}

// Speed value → index
_speed_val_to_idx :: proc(v: int) -> int {
    switch v {
    case 0:  return 0
    case 1:  return 1
    case 4:  return 2
    case 16: return 3
    }
    return 1
}

// ---- Headless tick loop ----------------------------------------------------

headless_run :: proc(cfg: ^DMLSConfig) {
    fmt.println("[dmls] Headless mode")

    engine := epilog_create()
    defer epilog_destroy(engine)

    world     := new(World)
    defer free(world)
    residents := Residents{}
    sim       := SimState{}
    island    := IslandName{}
    weather   := WeatherState{}
    decay     := FriendshipDecay{}

    residents_init(&residents)
    g_decay = &decay

    // Load rules
    starter_load_rules(engine)

    // Load save or generate world
    loaded := false
    if len(cfg.load) > 0 {
        ok := load_game(cfg.load, world, &residents, &sim, engine, &island)
        if ok {
            fmt.println("[dmls] Loaded:", cfg.load)
            loaded = true
        } else {
            fmt.println("[dmls] Failed to load:", cfg.load, "— generating fresh world")
        }
    }

    if !loaded {
        seed := cfg.seed
        if seed == 0 {
            // Use a quick entropy source
            t := u64(time.now()._nsec)
            t ~= t << 13; t ~= t >> 7; t ~= t << 17
            seed = t
        }
        world_init(world, seed)
        sim_init(&sim, seed)
        weather_init(&weather)
        starters_seed(&residents, world, engine)
        fmt.printf("[dmls] World seed: %016X\n", seed)
    }

    speed_idx := _speed_val_to_idx(cfg.speed)

    // Initialise shared snapshot
    {
        sp := new(SimSnapshot, context.temp_allocator)
        snapshot_fill(sp,world, &residents, &sim, &island, &weather, speed_idx, true, engine)
        shared_push_snapshot(sp)
        free_all(context.temp_allocator)
    }

    // Init shared control
    sync.lock(&g_shared.mu)
    g_shared.speed_req = -1
    sync.unlock(&g_shared.mu)

    fmt.println("[dmls] Running. Ctrl+C to quit.")

    for {
        // Poll control requests from API thread
        speed_req, quit, save := shared_poll_controls()
        if quit {
            fmt.println("[dmls] Quit requested")
            _save_headless(world, &residents, &sim, engine, &island, cfg.save)
            break
        }
        if save {
            _save_headless(world, &residents, &sim, engine, &island, cfg.save)
        }
        if speed_req >= 0 {
            speed_idx = speed_req
        }

        // Poll resident add/remove requests
        if req_kind, req_name, req_body, req_pending := shared_poll_res_req(); req_pending {
            if req_kind == 0 {
                _headless_add_resident(world, &residents, engine, req_name, req_body)
            } else {
                _headless_remove_resident(world, &residents, engine, req_name, &sim)
            }
        }

        // Tick if not paused
        _SPEED_HZ := [4]f32{0, 1.0, 4.0, 16.0}
        hz := _SPEED_HZ[speed_idx]
        if hz > 0 {
            interval := time.Duration(1e9 / f64(hz))
            world_tick_wander(world, &residents)
            sim_tick(&sim, &residents, engine, world.tick)
            weather_tick(&weather, &sim.rng)
            friendship_decay_tick(&decay, &residents, engine, &sim, world.tick)

            // Auto-save every 60 ticks
            if world.tick % 60 == 0 && world.tick > 0 {
                _save_headless(world, &residents, &sim, engine, &island, cfg.save)
            }

            // Push snapshot to API thread (heap-alloc to keep off stack)
            snap_ptr := new(SimSnapshot, context.temp_allocator)
            snapshot_fill(snap_ptr,world, &residents, &sim, &island, &weather, speed_idx, true, engine)
            shared_push_snapshot(snap_ptr)
            api_push_tick(snap_ptr^)
            free_all(context.temp_allocator)

            time.sleep(interval)
        } else {
            // Paused — keep snapshot fresh
            time.sleep(100 * time.Millisecond)
            sp := new(SimSnapshot, context.temp_allocator)
            snapshot_fill(sp,world, &residents, &sim, &island, &weather, speed_idx, true, engine)
            shared_push_snapshot(sp)
            free_all(context.temp_allocator)
        }
    }
}

_save_headless :: proc(world: ^World, res: ^Residents, sim: ^SimState,
                        engine: ^EpilogEngine, iname: ^IslandName, path: string) {
    ok := save_game(path, world, res, sim, engine, iname)
    if ok {
        fmt.println("[dmls] Saved to", path)
    } else {
        fmt.println("[dmls] Save failed:", path)
    }
}

_headless_add_resident :: proc(world: ^World, res: ^Residents,
                                engine: ^EpilogEngine, name, body: string) {
    if res.count >= MAX_RESIDENTS do return
    // Build a minimal character from the name; full field parsing deferred.
    c := Character{}
    n := min(len(name), MAX_NAME_LEN - 1)
    copy(c.name[:], name[:n])
    c.name[n] = 0
    c.sprite   = res.count % 8
    c.personality = .Ambitious_Achiever

    id := residents_add(res, c)
    epilog_assert_character(engine, residents_find(res, id))
    world_spawn_character(world, res, id)
    fmt.println("[dmls] Added resident:", name)
}

_headless_remove_resident :: proc(world: ^World, res: ^Residents,
                                   engine: ^EpilogEngine, name: string,
                                   sim: ^SimState) {
    if res.count <= 1 {
        fmt.println("[dmls] Cannot remove last resident")
        return
    }
    for i in 0..<res.count {
        c := &res.chars[i]
        if character_name(c) == name {
            // Clear from grid (remove by position)
            grid_remove_character(&world.grid, c.position[0], c.position[1])
            // Compact residents slice
            res.chars[i] = res.chars[res.count - 1]
            res.count -= 1
            fmt.println("[dmls] Removed resident:", name)
            return
        }
    }
    fmt.println("[dmls] Resident not found:", name)
}

/*
 * api_snapshot.odin — Shared simulation snapshot written by the sim thread,
 *                     read by the API thread under mutex.
 *
 * The snapshot is a plain Odin struct using only value types (fixed arrays,
 * integer counts) so it can be copied under the mutex without allocation.
 */

package dmls

import "core:sync"
import "core:fmt"
import "core:strings"
import "base:runtime"

// ---- Snapshot structs (value-type safe to copy) ----------------------------

MAX_SNAP_RESIDENTS :: MAX_RESIDENTS
MAX_SNAP_RELS      :: MAX_RESIDENTS * MAX_RESIDENTS
MAX_SNAP_EVENTS    :: 50
MAX_SNAP_NAME      :: 40

ResidentSnap :: struct {
    id               : u32,
    name             : [MAX_SNAP_NAME]u8,
    mood             : [12]u8,
    personality      : [32]u8,
    gender           : [12]u8,
    dating_pref      : [12]u8,
    position         : [2]i32,
    sprite           : u32,
    rel_count        : int,
    rels             : [MAX_RESIDENTS]RelSnap,
    interact_count   : u32,
}

RelSnap :: struct {
    from : [MAX_SNAP_NAME]u8,
    to   : [MAX_SNAP_NAME]u8,
    kind : [20]u8,
}

EventSnap :: struct {
    tick        : u64,
    description : [EVENT_MSG_LEN]u8,
    desc_len    : int,
    kind        : [24]u8,
}

SimSnapshot :: struct {
    tick          : u64,
    island_name   : [64]u8,
    seed          : u64,
    speed         : u8,          // 0=paused 1=1x 4=4x 16=16x
    weather       : [12]u8,
    time_of_day   : [10]u8,
    resident_count: int,
    residents     : [MAX_SNAP_RESIDENTS]ResidentSnap,
    crush_count   : int,
    rival_count   : int,
    event_count   : int,
    events        : [MAX_SNAP_EVENTS]EventSnap,
    is_headless   : bool,
}

// ---- Shared state ----------------------------------------------------------

SimShared :: struct {
    mu       : sync.Mutex,
    snap     : SimSnapshot,

    // Control channel: sim thread writes, API thread reads under mu
    speed_req   : int,   // -1 = no request, else new speed index
    quit_req    : bool,
    save_req    : bool,

    // Pending events that haven't been broadcast yet
    pending_events     : [MAX_SNAP_EVENTS]EventSnap,
    pending_event_count: int,

    // Active WebSocket prompts
    prompt_id      : [48]u8,
    prompt_kind    : [20]u8,   // "confession" or "confrontation"
    prompt_from    : [MAX_SNAP_NAME]u8,
    prompt_to      : [MAX_SNAP_NAME]u8,
    prompt_tick    : u64,
    prompt_active  : bool,
    prompt_choice  : int,     // 0=none, 1=accept, 2=reject
    prompt_resolved: bool,
}

g_shared : SimShared

// ---- Snapshot builder ------------------------------------------------------

_snap_str :: proc(dst: []u8, s: string) {
    n := min(len(s), len(dst) - 1)
    copy(dst, s[:n])
    dst[n] = 0
}

// snapshot_build fills a caller-provided struct to avoid a 425KB stack frame.
snapshot_fill :: proc(snap: ^SimSnapshot, world: ^World, res: ^Residents, sim: ^SimState,
                       iname: ^IslandName, weather: ^WeatherState,
                       speed_idx: int, is_headless: bool, engine: ^EpilogEngine) {
    snap.tick         = world.tick
    snap.seed         = world.seed
    snap.is_headless  = is_headless
    snap.crush_count  = sim.crush_count
    snap.rival_count  = sim.rival_count
    snap.resident_count = int(res.count)

    _speed_vals := [4]u8{0, 1, 4, 16}
    if speed_idx >= 0 && speed_idx < 4 {
        snap.speed = _speed_vals[speed_idx]
    }

    _snap_str(snap.island_name[:], island_name_str(iname))

    w_label := weather_label(weather.current)
    _snap_str(snap.weather[:], w_label)

    phase_str := ""
    switch day_phase_for_tick(world.tick) {
    case .Dawn:  phase_str = "dawn"
    case .Day:   phase_str = "day"
    case .Dusk:  phase_str = "dusk"
    case .Night: phase_str = "night"
    }
    _snap_str(snap.time_of_day[:], phase_str)

    // Residents
    for i in 0..<int(res.count) {
        c  := &res.chars[i]
        ia := int(c.id - 1)
        rs := &snap.residents[i]
        rs.id       = c.id
        rs.position = c.position
        rs.sprite   = c.sprite
        _snap_str(rs.name[:],        character_name(c))
        _snap_str(rs.personality[:], personality_label(c.personality))

        gender_s := ""
        switch c.gender {
        case .Male:      gender_s = "male"
        case .Female:    gender_s = "female"
        case .Nonbinary: gender_s = "nonbinary"
        }
        _snap_str(rs.gender[:], gender_s)
        _snap_str(rs.dating_pref[:], string(dating_pref_atom(c.dating_pref)))

        mood_s := "content"
        if ia >= 0 && ia < MAX_RESIDENTS {
            mood_s = mood_label(sim.social[ia].mood)
            rs.interact_count = sim.social[ia].interaction_count
        }
        _snap_str(rs.mood[:], mood_s)

        // Query relationships from Epilog
        rs.rel_count = _snap_query_rels(engine, c.id, res, rs.rels[:])
    }

    // Events (last MAX_SNAP_EVENTS from the log)
    n_events := min(sim.log.count, MAX_SNAP_EVENTS)
    snap.event_count = n_events
    for i in 0..<n_events {
        e := event_log_get(&sim.log, i)
        if e == nil do continue
        se := &snap.events[i]
        se.tick     = e.tick
        msg := event_entry_str(e)
        se.desc_len = min(len(msg), EVENT_MSG_LEN - 1)
        copy(se.description[:], msg[:se.desc_len])
        se.description[se.desc_len] = 0
        _snap_str(se.kind[:], _event_kind_from_msg(msg))
    }

}

_event_kind_from_msg :: proc(msg: string) -> string {
    if strings.contains(msg, "crush") || strings.contains(msg, "confesses") {
        return "crush_formed"
    }
    if strings.contains(msg, "rivals") || strings.contains(msg, "rival") {
        return "rival_detected"
    }
    if strings.contains(msg, "partner") {
        return "partner_formed"
    }
    if strings.contains(msg, "drifted") || strings.contains(msg, "stranger") {
        return "friendship_decayed"
    }
    if strings.contains(msg, "confrontation") || strings.contains(msg, "face each other") {
        return "rival_confrontation"
    }
    return "interaction"
}

// Per-resident relationship query for snapshot
_RelSnapAccum :: struct {
    out   : []RelSnap,
    count : int,
    res   : ^Residents,
    my_id : u32,
}

_rel_snap_cb :: proc "c" (soln: ^EpilogSolution, ud: rawptr) -> EpilogSignal {
    context = runtime.default_context()
    acc := cast(^_RelSnapAccum)ud
    if acc.count >= len(acc.out) do return .EPILOG_STOP

    other_atom: cstring
    tag_atom  : cstring

    for i in 0..<epilog_soln_var_count(soln) {
        vname := epilog_soln_var_name(soln, i)
        val   := epilog_soln_var_atom(soln, i)
        if vname == nil || val == nil do continue
        switch string(vname) {
        case "Other": other_atom = val
        case "Tag":   tag_atom   = val
        }
    }
    if other_atom == nil do return .EPILOG_NEXT

    other_id := _atom_to_id(string(other_atom))
    other    := residents_find(acc.res, other_id)
    if other == nil do return .EPILOG_NEXT

    rs := &acc.out[acc.count]

    my_c := residents_find(acc.res, acc.my_id)
    if my_c != nil { _snap_str(rs.from[:], character_name(my_c)) }
    _snap_str(rs.to[:], character_name(other))

    tag_s := "acquaintance"
    if tag_atom != nil { tag_s = string(tag_atom) }
    _snap_str(rs.kind[:], tag_s)

    acc.count += 1
    return .EPILOG_NEXT
}

_snap_query_rels :: proc(engine: ^EpilogEngine, id: u32, res: ^Residents, out: []RelSnap) -> int {
    buf_id, goal: [128]u8
    atom := character_atom(id, buf_id[:])
    gs := fmt.bprintf(goal[:], "relationship(%s, Other, Tag)", atom)
    goal[len(gs)] = 0

    acc := _RelSnapAccum{out = out, count = 0, res = res, my_id = id}
    epilog_query(engine, cstring(raw_data(goal[:])), _rel_snap_cb, &acc)
    return acc.count
}

_atom_to_id :: proc(s: string) -> u32 {
    if len(s) <= 5 || s[:5] != "char_" do return 0
    id := u32(0)
    for ch in s[5:] {
        if ch >= '0' && ch <= '9' { id = id*10 + u32(ch-'0') } else { break }
    }
    return id
}

// Push a snapshot update under the mutex
shared_push_snapshot :: proc(snap: ^SimSnapshot) {
    sync.lock(&g_shared.mu)
    g_shared.snap = snap^
    sync.unlock(&g_shared.mu)
}

// Returns a temp-allocator copy — freed automatically when temp_allocator is reset.
shared_read_snapshot :: proc() -> ^SimSnapshot {
    s := new(SimSnapshot, context.temp_allocator)
    sync.lock(&g_shared.mu)
    s^ = g_shared.snap
    sync.unlock(&g_shared.mu)
    return s
}

// Push a pending broadcast event
shared_push_event :: proc(e: EventSnap) {
    sync.lock(&g_shared.mu)
    if g_shared.pending_event_count < MAX_SNAP_EVENTS {
        g_shared.pending_events[g_shared.pending_event_count] = e
        g_shared.pending_event_count += 1
    }
    sync.unlock(&g_shared.mu)
}

shared_drain_events :: proc(out: []EventSnap) -> int {
    sync.lock(&g_shared.mu)
    n := g_shared.pending_event_count
    if n > len(out) { n = len(out) }
    copy(out, g_shared.pending_events[:n])
    g_shared.pending_event_count = 0
    sync.unlock(&g_shared.mu)
    return n
}

// Speed / quit / save control
shared_set_speed_req :: proc(idx: int) {
    sync.lock(&g_shared.mu)
    g_shared.speed_req = idx
    sync.unlock(&g_shared.mu)
}

shared_set_quit :: proc() {
    sync.lock(&g_shared.mu)
    g_shared.quit_req = true
    sync.unlock(&g_shared.mu)
}

shared_set_save :: proc() {
    sync.lock(&g_shared.mu)
    g_shared.save_req = true
    sync.unlock(&g_shared.mu)
}

shared_poll_controls :: proc() -> (speed_req: int, quit: bool, save: bool) {
    sync.lock(&g_shared.mu)
    speed_req = g_shared.speed_req
    quit      = g_shared.quit_req
    save      = g_shared.save_req
    g_shared.speed_req = -1
    g_shared.quit_req  = false
    g_shared.save_req  = false
    sync.unlock(&g_shared.mu)
    return
}

// Prompt state
shared_set_prompt :: proc(id, kind, from, to: string, tick: u64) {
    sync.lock(&g_shared.mu)
    _snap_str(g_shared.prompt_id[:],   id)
    _snap_str(g_shared.prompt_kind[:], kind)
    _snap_str(g_shared.prompt_from[:], from)
    _snap_str(g_shared.prompt_to[:],   to)
    g_shared.prompt_tick    = tick
    g_shared.prompt_active  = true
    g_shared.prompt_choice  = 0
    g_shared.prompt_resolved = false
    sync.unlock(&g_shared.mu)
}

shared_clear_prompt :: proc() {
    sync.lock(&g_shared.mu)
    g_shared.prompt_active   = false
    g_shared.prompt_resolved = false
    sync.unlock(&g_shared.mu)
}

shared_resolve_prompt :: proc(pid: string, choice: int) -> bool {
    sync.lock(&g_shared.mu)
    defer sync.unlock(&g_shared.mu)
    if !g_shared.prompt_active do return false
    cur_id := strings.truncate_to_byte(string(g_shared.prompt_id[:]), 0)
    if cur_id != pid do return false
    g_shared.prompt_choice   = choice
    g_shared.prompt_resolved = true
    return true
}

shared_poll_prompt_choice :: proc() -> (choice: int, resolved: bool) {
    sync.lock(&g_shared.mu)
    choice   = g_shared.prompt_choice
    resolved = g_shared.prompt_resolved
    if resolved {
        g_shared.prompt_resolved = false
        g_shared.prompt_active   = false
    }
    sync.unlock(&g_shared.mu)
    return
}

/*
 * api_server.odin — API thread lifecycle and broadcast loop.
 *
 * api_thread_start() spawns the HTTP listener and broadcast timer.
 * After each sim tick, sim code calls api_push_tick() which signals
 * the broadcast goroutine to emit WS "tick" and "position_update" messages.
 */

package dmls

import "core:thread"
import "core:sync"
import "core:fmt"
import "core:strings"
import "core:time"

// ---- Broadcast state -------------------------------------------------------

ApiServer :: struct {
    port      : int,
    running   : bool,
    tick_chan  : chan_bool,
}

// Minimal channel using an atomic flag
chan_bool :: struct {
    flag : bool,
    mu   : sync.Mutex,
}

chan_signal :: proc(c: ^chan_bool) {
    sync.lock(&c.mu)
    c.flag = true
    sync.unlock(&c.mu)
}

chan_drain :: proc(c: ^chan_bool) -> bool {
    sync.lock(&c.mu)
    v := c.flag
    c.flag = false
    sync.unlock(&c.mu)
    return v
}

g_api_server : ApiServer

// Called by the sim thread every tick to signal the broadcast loop.
api_push_tick :: proc(snap: SimSnapshot) {
    // snap unused — broadcast loop reads from g_shared directly
    chan_signal(&g_api_server.tick_chan)
}

// ---- Server thread ---------------------------------------------------------

_ApiThreadCtx :: struct {
    port: int,
}

_api_broadcast_loop :: proc(data: rawptr) {
    for {
        time.sleep(50 * time.Millisecond)  // 20 Hz broadcast rate

        // Emit tick message if signalled
        if chan_drain(&g_api_server.tick_chan) {
            snap := shared_read_snapshot()   // ^SimSnapshot, temp-allocated
            _ws_emit_tick(snap)
            _ws_emit_positions(snap)

            // Broadcast any pending events
            evts: [MAX_SNAP_EVENTS]EventSnap
            n := shared_drain_events(evts[:])
            for i in 0..<n {
                _ws_emit_event(&evts[i])
            }

            // Broadcast snapshot every 10 ticks
            if snap.tick % 10 == 0 {
                sj := _build_snapshot_json()
                ws_broadcast(sj)
            }

            // Prompt broadcast
            _ws_emit_prompt_if_active()

            free_all(context.temp_allocator)
        }
    }
}

_ws_emit_tick :: proc(snap: ^SimSnapshot) {
    b := strings.builder_make(context.temp_allocator)
    strings.write_string(&b, `{"type":"tick",`)
    _js_u64(&b, "tick", snap.tick); strings.write_string(&b, ",")
    _js_int(&b, "speed", int(snap.speed)); strings.write_string(&b, ",")
    _js_str(&b, "weather", _snap_cstr(snap.weather[:])); strings.write_string(&b, ",")
    _js_str(&b, "time_of_day", _snap_cstr(snap.time_of_day[:]))
    strings.write_string(&b, "}")
    ws_broadcast(strings.to_string(b))
}

_ws_emit_positions :: proc(snap: ^SimSnapshot) {
    b := strings.builder_make(context.temp_allocator)
    fmt.sbprintf(&b, `{"type":"position_update","tick":%d,"updates":[`, snap.tick)
    for i in 0..<snap.resident_count {
        if i > 0 { strings.write_string(&b, ",") }
        rs := &snap.residents[i]
        fmt.sbprintf(&b, `{"name":"%s","position":[%d,%d]}`,
            _snap_cstr(rs.name[:]), rs.position[0], rs.position[1])
    }
    strings.write_string(&b, "]}")
    ws_broadcast(strings.to_string(b))
}

_ws_emit_event :: proc(e: ^EventSnap) {
    b := strings.builder_make(context.temp_allocator)
    desc := _snap_cstr(e.description[:])
    kind := _snap_cstr(e.kind[:])
    fmt.sbprintf(&b, `{"type":"event","tick":%d,"kind":"%s","description":"%s","characters":[]}`,
        e.tick, kind, _json_escape(desc, context.temp_allocator))
    ws_broadcast(strings.to_string(b))
}

_ws_emit_prompt_if_active :: proc() {
    sync.lock(&g_shared.mu)
    active := g_shared.prompt_active
    pid    := strings.truncate_to_byte(string(g_shared.prompt_id[:]),   0)
    kind   := strings.truncate_to_byte(string(g_shared.prompt_kind[:]), 0)
    from   := strings.truncate_to_byte(string(g_shared.prompt_from[:]), 0)
    to     := strings.truncate_to_byte(string(g_shared.prompt_to[:]),   0)
    tick   := g_shared.prompt_tick
    sync.unlock(&g_shared.mu)

    if !active do return

    b := strings.builder_make(context.temp_allocator)
    fmt.sbprintf(&b,
        `{"type":"prompt","prompt_id":"%s","kind":"%s","from":"%s","to":"%s","tick":%d,"auto_resolve_in_ticks":10,"options":["accept","reject"]}`,
        pid, kind, from, to, tick)
    ws_broadcast(strings.to_string(b))
}

// ---- Start API (call once from main before the main loop) ------------------

api_thread_start :: proc(port: int) {
    g_api_server.port    = port
    g_api_server.running = true

    // HTTP listener thread
    http_t := thread.create_and_start_with_data(nil, proc(data: rawptr) {
        http_server_run(g_api_server.port, api_dispatch)
    })
    thread.destroy(http_t)

    // Broadcast loop thread
    bc_t := thread.create_and_start_with_data(nil, _api_broadcast_loop)
    thread.destroy(bc_t)

    fmt.println("[api] Dashboard: http://localhost:", port)
}

