/*
 * api_routes.odin — HTTP route handlers and WebSocket message processing.
 *
 * All handlers read from g_shared (snapshot) under mutex. They never touch
 * SimState, Residents, or the Epilog engine directly.
 */

package dmls

import "core:net"
import "core:fmt"
import "core:strings"
import "core:strconv"
import "core:sync"

// ---- JSON helpers ----------------------------------------------------------

_js_str :: proc(b: ^strings.Builder, key, val: string) {
    fmt.sbprintf(b, `"%s":"%s"`, key, val)
}

_js_int :: proc(b: ^strings.Builder, key: string, val: int) {
    fmt.sbprintf(b, `"%s":%d`, key, val)
}

_js_u64 :: proc(b: ^strings.Builder, key: string, val: u64) {
    fmt.sbprintf(b, `"%s":%d`, key, val)
}

_js_bool :: proc(b: ^strings.Builder, key: string, val: bool) {
    v := val ? "true" : "false"
    fmt.sbprintf(b, `"%s":%s`, key, v)
}

_snap_cstr :: proc(buf: []u8) -> string {
    return strings.truncate_to_byte(string(buf), 0)
}

// ---- /api/status -----------------------------------------------------------

route_status :: proc() -> string {
    snap := shared_read_snapshot()
    b    := strings.builder_make(context.temp_allocator)

    strings.write_string(&b, "{")
    _js_u64(&b, "tick", snap.tick); strings.write_string(&b, ",")
    _js_str(&b, "island_name", _snap_cstr(snap.island_name[:]) ); strings.write_string(&b, ",")
    fmt.sbprintf(&b, `"seed":"%016X"`, snap.seed); strings.write_string(&b, ",")
    _js_int(&b, "speed", int(snap.speed)); strings.write_string(&b, ",")
    _js_str(&b, "weather", _snap_cstr(snap.weather[:])); strings.write_string(&b, ",")
    _js_str(&b, "time_of_day", _snap_cstr(snap.time_of_day[:])); strings.write_string(&b, ",")
    _js_bool(&b, "is_headless", snap.is_headless); strings.write_string(&b, ",")
    _js_int(&b, "residents", snap.resident_count); strings.write_string(&b, ",")
    _js_int(&b, "crushes", snap.crush_count); strings.write_string(&b, ",")
    _js_int(&b, "rivals", snap.rival_count)
    strings.write_string(&b, "}")

    return strings.to_string(b)
}

// ---- /api/residents --------------------------------------------------------

_resident_json :: proc(rs: ^ResidentSnap, b: ^strings.Builder) {
    strings.write_string(b, "{")
    _js_int(b, "id", int(rs.id)); strings.write_string(b, ",")
    _js_str(b, "name", _snap_cstr(rs.name[:])); strings.write_string(b, ",")
    _js_str(b, "mood", _snap_cstr(rs.mood[:])); strings.write_string(b, ",")
    _js_str(b, "personality", _snap_cstr(rs.personality[:])); strings.write_string(b, ",")
    _js_str(b, "gender", _snap_cstr(rs.gender[:])); strings.write_string(b, ",")
    fmt.sbprintf(b, `"position":[%d,%d]`, rs.position[0], rs.position[1])
    strings.write_string(b, `,"relationships":[`)
    for ri in 0..<rs.rel_count {
        if ri > 0 { strings.write_string(b, ",") }
        r := &rs.rels[ri]
        fmt.sbprintf(b, `{"to":"%s","kind":"%s"}`,
            _snap_cstr(r.to[:]), _snap_cstr(r.kind[:]))
    }
    strings.write_string(b, `],"interaction_counts":{`)
    for ri in 0..<rs.rel_count {
        if ri > 0 { strings.write_string(b, ",") }
        r := &rs.rels[ri]
        fmt.sbprintf(b, `"%s":%d`, _snap_cstr(r.to[:]), rs.interact_count)
    }
    strings.write_string(b, "}}")
}

route_residents :: proc() -> string {
    snap := shared_read_snapshot()
    b    := strings.builder_make(context.temp_allocator)

    strings.write_string(&b, `{"residents":[`)
    for i in 0..<snap.resident_count {
        if i > 0 { strings.write_string(&b, ",") }
        _resident_json(&snap.residents[i], &b)
    }
    strings.write_string(&b, "]}")
    return strings.to_string(b)
}

route_resident_by_name :: proc(name: string) -> (string, int) {
    snap   := shared_read_snapshot()
    name_l := strings.to_lower(name, context.temp_allocator)

    for i in 0..<snap.resident_count {
        rs := &snap.residents[i]
        rn := strings.to_lower(_snap_cstr(rs.name[:]), context.temp_allocator)
        if rn == name_l {
            b := strings.builder_make(context.temp_allocator)
            _resident_json(rs, &b)
            return strings.to_string(b), 200
        }
    }
    b := strings.builder_make(context.temp_allocator)
    fmt.sbprintf(&b, `{"error":"resident not found","name":"%s"}`, name)
    return strings.to_string(b), 404
}

// ---- /api/relationships ----------------------------------------------------

route_relationships :: proc() -> string {
    snap := shared_read_snapshot()
    b    := strings.builder_make(context.temp_allocator)
    first := true

    strings.write_string(&b, `{"relationships":[`)
    for i in 0..<snap.resident_count {
        rs := &snap.residents[i]
        for ri in 0..<rs.rel_count {
            r := &rs.rels[ri]
            if !first { strings.write_string(&b, ",") }
            first = false
            fmt.sbprintf(&b, `{"from":"%s","to":"%s","kind":"%s"}`,
                _snap_cstr(rs.name[:]), _snap_cstr(r.to[:]), _snap_cstr(r.kind[:]))
        }
    }
    strings.write_string(&b, "]}")
    return strings.to_string(b)
}

// ---- /api/rivals -----------------------------------------------------------

route_rivals :: proc() -> string {
    snap := shared_read_snapshot()
    b    := strings.builder_make(context.temp_allocator)

    // Find rival pairs from relationship data
    strings.write_string(&b, `{"rivals":[`)
    first := true
    for i in 0..<snap.resident_count {
        rs := &snap.residents[i]
        for ri in 0..<rs.rel_count {
            r := &rs.rels[ri]
            if _snap_cstr(r.kind[:]) == "rivals" {
                if !first { strings.write_string(&b, ",") }
                first = false
                fmt.sbprintf(&b, `{"a":"%s","b":"%s","duration_ticks":0}`,
                    _snap_cstr(rs.name[:]), _snap_cstr(r.to[:]))
            }
        }
    }
    strings.write_string(&b, "]}")
    return strings.to_string(b)
}

// ---- /api/events -----------------------------------------------------------

route_events :: proc(query: string) -> string {
    snap  := shared_read_snapshot()
    b     := strings.builder_make(context.temp_allocator)
    limit := 20
    kind_filter := ""

    // Parse ?limit=N&kind=K
    for part in strings.split(query, "&", context.temp_allocator) {
        kv := strings.split(part, "=", context.temp_allocator)
        if len(kv) != 2 do continue
        switch kv[0] {
        case "limit":
            if n, ok := strconv.parse_int(kv[1]); ok { limit = n }
        case "kind":
            kind_filter = kv[1]
        }
    }

    strings.write_string(&b, `{"events":[`)
    count := 0
    first := true
    for i in 0..<snap.event_count {
        if count >= limit do break
        e := &snap.events[i]
        kind := _snap_cstr(e.kind[:])
        if kind_filter != "" && kind != kind_filter do continue
        desc := _snap_cstr(e.description[:])
        if !first { strings.write_string(&b, ",") }
        first = false
        fmt.sbprintf(&b, `{"tick":%d,"kind":"%s","description":"%s","characters":[]}`,
            e.tick, kind, _json_escape(desc, context.temp_allocator))
        count += 1
    }
    strings.write_string(&b, "]}")
    return strings.to_string(b)
}

_json_escape :: proc(s: string, alloc := context.allocator) -> string {
    b := strings.builder_make(alloc)
    for c in s {
        switch c {
        case '"':  strings.write_string(&b, `\"`)
        case '\\': strings.write_string(&b, `\\`)
        case '\n': strings.write_string(&b, `\n`)
        case '\r': strings.write_string(&b, `\r`)
        case:      strings.write_rune(&b, c)
        }
    }
    return strings.to_string(b)
}

// ---- /api/control/speed ---------------------------------------------------

_speed_index_from_val :: proc(v: int) -> (int, bool) {
    switch v {
    case 0:  return 0, true
    case 1:  return 1, true
    case 4:  return 2, true
    case 16: return 3, true
    }
    return 0, false
}

route_control_speed :: proc(body: string) -> (string, int) {
    // Parse {"speed": N}
    speed_val, ok := _json_get_int(body, "speed")
    if !ok {
        return `{"error":"missing speed field"}`, 400
    }

    prev_snap := shared_read_snapshot()
    prev := int(prev_snap.speed)

    idx, valid := _speed_index_from_val(speed_val)
    if !valid {
        b := strings.builder_make(context.temp_allocator)
        fmt.sbprintf(&b, `{"error":"invalid speed: %d"}`, speed_val)
        return strings.to_string(b), 400
    }

    shared_set_speed_req(idx)

    b := strings.builder_make(context.temp_allocator)
    fmt.sbprintf(&b, `{"speed":%d,"previous":%d}`, speed_val, prev)
    return strings.to_string(b), 200
}

route_control_pause :: proc() -> string {
    snap := shared_read_snapshot()
    paused := snap.speed == 0
    if paused {
        shared_set_speed_req(1)
    } else {
        shared_set_speed_req(0)
    }
    b := strings.builder_make(context.temp_allocator)
    fmt.sbprintf(&b, `{"paused":%s,"tick":%d}`, !paused ? "true" : "false", snap.tick)
    return strings.to_string(b)
}

route_control_save :: proc() -> string {
    snap := shared_read_snapshot()
    shared_set_save()
    iname := _snap_cstr(snap.island_name[:])
    path := "dmls_save.bin"
    if len(iname) > 0 {
        path_buf: [64]u8
        p := fmt.bprintf(path_buf[:], "%s.dmls", iname)
        path = strings.clone(string(path_buf[:len(p)]), context.temp_allocator)
    }
    b := strings.builder_make(context.temp_allocator)
    fmt.sbprintf(&b, `{"saved":true,"path":"%s","tick":%d}`, path, snap.tick)
    return strings.to_string(b)
}

route_control_quit :: proc() -> string {
    snap := shared_read_snapshot()
    shared_set_quit()
    b := strings.builder_make(context.temp_allocator)
    fmt.sbprintf(&b, `{"quitting":true,"final_tick":%d}`, snap.tick)
    return strings.to_string(b)
}

// ---- /api/query (Epilog read-only proxy) ----------------------------------
// The query must be forwarded to the sim thread, which owns the engine.
// We use a simple request/response slot in g_shared.

EpilogQueryReq :: struct {
    goal   : [256]u8,
    goal_len : int,
    pending  : bool,
    done     : bool,
    result   : [4096]u8,
    result_len : int,
}

// We expose a single-slot query channel; concurrent queries are serialised.
g_eq_mu  : ^_EqState
_EqState :: struct {
    mu      : _sync_mu,
    req     : EpilogQueryReq,
}

// minimal mutex alias to avoid import cycle
_sync_mu :: struct { _: [8]u8 } // placeholder — we reuse sync.Mutex via g_shared

// Because we can't block the API thread indefinitely, we use a polling approach:
// API thread writes goal into g_shared, sim thread picks it up each tick.

shared_eq_req   : EpilogQueryReq
shared_eq_mu    : _DummyMu  // we re-use the snapshot mutex

_DummyMu :: struct{}

// Actually we'll piggyback on the snapshot mutex for the query channel.

shared_set_query :: proc(goal: string) {
    sync.lock(&g_shared.mu)
    n := min(len(goal), 255)
    copy(shared_eq_req.goal[:], goal[:n])
    shared_eq_req.goal[n]  = 0
    shared_eq_req.goal_len = n
    shared_eq_req.pending  = true
    shared_eq_req.done     = false
    sync.unlock(&g_shared.mu)
}

shared_poll_query :: proc() -> (goal: string, pending: bool) {
    sync.lock(&g_shared.mu)
    defer sync.unlock(&g_shared.mu)
    if !shared_eq_req.pending do return "", false
    shared_eq_req.pending = false
    g := strings.truncate_to_byte(string(shared_eq_req.goal[:]), 0)
    return strings.clone(g, context.temp_allocator), true
}

shared_put_query_result :: proc(result: string) {
    sync.lock(&g_shared.mu)
    n := min(len(result), 4095)
    copy(shared_eq_req.result[:], result[:n])
    shared_eq_req.result[n]    = 0
    shared_eq_req.result_len   = n
    shared_eq_req.done         = true
    sync.unlock(&g_shared.mu)
}

shared_get_query_result :: proc() -> (result: string, done: bool) {
    sync.lock(&g_shared.mu)
    defer sync.unlock(&g_shared.mu)
    if !shared_eq_req.done do return "", false
    shared_eq_req.done = false
    r := strings.truncate_to_byte(string(shared_eq_req.result[:]), 0)
    return strings.clone(r, context.temp_allocator), true
}

// Forbidden patterns for read-only query gate
_query_forbidden :: proc(goal: string) -> bool {
    gl := strings.to_lower(goal, context.temp_allocator)
    return strings.contains(gl, "assert") || strings.contains(gl, "retract")
}

route_query :: proc(body: string) -> (string, int) {
    goal, ok := _json_get_str(body, "goal")
    if !ok {
        return `{"error":"missing goal field"}`, 400
    }
    if _query_forbidden(goal) {
        return `{"error":"assert and retract are not permitted via the query API"}`, 403
    }
    return fmt.tprintf(`{"goal":"%s","results":[],"count":0,"note":"query forwarding not yet wired in this build"}`,
        _json_escape(goal, context.temp_allocator)), 200
}

// ---- /api/residents POST (add) / DELETE ------------------------------------

route_add_resident_json :: proc(body: string) -> (string, int) {
    // Parse name — minimal JSON key extraction
    name, ok := _json_get_str(body, "name")
    if !ok || len(name) == 0 {
        return `{"error":"name required"}`, 400
    }
    // Signal sim thread to add a resident.  For now we write to a small shared
    // channel; the sim thread processes it next tick.
    shared_request_add_resident(name, body)
    return fmt.tprintf(`{"spawned":true,"name":"%s"}`, _json_escape(name, context.temp_allocator)), 202
}

route_remove_resident :: proc(name: string) -> (string, int) {
    if len(name) == 0 {
        return `{"error":"name required"}`, 400
    }
    shared_request_remove_resident(name)
    b := strings.builder_make(context.temp_allocator)
    snap := shared_read_snapshot()
    fmt.sbprintf(&b, `{"removed":"%s","at_tick":%d}`, name, snap.tick)
    return strings.to_string(b), 200
}

// Resident add/remove request channel
ResidentReq :: struct {
    kind : u8,    // 0=add 1=remove
    name : [MAX_SNAP_NAME]u8,
    body : [512]u8,
}

g_res_req : ResidentReq
g_res_req_pending : bool
g_res_req_mu      : bool  // spin via shared mu

shared_request_add_resident :: proc(name, body: string) {
    sync.lock(&g_shared.mu)
    g_res_req.kind = 0
    _snap_str(g_res_req.name[:], name)
    n := min(len(body), 511)
    copy(g_res_req.body[:], body[:n])
    g_res_req.body[n] = 0
    g_res_req_pending = true
    sync.unlock(&g_shared.mu)
}

shared_request_remove_resident :: proc(name: string) {
    sync.lock(&g_shared.mu)
    g_res_req.kind = 1
    _snap_str(g_res_req.name[:], name)
    g_res_req_pending = true
    sync.unlock(&g_shared.mu)
}

shared_poll_res_req :: proc() -> (kind: u8, name: string, body: string, pending: bool) {
    sync.lock(&g_shared.mu)
    defer sync.unlock(&g_shared.mu)
    if !g_res_req_pending do return 0, "", "", false
    g_res_req_pending = false
    name = strings.clone(strings.truncate_to_byte(string(g_res_req.name[:]), 0), context.temp_allocator)
    body = strings.clone(strings.truncate_to_byte(string(g_res_req.body[:]), 0), context.temp_allocator)
    return g_res_req.kind, name, body, true
}

// ---- WebSocket message handler (called per connected client frame) ----------

ws_handle_message :: proc(msg: string, sock: net.TCP_Socket) {
    // Expect JSON with "type" field
    typ, ok := _json_get_str(msg, "type")
    if !ok do return

    switch typ {
    case "set_speed":
        speed_val, sok := _json_get_int(msg, "speed")
        if !sok {
            ws_send_sock(sock, `{"type":"error","message":"missing speed"}`)
            return
        }
        idx, valid := _speed_index_from_val(speed_val)
        if !valid {
            b := strings.builder_make(context.temp_allocator)
            fmt.sbprintf(&b, `{"type":"error","message":"unknown speed value: %d","original_command":%s}`,
                speed_val, msg)
            ws_send_sock(sock, strings.to_string(b))
            return
        }
        shared_set_speed_req(idx)

    case "pause":
        shared_set_speed_req(0)

    case "unpause":
        shared_set_speed_req(1)

    case "resolve_prompt":
        pid, _ := _json_get_str(msg, "prompt_id")
        choice_str, _ := _json_get_str(msg, "choice")
        choice := 0
        if choice_str == "accept" { choice = 1 }
        else if choice_str == "reject" { choice = 2 }
        if !shared_resolve_prompt(pid, choice) {
            ws_send_sock(sock, `{"type":"error","message":"no matching prompt"}`)
        }

    case "query":
        goal, gok := _json_get_str(msg, "goal")
        if !gok {
            ws_send_sock(sock, `{"type":"error","message":"missing goal"}`)
            return
        }
        if _query_forbidden(goal) {
            ws_send_sock(sock, `{"type":"error","message":"assert/retract forbidden"}`)
            return
        }
        // Return empty result immediately (same limitation as REST /api/query)
        b := strings.builder_make(context.temp_allocator)
        fmt.sbprintf(&b, `{"type":"query_result","goal":"%s","results":[],"count":0}`,
            _json_escape(goal, context.temp_allocator))
        ws_send_sock(sock, strings.to_string(b))

    case "add_resident":
        name, _ := _json_get_str(msg, "name")
        if len(name) > 0 {
            shared_request_add_resident(name, msg)
        }
    }
}

// Send a text frame to a single WS connection
ws_send_sock :: proc(sock: net.TCP_Socket, msg: string) {
    frame := ws_make_frame(msg)
    defer delete(frame)
    net.send_tcp(sock, frame)
}

// ---- Minimal JSON value extractors -----------------------------------------

_json_get_str :: proc(json: string, key: string) -> (string, bool) {
    pat := strings.concatenate({`"`, key, `"`}, context.temp_allocator)
    i := strings.index(json, pat)
    if i < 0 do return "", false
    rest := json[i + len(pat):]
    ci := strings.index(rest, ":")
    if ci < 0 do return "", false
    rest = strings.trim_space(rest[ci+1:])
    if len(rest) == 0 || rest[0] != '"' do return "", false
    rest = rest[1:]
    end := strings.index(rest, `"`)
    if end < 0 do return "", false
    return rest[:end], true
}

_json_get_int :: proc(json: string, key: string) -> (int, bool) {
    pat := strings.concatenate({`"`, key, `"`}, context.temp_allocator)
    i := strings.index(json, pat)
    if i < 0 do return 0, false
    rest := json[i + len(pat):]
    ci := strings.index(rest, ":")
    if ci < 0 do return 0, false
    rest = strings.trim_space(rest[ci+1:])
    // Read digits
    end := 0
    for end < len(rest) && (rest[end] >= '0' && rest[end] <= '9') { end += 1 }
    if end == 0 do return 0, false
    v, ok := strconv.parse_int(rest[:end])
    return v, ok
}

// ---- Main HTTP dispatcher --------------------------------------------------

DASHBOARD_HTML :: #load("dashboard.html", string)

api_dispatch :: proc(req: HttpRequest, sock: net.TCP_Socket) {
    free_all(context.temp_allocator)
    defer free_all(context.temp_allocator)

    // WebSocket upgrade
    if req.is_ws_upgrade && req.path == "/ws" {
        if !ws_handshake(sock, req.ws_key) do return
        ws_hub_add(sock)

        // Send initial snapshot
        snap_json := _build_snapshot_json()
        ws_send_sock(sock, snap_json)

        // Read loop
        for {
            msg, closed := ws_read_frame(sock)
            if closed { break }
            if len(msg) > 0 {
                ws_handle_message(msg, sock)
            }
        }
        ws_hub_remove(sock)
        return
    }

    // REST routes
    resp := HttpResponse{}
    switch req.method {
    case .GET:
        switch {
        case req.path == "/":
            resp = http_ok(DASHBOARD_HTML, "text/html")

        case req.path == "/api/status":
            resp = http_ok(route_status())

        case req.path == "/api/residents":
            resp = http_ok(route_residents())

        case strings.has_prefix(req.path, "/api/residents/"):
            name := req.path[len("/api/residents/"):]
            body, code := route_resident_by_name(name)
            resp = HttpResponse{status = code, content = body, ctype = "application/json"}

        case req.path == "/api/relationships":
            resp = http_ok(route_relationships())

        case req.path == "/api/rivals":
            resp = http_ok(route_rivals())

        case req.path == "/api/events":
            resp = http_ok(route_events(req.query))

        case req.path == "/api/query":
            body, code := route_query(req.body)
            resp = HttpResponse{status = code, content = body, ctype = "application/json"}

        case:
            resp = http_err(404, `{"error":"not found"}`)
        }

    case .POST:
        switch req.path {
        case "/api/control/speed":
            body, code := route_control_speed(req.body)
            resp = HttpResponse{status = code, content = body, ctype = "application/json"}
        case "/api/control/pause":
            resp = http_ok(route_control_pause())
        case "/api/control/save":
            resp = http_ok(route_control_save())
        case "/api/control/quit":
            resp = http_ok(route_control_quit())
        case "/api/residents":
            body, code := route_add_resident_json(req.body)
            resp = HttpResponse{status = code, content = body, ctype = "application/json"}
        case "/api/query":
            body, code := route_query(req.body)
            resp = HttpResponse{status = code, content = body, ctype = "application/json"}
        case:
            resp = http_err(404, `{"error":"not found"}`)
        }

    case .DELETE:
        if strings.has_prefix(req.path, "/api/residents/") {
            name := req.path[len("/api/residents/"):]
            body, code := route_remove_resident(name)
            resp = HttpResponse{status = code, content = body, ctype = "application/json"}
        } else {
            resp = http_err(404, `{"error":"not found"}`)
        }

    case .UNKNOWN:
        resp = http_err(405, `{"error":"method not allowed"}`)
    }

    http_send(sock, resp)
}

// Build a WS "snapshot" message
_build_snapshot_json :: proc() -> string {
    snap := shared_read_snapshot()
    b    := strings.builder_make(context.temp_allocator)

    strings.write_string(&b, `{"type":"snapshot",`)
    _js_u64(&b, "tick", snap.tick); strings.write_string(&b, ",")
    _js_str(&b, "island_name", _snap_cstr(snap.island_name[:])); strings.write_string(&b, ",")
    fmt.sbprintf(&b, `"seed":"%016X"`, snap.seed); strings.write_string(&b, ",")
    _js_int(&b, "crushes", snap.crush_count); strings.write_string(&b, ",")
    _js_int(&b, "rivals", snap.rival_count); strings.write_string(&b, `,"residents":[`)
    for i in 0..<snap.resident_count {
        if i > 0 { strings.write_string(&b, ",") }
        _resident_json(&snap.residents[i], &b)
    }
    strings.write_string(&b, `],"events":[`)
    for i in 0..<min(snap.event_count, 20) {
        if i > 0 { strings.write_string(&b, ",") }
        e := &snap.events[i]
        fmt.sbprintf(&b, `{"tick":%d,"kind":"%s","description":"%s"}`,
            e.tick, _snap_cstr(e.kind[:]),
            _json_escape(_snap_cstr(e.description[:]), context.temp_allocator))
    }
    strings.write_string(&b, "]}")
    return strings.to_string(b)
}

