/*
 * api_server.odin — API thread lifecycle and broadcast loop.
 *
 * api_thread_start() spawns the HTTP listener and broadcast timer.
 * After each sim tick, sim code calls api_push_tick() which signals
 * the broadcast goroutine to emit WS "tick" and "position_update" messages.
 */

package dmls

import "core:thread"
import "core:sync"
import "core:fmt"
import "core:strings"
import "core:time"

// ---- Broadcast state -------------------------------------------------------

ApiServer :: struct {
    port      : int,
    running   : bool,
    tick_chan  : chan_bool,
}

// Minimal channel using an atomic flag
chan_bool :: struct {
    flag : bool,
    mu   : sync.Mutex,
}

chan_signal :: proc(c: ^chan_bool) {
    sync.lock(&c.mu)
    c.flag = true
    sync.unlock(&c.mu)
}

chan_drain :: proc(c: ^chan_bool) -> bool {
    sync.lock(&c.mu)
    v := c.flag
    c.flag = false
    sync.unlock(&c.mu)
    return v
}

g_api_server : ApiServer

// Called by the sim thread every tick to signal the broadcast loop.
api_push_tick :: proc(snap: SimSnapshot) {
    // snap unused — broadcast loop reads from g_shared directly
    chan_signal(&g_api_server.tick_chan)
}

// ---- Server thread ---------------------------------------------------------

_ApiThreadCtx :: struct {
    port: int,
}

_api_broadcast_loop :: proc(data: rawptr) {
    for {
        time.sleep(50 * time.Millisecond)  // 20 Hz broadcast rate

        // Emit tick message if signalled
        if chan_drain(&g_api_server.tick_chan) {
            snap := shared_read_snapshot()   // ^SimSnapshot, temp-allocated
            _ws_emit_tick(snap)
            _ws_emit_positions(snap)

            // Broadcast any pending events
            evts: [MAX_SNAP_EVENTS]EventSnap
            n := shared_drain_events(evts[:])
            for i in 0..<n {
                _ws_emit_event(&evts[i])
            }

            // Broadcast snapshot every 10 ticks
            if snap.tick % 10 == 0 {
                sj := _build_snapshot_json()
                ws_broadcast(sj)
            }

            // Prompt broadcast
            _ws_emit_prompt_if_active()

            free_all(context.temp_allocator)
        }
    }
}

_ws_emit_tick :: proc(snap: ^SimSnapshot) {
    b := strings.builder_make(context.temp_allocator)
    strings.write_string(&b, `{"type":"tick",`)
    _js_u64(&b, "tick", snap.tick); strings.write_string(&b, ",")
    _js_int(&b, "speed", int(snap.speed)); strings.write_string(&b, ",")
    _js_str(&b, "weather", _snap_cstr(snap.weather[:])); strings.write_string(&b, ",")
    _js_str(&b, "time_of_day", _snap_cstr(snap.time_of_day[:]))
    strings.write_string(&b, "}")
    ws_broadcast(strings.to_string(b))
}

_ws_emit_positions :: proc(snap: ^SimSnapshot) {
    b := strings.builder_make(context.temp_allocator)
    fmt.sbprintf(&b, `{"type":"position_update","tick":%d,"updates":[`, snap.tick)
    for i in 0..<snap.resident_count {
        if i > 0 { strings.write_string(&b, ",") }
        rs := &snap.residents[i]
        fmt.sbprintf(&b, `{"name":"%s","position":[%d,%d]}`,
            _snap_cstr(rs.name[:]), rs.position[0], rs.position[1])
    }
    strings.write_string(&b, "]}")
    ws_broadcast(strings.to_string(b))
}

_ws_emit_event :: proc(e: ^EventSnap) {
    b := strings.builder_make(context.temp_allocator)
    desc := _snap_cstr(e.description[:])
    kind := _snap_cstr(e.kind[:])
    fmt.sbprintf(&b, `{"type":"event","tick":%d,"kind":"%s","description":"%s","characters":[]}`,
        e.tick, kind, _json_escape(desc, context.temp_allocator))
    ws_broadcast(strings.to_string(b))
}

_ws_emit_prompt_if_active :: proc() {
    sync.lock(&g_shared.mu)
    active := g_shared.prompt_active
    pid    := strings.truncate_to_byte(string(g_shared.prompt_id[:]),   0)
    kind   := strings.truncate_to_byte(string(g_shared.prompt_kind[:]), 0)
    from   := strings.truncate_to_byte(string(g_shared.prompt_from[:]), 0)
    to     := strings.truncate_to_byte(string(g_shared.prompt_to[:]),   0)
    tick   := g_shared.prompt_tick
    sync.unlock(&g_shared.mu)

    if !active do return

    b := strings.builder_make(context.temp_allocator)
    fmt.sbprintf(&b,
        `{"type":"prompt","prompt_id":"%s","kind":"%s","from":"%s","to":"%s","tick":%d,"auto_resolve_in_ticks":10,"options":["accept","reject"]}`,
        pid, kind, from, to, tick)
    ws_broadcast(strings.to_string(b))
}

// ---- Start API (call once from main before the main loop) ------------------

api_thread_start :: proc(port: int) {
    g_api_server.port    = port
    g_api_server.running = true

    // HTTP listener thread (detached — runs for lifetime of process)
    http_t := thread.create_and_start_with_data(nil, proc(data: rawptr) {
        http_server_run(g_api_server.port, api_dispatch)
    })
    http_t.init_context = context
    thread.detach(http_t)

    // Broadcast loop thread (detached)
    bc_t := thread.create_and_start_with_data(nil, _api_broadcast_loop)
    bc_t.init_context = context
    thread.detach(bc_t)

    fmt.println("[api] Dashboard: http://localhost:", port)
}

